// ============================================
// @elitegrid/adapter-react — use-grid.ts
// Hooks that connect GridInstance to React
//
// useGrid()            — wires DOM to engine
// useViewportState()   — subscribe to visible rows
// useColumnsState()    — subscribe to column definitions
// usePaginationState() — subscribe to pagination
// ============================================

import {
  useEffect,
  useRef,
  useCallback,
  useState,
  useSyncExternalStore,
} from 'react'
import type {
  ViewportNamespace,
  ColumnsNamespace,
  PaginatedNamespace,
  FilteredNamespace,
  SortedNamespace,
  RawNamespace,
  SelectionNamespace,
  EditingNamespace,
  FocusNamespace,
} from '@elitegrid/core'
import { GridEvent } from '@elitegrid/core'
import type { GridInstance } from './create-grid'

// ─────────────────────────────────────────────
// SECTION 1 — useGrid
// ─────────────────────────────────────────────
// Wires the DOM container to the engine
// Handles three things:
//   1. ResizeObserver — reports container size to viewport plugin
//   2. Scroll handler — reports scroll position to viewport plugin
//   3. Cleanup        — destroys engine when component unmounts
//
// Returns containerRef — attach this to your scroll container div

export interface UseGridReturn {
  containerRef: React.RefObject<HTMLDivElement>
}

export function useGrid(grid: GridInstance): UseGridReturn {
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    const container = containerRef.current
    if (!container) return

    // ── Emit initial size synchronously ───────────────────────────────
    // clientWidth always excludes the scrollbar — this is correct whether
    // the scrollbar is overlay or classic. overflowY:scroll ensures the
    // scrollbar track is always present so clientWidth is stable.
    const CHECKBOX_WIDTH = 48
    const showCheckboxes =
      grid.options.selection?.mode !== 'none' &&
      (grid.options.selection?.showCheckboxes ?? true)

    const emitSize = () => {
      const width =
        container.clientWidth - (showCheckboxes ? CHECKBOX_WIDTH : 0)
      const height = container.clientHeight
      if (width > 0 && height > 0) {
        grid.kernel.eventBus.emit(GridEvent.CONTAINER_RESIZED, {
          width,
          height,
        })
      }
    }

    // ── Emit initial size ─────────────────────────────────────────────
    // Must defer to rAF — useEffect runs after paint but the scrollbar
    // from overflowY:scroll may not be laid out yet on first read.
    // rAF fires after the browser has completed layout and the scrollbar
    // track is present, so clientWidth correctly excludes it.
    const rafId = requestAnimationFrame(() => {
      emitSize()
    })

    // ── ResizeObserver — watches for subsequent size changes ──────────
    const observer = new ResizeObserver(emitSize)
    observer.observe(container)

    return () => {
      cancelAnimationFrame(rafId)
      observer.disconnect()
    }
  }, [grid])

  // ── Scroll handler (unchanged) ────────────────────────────────────
  const rafIdRef = useRef<number | null>(null)

  const handleScroll = useCallback(() => {
    if (rafIdRef.current !== null) return

    rafIdRef.current = requestAnimationFrame(() => {
      rafIdRef.current = null
      const container = containerRef.current
      if (!container) return
      grid.kernel.eventBus.emit(GridEvent.SCROLL_CHANGED, {
        scrollTop: container.scrollTop,
        scrollLeft: container.scrollLeft,
      })
    })
  }, [grid])

  useEffect(() => {
    const container = containerRef.current
    if (!container) return

    container.addEventListener('scroll', handleScroll, { passive: true })

    return () => {
      container.removeEventListener('scroll', handleScroll)
      if (rafIdRef.current !== null) {
        cancelAnimationFrame(rafIdRef.current)
      }
    }
  }, [handleScroll])

  return { containerRef }
}

// ─────────────────────────────────────────────
// SECTION 2 — useStoreNamespace (internal)
// ─────────────────────────────────────────────
// Generic hook — subscribes to any store namespace.
// Re-renders ONLY when that specific namespace changes.
// All specific hooks below use this as their base.
//
// Uses useSyncExternalStore (React 18) to eliminate concurrent-mode tearing.
//
// CRITICAL: getSnapshot must return a cached (stable) reference between
// store writes. The store's read() returns a new shallow-copy object on
// every call — if getSnapshot does the same, React sees a different
// reference every time it checks and enters an infinite loop.
//
// Solution: cache the last snapshot in a ref. The store subscriber
// increments a version counter on every write. getSnapshot compares
// the cached version to the current version — only re-reads from the
// store (and returns a new reference) when the version has advanced.

function useStoreNamespace<
  K extends
    | 'viewport'
    | 'columns'
    | 'paginated'
    | 'filtered'
    | 'sorted'
    | 'raw'
    | 'selection'
    | 'editing'
    | 'focus',
>(grid: GridInstance, namespace: K) {
  // Version counter — incremented by the subscriber on every store write.
  // Stored in a ref so it's shared between subscribe and getSnapshot
  // without causing re-renders on its own.
  const versionRef = useRef(0)
  const cachedRef = useRef(grid.kernel.store.read(namespace))

  // subscribe: called by useSyncExternalStore to wire the external store.
  // Must return an unsubscribe function. Stable across renders because
  // grid and namespace are both stable for a grid's lifetime.
  const subscribe = useCallback(
    (onStoreChange: () => void) => {
      return grid.kernel.store.subscribe(namespace, () => {
        // Bump version so getSnapshot knows it must re-read
        versionRef.current += 1
        onStoreChange()
      })
    },
    [grid, namespace]
  )

  // getSnapshot: called synchronously during render by useSyncExternalStore.
  // Must return the SAME reference if nothing has changed — React uses
  // Object.is for the bail-out comparison. Returning a new object every
  // call causes the "getSnapshot should be cached" infinite loop.
  const snapshotVersionRef = useRef(-1)
  const getSnapshot = useCallback(() => {
    if (snapshotVersionRef.current !== versionRef.current) {
      snapshotVersionRef.current = versionRef.current
      cachedRef.current = grid.kernel.store.read(namespace)
    }
    return cachedRef.current
  }, [grid, namespace])

  return useSyncExternalStore(subscribe, getSnapshot, getSnapshot)
}

// ─────────────────────────────────────────────
// SECTION 3 — Specific State Hooks
// ─────────────────────────────────────────────
// Each hook subscribes to exactly one namespace
// A scroll event only re-renders GridBody (viewport)
// A column resize only re-renders GridHeader (columns)
// They never cross-trigger each other

// Used by GridBody — re-renders when visible rows change
export function useViewportState(grid: GridInstance): ViewportNamespace {
  return useStoreNamespace(grid, 'viewport') as ViewportNamespace
}

// Used by GridHeader — re-renders when column definitions change
export function useColumnsState(grid: GridInstance): ColumnsNamespace {
  return useStoreNamespace(grid, 'columns') as ColumnsNamespace
}

// Used by pagination controls — re-renders when page changes
export function usePaginationState(grid: GridInstance): PaginatedNamespace {
  return useStoreNamespace(grid, 'paginated') as PaginatedNamespace
}

// Used by GridHeader — re-renders when sort model changes
export function useSortedState(grid: GridInstance): SortedNamespace {
  return useStoreNamespace(grid, 'sorted') as SortedNamespace
}

// Used by GridHeader — re-renders when filter model changes so filter
// icon color updates immediately when a filter is applied or cleared (§4.4)
export function useFilteredState(grid: GridInstance): FilteredNamespace {
  return useStoreNamespace(grid, 'filtered') as FilteredNamespace
}

// Used by GridOverlay — re-renders when loading/error/rows change
export function useRawState(grid: GridInstance): RawNamespace {
  return useStoreNamespace(grid, 'raw') as RawNamespace
}

// Used by GridRow and GridHeader — re-renders when selection changes
export function useSelectionState(grid: GridInstance): SelectionNamespace {
  return useStoreNamespace(grid, 'selection') as SelectionNamespace
}

// Used by GridCell — re-renders when edit state changes
export function useEditState(grid: GridInstance): EditingNamespace {
  return useStoreNamespace(grid, 'editing') as EditingNamespace
}

// ─────────────────────────────────────────────
// SECTION 4 — useFocusState
// ─────────────────────────────────────────────
// Subscribes to the focus namespace.
// Used by GridCell to apply tabIndex and by GridBody
// to move DOM focus when FOCUS_CHANGED fires.

export function useFocusState(grid: GridInstance): FocusNamespace {
  return useStoreNamespace(grid, 'focus') as FocusNamespace
}

// ─────────────────────────────────────────────
// SECTION 4a — useCellFocused
// ─────────────────────────────────────────────
// Derived selector — returns a boolean for THIS cell only.
// GridCell subscribes to this instead of the full focus namespace.
//
// Why this matters:
//   useStoreNamespace('focus') re-renders EVERY mounted cell when focus moves.
//   With 20 visible rows × 10 columns = 200 cells all re-rendering on every
//   arrow key. This hook compares the specific (rowId, columnId) pair and
//   returns a stable boolean — so only 2 cells re-render per focus change
//   (the cell that lost focus and the one that gained it).

export function useCellFocused(
  grid: GridInstance,
  rowId: string,
  columnId: string
): boolean {
  const [isFocused, setIsFocused] = useState(() => {
    const { focusedCell } = grid.kernel.store.read('focus')
    return focusedCell?.rowId === rowId && focusedCell?.columnId === columnId
  })

  useEffect(() => {
    setIsFocused(() => {
      const { focusedCell } = grid.kernel.store.read('focus')
      return focusedCell?.rowId === rowId && focusedCell?.columnId === columnId
    })

    const unsubscribe = grid.kernel.store.subscribe('focus', () => {
      const focused = grid.kernel.store.read('focus').focusedCell
      setIsFocused(focused?.rowId === rowId && focused?.columnId === columnId)
    })

    return unsubscribe
  }, [grid, rowId, columnId])

  return isFocused
}

// ─────────────────────────────────────────────
// SECTION 4b — useCellEditing
// ─────────────────────────────────────────────
// Derived selector — returns a boolean for THIS cell only.
// Same rationale as useCellFocused: only 1 cell re-renders when
// editing starts/stops instead of all 200.

export function useCellEditing(
  grid: GridInstance,
  rowId: string,
  columnId: string
): boolean {
  const [isEditing, setIsEditing] = useState(() => {
    const state = grid.kernel.store.read('editing')
    return (
      state.isEditing &&
      state.editingCell?.rowId === rowId &&
      state.editingCell?.columnId === columnId
    )
  })

  useEffect(() => {
    setIsEditing(() => {
      const state = grid.kernel.store.read('editing')
      return (
        state.isEditing &&
        state.editingCell?.rowId === rowId &&
        state.editingCell?.columnId === columnId
      )
    })

    const unsubscribe = grid.kernel.store.subscribe('editing', () => {
      const s = grid.kernel.store.read('editing')
      setIsEditing(
        s.isEditing &&
          s.editingCell?.rowId === rowId &&
          s.editingCell?.columnId === columnId
      )
    })

    return unsubscribe
  }, [grid, rowId, columnId])

  return isEditing
}

// ─────────────────────────────────────────────
// SECTION 4c — useCellSelected
// ─────────────────────────────────────────────
// Derived selector — returns a boolean for THIS row only.
// GridRow subscribes to this instead of the full selection namespace.
//
// Without this: clicking one row re-renders ALL mounted rows because
// every GridRow holds useSelectionState and gets the new selectedIds Set.
// With this: only the two rows that changed (deselected + selected) re-render.

export function useCellSelected(grid: GridInstance, rowId: string): boolean {
  const [isSelected, setIsSelected] = useState(() =>
    grid.kernel.store.read('selection').selectedIds.has(rowId)
  )

  useEffect(() => {
    setIsSelected(grid.kernel.store.read('selection').selectedIds.has(rowId))

    const unsubscribe = grid.kernel.store.subscribe('selection', () => {
      // Read directly from store — do not trust the newState argument.
      // If the engine mutates selectedIds in place rather than replacing
      // the namespace object, newState may be a stale reference. Direct
      // read always returns current state regardless of engine internals.
      const next = grid.kernel.store.read('selection').selectedIds.has(rowId)
      setIsSelected(next)
    })

    return unsubscribe
  }, [grid, rowId])

  return isSelected
}

// ─────────────────────────────────────────────
// SECTION 5 — useFocusManager
// ─────────────────────────────────────────────
// Moves real DOM focus when FocusPlugin changes the focused cell.
// Lives in GridBody — has access to the scroll container ref.
//
// Strategy:
//   - Listen to FOCUS_CHANGED on the event bus
//   - Find the DOM cell element by data-rowid + data-columnid attributes
//   - Call .focus() on it
//   - If the cell is outside the visible viewport, the browser will
//     scroll it into view automatically
//
// We use data attributes instead of React refs because cells are
// virtualised — only visible cells exist in the DOM at any time.

export function useFocusManager(
  grid: GridInstance,
  containerRef: React.RefObject<HTMLDivElement>
): void {
  useEffect(() => {
    const unsub = grid.kernel.eventBus.on(
      GridEvent.FOCUS_CHANGED,
      (payload: unknown) => {
        const { cell } = payload as {
          cell: { rowId: string; columnId: string } | null
        }

        if (!cell) return

        // Small rAF delay — virtualised rows may not be in the DOM yet
        // if the focused cell is outside the current scroll position.
        // The rAF gives React one paint cycle to render the new rows.
        requestAnimationFrame(() => {
          const container = containerRef.current
          if (!container) return

          // CSS.escape prevents crashes when rowId/columnId contains
          // quotes, brackets, or other special CSS selector characters (§1.4)
          const safeEscape = (s: string) =>
            typeof CSS !== 'undefined' && CSS.escape
              ? CSS.escape(s)
              : s.replace(/["\\[\]]/g, '\\$&')

          const el = container.querySelector<HTMLElement>(
            `[data-rowid="${safeEscape(cell.rowId)}"][data-columnid="${safeEscape(cell.columnId)}"]`
          )

          if (el) {
            el.focus({ preventScroll: false })
          }
        })
      }
    )

    return unsub
  }, [grid, containerRef])
}

// ─────────────────────────────────────────────
// SECTION 6 — useExport
// ─────────────────────────────────────────────
// Returns a triggerExport function the toolbar can call.
// Reads default scope and filename from grid.options.export.

export function useExport(grid: GridInstance) {
  const triggerExport = useCallback(
    (overrides?: {
      scope?: 'all' | 'filtered' | 'page' | 'selected'
      filename?: string
    }) => {
      const defaults = grid.options.export ?? {}
      grid.plugins.export.export({
        scope: overrides?.scope ?? defaults.scope ?? 'filtered',
        filename: overrides?.filename ?? defaults.filename ?? 'export',
      })
    },
    [grid]
  )

  return { triggerExport }
}
