// ============================================
// @elitegrid/core — Filter Plugin
// First step in the data pipeline
// Reads from 'raw' namespace
// Writes to 'filtered' namespace
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type {
  FilterModel,
  ColumnFilter,
  TextColumnFilter,
  NumberColumnFilter,
  DateColumnFilter,
  BooleanColumnFilter,
} from '../../types/index'

// ── Plugin ID ─────────────────────────────────

export const FILTER_PLUGIN_ID = 'filter'

// ── Config ────────────────────────────────────

export interface FilterConfig {
  caseSensitive?: boolean
  debounceMs?: number
}

// ── Compiled filter — built once when filterModel changes ──────────
// Holds a pre-built getter and pre-resolved filter values so the
// hot per-row loop does zero string allocations or object entry calls.

interface CompiledFilter {
  // O(1) field getter — path split is done once, not per row
  getter: (row: unknown) => unknown
  // The raw filter config — kept for type dispatch in matchesFilter
  filter: ColumnFilter
  // Pre-resolved filter values (avoids recomputing per row)
  // Text: lowercased filterValue (when case-insensitive)
  // Number: parsed numeric values
  // Date: numeric timestamps
  resolvedA: unknown
  resolvedB: unknown // 'between' second bound
}

// ── Implementation ─────────────────────────────

export class FilterPlugin implements Plugin {
  readonly id = FILTER_PLUGIN_ID

  private context!: PluginContext
  private config: FilterConfig = {}

  // Current active filter model
  private filterModel: FilterModel = { columns: {} }

  // Compiled filter array — rebuilt only when filterModel changes
  // Avoids Object.entries() + getter construction per row in the hot loop
  private compiledFilters: CompiledFilter[] = []

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: FilterConfig): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // When new data arrives — re-apply filters
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_SET, this.handleDataChanged)
    )

    // When data changes — re-apply filters
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_CHANGED, this.handleDataChanged)
    )

    // When filter is requested — recompile and apply new filter
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.FILTER_REQUESTED,
        this.handleFilterRequested
      )
    )

    // Run initial filter pass with empty model
    this.applyFilters()
  }

  // ── Event Handlers ─────────────────────────

  private handleDataChanged = (): void => {
    this.applyFilters()
  }

  private handleFilterRequested = (payload: {
    filterModel: FilterModel
  }): void => {
    this.filterModel = payload.filterModel
    // Recompile filters once here — not inside the per-row hot loop
    this.compiledFilters = this.compileFilters(this.filterModel)
    this.applyFilters()
  }

  // ── Compile Filters ────────────────────────
  // Runs once per filter model change.
  // Builds getter functions and resolves filter values so the hot
  // per-row loop is allocation-free.

  private compileFilters(model: FilterModel): CompiledFilter[] {
    const caseSensitive = this.config.caseSensitive ?? false
    const entries = Object.entries(model.columns)
    const compiled: CompiledFilter[] = []

    for (const [columnId, filter] of entries) {
      // Build getter once — hoists the field.includes('.') check out of the loop
      const getter = this.makeGetter(columnId)

      let resolvedA: unknown = undefined
      let resolvedB: unknown = undefined

      // Pre-resolve filter values by type so the per-row comparator
      // does no string → number / string → Date / toLowerCase work
      if (filter.type === 'text') {
        const f = filter as TextColumnFilter
        if (f.value !== undefined && f.value !== null) {
          const raw = String(f.value)
          resolvedA = caseSensitive || f.caseSensitive ? raw : raw.toLowerCase()
        }
      } else if (filter.type === 'number') {
        const f = filter as NumberColumnFilter
        resolvedA = f.value !== undefined ? Number(f.value) : undefined
        resolvedB = f.valueTo !== undefined ? Number(f.valueTo) : undefined
      } else if (filter.type === 'date') {
        const f = filter as DateColumnFilter
        // Store timestamps — comparing numbers is faster than Date objects
        resolvedA = f.value ? new Date(f.value).getTime() : undefined
        resolvedB = f.valueTo ? new Date(f.valueTo).getTime() : undefined
      }

      compiled.push({ getter, filter, resolvedA, resolvedB })
    }

    return compiled
  }

  // ── Apply Filters ──────────────────────────

  private applyFilters(): void {
    const { rows } = this.context.store.read('raw')

    // No filters active — pass all rows through unchanged
    const hasActiveFilters = this.compiledFilters.length > 0

    const t0 = Date.now()
    const filteredRows = hasActiveFilters
      ? rows.filter((row) => this.rowMatchesAllFilters(row))
      : rows
    const ms = Date.now() - t0

    // Write to filtered namespace
    this.context.store.write('filtered', {
      rows: filteredRows,
      matchCount: filteredRows.length,
      filterModel: this.filterModel,
    })

    // Notify pipeline
    this.context.eventBus.emit(GridEvent.FILTER_COMPLETED, {
      filterModel: this.filterModel,
      matchCount: filteredRows.length,
      _ms: ms,
    })
  }

  // ── Row Matching ───────────────────────────
  // Hot path — iterates compiledFilters (plain array) instead of
  // calling Object.entries() per row. Zero allocations per row.

  private rowMatchesAllFilters(row: unknown): boolean {
    // Every compiled filter must pass — AND logic
    for (const cf of this.compiledFilters) {
      const value = cf.getter(row)
      if (!this.matchesCompiledFilter(value, cf, row)) return false
    }
    return true
  }

  // ── Match Compiled Filter ──────────────────
  // Dispatches by filter type using pre-resolved values from CompileFilter

  private matchesCompiledFilter(
    value: unknown,
    cf: CompiledFilter,
    row: unknown
  ): boolean {
    switch (cf.filter.type) {
      case 'text':
        return this.matchesTextFilter(
          value,
          cf.filter as TextColumnFilter,
          cf.resolvedA,
          row
        )
      case 'number':
        return this.matchesNumberFilter(
          value,
          cf.filter as NumberColumnFilter,
          cf.resolvedA,
          cf.resolvedB,
          row
        )
      case 'date':
        return this.matchesDateFilter(
          value,
          cf.filter as DateColumnFilter,
          cf.resolvedA,
          cf.resolvedB,
          row
        )
      case 'boolean':
        return this.matchesBooleanFilter(
          value,
          cf.filter as BooleanColumnFilter,
          row
        )
      default:
        return true
    }
  }

  // ── Text Filter ────────────────────────────
  // resolvedFilterValue = pre-lowercased filter string (or original if case-sensitive)

  private matchesTextFilter(
    value: unknown,
    filter: TextColumnFilter,
    resolvedFilterValue: unknown,
    row: unknown
  ): boolean {
    // Custom filter function overrides built-in logic
    if (filter.customFilter) {
      return filter.customFilter(value, row)
    }

    if (filter.operator === 'isEmpty') {
      return (
        value === null || value === undefined || String(value).trim() === ''
      )
    }

    if (filter.operator === 'isNotEmpty') {
      return (
        value !== null && value !== undefined && String(value).trim() !== ''
      )
    }

    if (value === null || value === undefined) return false

    const caseSensitive =
      filter.caseSensitive ?? this.config.caseSensitive ?? false
    const strValue = String(value)
    // Only lowercase the row value — filter value was lowercased at compile time
    const a = caseSensitive ? strValue : strValue.toLowerCase()
    const b = resolvedFilterValue as string

    switch (filter.operator) {
      case 'contains':
        return a.includes(b)
      case 'notContains':
        return !a.includes(b)
      case 'equals':
        return a === b
      case 'notEquals':
        return a !== b
      case 'startsWith':
        return a.startsWith(b)
      case 'endsWith':
        return a.endsWith(b)
      default:
        return true
    }
  }

  // ── Number Filter ──────────────────────────
  // resolvedA/B = pre-parsed Number values from compile step

  private matchesNumberFilter(
    value: unknown,
    filter: NumberColumnFilter,
    resolvedA: unknown,
    resolvedB: unknown,
    row: unknown
  ): boolean {
    if (filter.customFilter) {
      return filter.customFilter(value, row)
    }

    if (filter.operator === 'isEmpty')
      return value === null || value === undefined
    if (filter.operator === 'isNotEmpty')
      return value !== null && value !== undefined
    if (value === null || value === undefined) return false

    const numValue = Number(value)
    if (isNaN(numValue)) return false
    const filterValue = resolvedA as number

    switch (filter.operator) {
      case 'equals':
        return numValue === filterValue
      case 'notEquals':
        return numValue !== filterValue
      case 'greaterThan':
        return numValue > filterValue
      case 'greaterThanOrEqual':
        return numValue >= filterValue
      case 'lessThan':
        return numValue < filterValue
      case 'lessThanOrEqual':
        return numValue <= filterValue
      case 'between':
        return numValue >= filterValue && numValue <= (resolvedB as number)
      default:
        return true
    }
  }

  // ── Date Filter ────────────────────────────
  // resolvedA/B = pre-computed timestamps (ms) from compile step
  // Row values are compared as timestamps — no new Date() per row

  private matchesDateFilter(
    value: unknown,
    filter: DateColumnFilter,
    resolvedA: unknown,
    resolvedB: unknown,
    row: unknown
  ): boolean {
    if (filter.customFilter) {
      return filter.customFilter(value, row)
    }

    if (filter.operator === 'isEmpty')
      return value === null || value === undefined
    if (filter.operator === 'isNotEmpty')
      return value !== null && value !== undefined
    if (value === null || value === undefined) return false

    // Get row value as timestamp — one allocation if value is a string,
    // zero if it's already a Date (getTime() is a number read)
    const rowTs =
      value instanceof Date
        ? value.getTime()
        : new Date(value as string).getTime()

    if (isNaN(rowTs)) return false

    const filterTs = resolvedA as number

    switch (filter.operator) {
      case 'equals': {
        // Day-level comparison — strip time component for both sides
        const rowDay = new Date(rowTs)
        rowDay.setHours(0, 0, 0, 0)
        const filterDay = new Date(filterTs)
        filterDay.setHours(0, 0, 0, 0)
        return rowDay.getTime() === filterDay.getTime()
      }
      case 'notEquals': {
        const rowDay = new Date(rowTs)
        rowDay.setHours(0, 0, 0, 0)
        const filterDay = new Date(filterTs)
        filterDay.setHours(0, 0, 0, 0)
        return rowDay.getTime() !== filterDay.getTime()
      }
      case 'before':
        return rowTs < filterTs
      case 'after':
        return rowTs > filterTs
      case 'between':
        return rowTs >= filterTs && rowTs <= (resolvedB as number)
      default:
        return true
    }
  }

  // ── Boolean Filter ─────────────────────────

  private matchesBooleanFilter(
    value: unknown,
    filter: BooleanColumnFilter,
    row: unknown
  ): boolean {
    if (filter.customFilter) {
      return filter.customFilter(value, row)
    }

    if (filter.operator === 'isEmpty')
      return value === null || value === undefined
    if (filter.operator === 'isNotEmpty')
      return value !== null && value !== undefined

    return Boolean(value) === filter.value
  }

  // ── Build value getter ─────────────────────
  // Hoists the dot-path check OUT of the per-row comparator.
  // Flat fields: single property read, zero allocation.
  // Nested paths (e.g. "user.address.city"): compiled key array traversal.

  private makeGetter(field: string): (row: unknown) => unknown {
    if (!field.includes('.')) {
      // Flat field — direct bracket access, no string work per row
      return (row: unknown) => (row as Record<string, unknown>)[field]
    }

    // Nested path — compile key array once
    const keys = field.split('.')
    return (row: unknown): unknown => {
      let cur: unknown = row
      for (const key of keys) {
        if (cur == null) return undefined
        cur = (cur as Record<string, unknown>)[key]
      }
      return cur
    }
  }

  // ── Public API ─────────────────────────────

  getFilterModel(): FilterModel {
    return { ...this.filterModel }
  }

  setFilterModel(model: FilterModel): void {
    this.context.eventBus.emit(GridEvent.FILTER_REQUESTED, {
      filterModel: model,
    })
  }

  setColumnFilter(columnId: string, filter: ColumnFilter): void {
    const newModel: FilterModel = {
      columns: {
        ...this.filterModel.columns,
        [columnId]: filter,
      },
    }
    this.setFilterModel(newModel)
  }

  clearColumnFilter(columnId: string): void {
    const { [columnId]: _, ...remaining } = this.filterModel.columns
    this.setFilterModel({ columns: remaining })
  }

  clearAll(): void {
    this.setFilterModel({ columns: {} })
  }

  getMatchCount(): number {
    return this.context.store.read('filtered').matchCount
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
    this.compiledFilters = []
  }
}
