// ============================================
// @elitegrid/core — Edit Plugin
// Manages the cell editing lifecycle
// Owns the 'editing' namespace in Data Store
// ============================================
//
// Trigger:  Double-click on an editable cell
// Commit:   Enter / Tab / click outside
// Cancel:   Escape
//
// Editor types (rendered by adapter):
//   'text'     — plain text input
//   'number'   — numeric input
//   'select'   — dropdown (options provided per column)
//   'date'     — date picker
//   'boolean'  — true false
//
// Validation:
//   - Per-column validator function
//   - Global fallback validator
//   - Commit is blocked if validation fails
//
// Events this plugin LISTENS to (from adapter):
//   EDIT_START_REQUESTED   — double-click on cell
//   EDIT_VALUE_CHANGED     — user typing
//   EDIT_COMMIT_REQUESTED  — Enter / Tab / blur
//   EDIT_CANCEL_REQUESTED  — Escape
//   DATA_SET               — bail out of edit on data reload
//   ROW_DELETED            — bail out if editing row is deleted
//
// Events this plugin EMITS:
//   EDIT_STARTED           — cell entered edit mode
//   EDIT_COMMITTED         — value saved
//   EDIT_CANCELLED         — edit discarded
//   EDIT_VALIDATION_FAILED — validation rejected value
//   ROW_UPDATED            — tell DataSource/adapter to persist new value

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { CellPosition, ValidationResult } from '../../types/index'
import { CELL_VALUE_PLUGIN_ID } from '../cell-value/index'
import type { CellValuePlugin } from '../cell-value/index'
import { ROW_MODEL_PLUGIN_ID } from '../row-model/index'
import type { RowModelPlugin } from '../row-model/index'

// ── Plugin ID ─────────────────────────────────

export const EDIT_PLUGIN_ID = 'edit'

// ── Editor Types ──────────────────────────────

export type EditorType = 'text' | 'number' | 'select' | 'date' | 'boolean'

// ── Select Option ─────────────────────────────

export interface SelectOption {
  label: string
  value: unknown
}

// ── Validator ─────────────────────────────────

export type CellValidator = (
  value: unknown,
  cell: CellPosition
) => ValidationResult | Promise<ValidationResult>

// ── Per-column editor config ───────────────────
// Registered by adapter when column has editable: true

export interface ColumnEditorConfig {
  type: EditorType
  // For 'select' editor
  options?: SelectOption[] | ((row: unknown) => SelectOption[])
  // Per-column validator — takes priority over global
  validator?: CellValidator
  // For 'number' editor
  min?: number
  max?: number
  step?: number
  // For 'date' editor
  minDate?: Date
  maxDate?: Date
}

// ── Config ────────────────────────────────────

export interface EditConfig {
  // Global validator — runs when no column-level validator is set
  validator?: CellValidator
}

// ── Adapter Payloads ──────────────────────────

export interface EditStartPayload {
  cell: CellPosition
}

export interface EditValuePayload {
  cell: CellPosition
  value: unknown
}

export interface EditCommitPayload {
  cell: CellPosition
}

export interface EditCancelPayload {
  cell: CellPosition
}

// ── Implementation ─────────────────────────────

export class EditPlugin implements Plugin {
  readonly id = EDIT_PLUGIN_ID

  private context!: PluginContext
  private config: EditConfig = {}

  // Per-column editor configs registered by adapter
  private columnEditors: Map<string, ColumnEditorConfig> = new Map()

  // Incrementing counter — each validation call gets a unique ID.
  // When the result arrives, if the ID no longer matches the current
  // counter the edit has moved on and the result is discarded.
  // This prevents a slow validator from a previous cell overwriting
  // the edit state of a new cell the user has already moved to.
  private validationGeneration: number = 0

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: EditConfig): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // Write initial idle state
    this.writeIdle()

    // Adapter: double-click on cell
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.EDIT_START_REQUESTED,
        this.handleStartRequested
      )
    )

    // Adapter: user typing in editor
    this.cleanups.push(
      context.eventBus.on(GridEvent.EDIT_VALUE_CHANGED, this.handleValueChanged)
    )

    // Adapter: Enter / Tab / blur
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.EDIT_COMMIT_REQUESTED,
        this.handleCommitRequested
      )
    )

    // Adapter: Escape
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.EDIT_CANCEL_REQUESTED,
        this.handleCancelRequested
      )
    )

    // Data replaced — bail out of any active edit
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_SET, this.handleDataSet)
    )

    // Row deleted — cancel if editing that row
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_DELETED, this.handleRowDeleted)
    )
  }

  // ── Event Handlers ─────────────────────────

  private handleStartRequested = (payload: EditStartPayload): void => {
    const { cell } = payload
    const current = this.context.store.read('editing')

    // Already editing this exact cell — no-op
    if (
      current.isEditing &&
      current.editingCell?.rowId === cell.rowId &&
      current.editingCell?.columnId === cell.columnId
    ) {
      return
    }

    // Editing a different cell — commit it first (auto-commit).
    // We capture the generation *after* incrementing for the new edit below,
    // so the auto-commit's result is accepted in the new edit's window.
    // The increment happens in the next block; record current value here
    // and pass it through so doCommit uses the right stamp.
    const autoCommitCell = current.editingCell
    const autoCommitValue = current.currentValue
    const isAutoCommit = current.isEditing && !!autoCommitCell

    // Invalidate any in-flight validation from the previous edit
    this.validationGeneration++

    if (isAutoCommit && autoCommitCell) {
      // Auto-commit uses the generation we just set — same window as the
      // new edit start, so it's never treated as stale by its own commit.
      this.doCommit(autoCommitCell, autoCommitValue, false)
    }

    // Check column is editable
    const { definitions } = this.context.store.read('columns')
    const col = definitions.find((d) => d.id === cell.columnId)
    if (!col?.editable) return

    // Read original value from row data
    const originalValue = this.readCellValue(cell)

    this.context.store.write('editing', {
      isEditing: true,
      editingCell: cell,
      originalValue,
      currentValue: originalValue,
      isValid: true,
      validationError: null,
    })

    this.context.eventBus.emit(GridEvent.EDIT_STARTED, {
      cell,
      originalValue,
      editorType: this.getEditorType(cell.columnId),
      editorConfig: this.columnEditors.get(cell.columnId) ?? null,
    })
  }

  private handleValueChanged = (payload: EditValuePayload): void => {
    const current = this.context.store.read('editing')
    if (!current.isEditing) return

    // Update current value immediately — UI stays responsive
    this.context.store.write('editing', {
      currentValue: payload.value,
    })

    // Stamp this validation call with the current generation.
    // If the user moves to a new cell before this resolves, generation
    // will have been incremented in handleStartRequested and the result
    // will be discarded rather than clobbering the new cell's state.
    const generation = this.validationGeneration
    this.runValidation(payload.value, payload.cell).then((result) => {
      if (this.validationGeneration !== generation) return // stale — discard

      this.context.store.write('editing', {
        isValid: result.valid,
        validationError: result.error ?? null,
      })

      if (!result.valid) {
        this.context.eventBus.emit(GridEvent.EDIT_VALIDATION_FAILED, {
          cell: payload.cell,
          value: payload.value,
          error: result.error ?? 'Invalid value',
        })
      }
    })
  }

  private handleCommitRequested = (payload: EditCommitPayload): void => {
    const current = this.context.store.read('editing')
    if (!current.isEditing || !current.editingCell) return

    this.doCommit(current.editingCell, current.currentValue)
  }

  private handleCancelRequested = (_payload: EditCancelPayload): void => {
    const current = this.context.store.read('editing')
    if (!current.isEditing || !current.editingCell) return

    const { editingCell, originalValue } = current

    // Invalidate any in-flight validation so it doesn't write back
    this.validationGeneration++

    this.writeIdle()

    this.context.eventBus.emit(GridEvent.EDIT_CANCELLED, {
      cell: editingCell,
      originalValue,
    })
  }

  private handleDataSet = (): void => {
    if (!this.context.store.read('editing').isEditing) return
    this.writeIdle()
  }

  private handleRowDeleted = (payload: { rowId: string }): void => {
    const current = this.context.store.read('editing')
    if (!current.isEditing || current.editingCell?.rowId !== payload.rowId)
      return
    this.writeIdle()
  }

  // ── Commit Logic ───────────────────────────

  private doCommit(
    cell: CellPosition,
    value: unknown,
    bumpGeneration = true
  ): void {
    const current = this.context.store.read('editing')

    // Stamp this commit's validation — if another edit starts before this
    // async validation resolves, the result is discarded rather than
    // clobbering the new cell's state.
    // When called as an auto-commit from handleStartRequested, bumpGeneration
    // is false because handleStartRequested already increments the counter.
    if (bumpGeneration) {
      this.validationGeneration++
    }
    const generation = this.validationGeneration

    // Run final validation before committing
    this.runValidation(value, cell).then((result) => {
      if (this.validationGeneration !== generation) return // stale — discard

      if (!result.valid) {
        // Block commit — keep editor open with error
        this.context.store.write('editing', {
          isValid: false,
          validationError: result.error ?? 'Invalid value',
        })

        this.context.eventBus.emit(GridEvent.EDIT_VALIDATION_FAILED, {
          cell,
          value,
          error: result.error ?? 'Invalid value',
        })
        return
      }

      const oldValue = current.originalValue

      this.writeIdle()

      // Tell adapter/datasource to persist the change
      this.context.eventBus.emit(GridEvent.ROW_UPDATED, {
        rowId: cell.rowId,
        columnId: cell.columnId,
        newValue: value,
        oldValue,
      })

      this.context.eventBus.emit(GridEvent.EDIT_COMMITTED, {
        cell,
        newValue: value,
        oldValue,
      })
    })
  }

  // ── Validation ─────────────────────────────

  private async runValidation(
    value: unknown,
    cell: CellPosition
  ): Promise<ValidationResult> {
    // Column-level validator takes priority
    const colEditor = this.columnEditors.get(cell.columnId)
    if (colEditor?.validator) {
      return colEditor.validator(value, cell)
    }

    // Built-in type validation
    const builtIn = this.runBuiltInValidation(value, cell)
    if (!builtIn.valid) return builtIn

    // Global validator fallback
    if (this.config.validator) {
      return this.config.validator(value, cell)
    }

    return { valid: true }
  }

  // ── Built-in Type Validation ───────────────

  private runBuiltInValidation(
    value: unknown,
    cell: CellPosition
  ): ValidationResult {
    const colEditor = this.columnEditors.get(cell.columnId)
    if (!colEditor) return { valid: true }

    // Empty value — always valid unless custom validator says otherwise
    if (value === null || value === undefined || value === '') {
      return { valid: true }
    }

    switch (colEditor.type) {
      case 'number': {
        const num = Number(value)
        if (isNaN(num)) {
          return { valid: false, error: 'Must be a valid number' }
        }
        if (colEditor.min !== undefined && num < colEditor.min) {
          return { valid: false, error: `Must be at least ${colEditor.min}` }
        }
        if (colEditor.max !== undefined && num > colEditor.max) {
          return { valid: false, error: `Must be at most ${colEditor.max}` }
        }
        return { valid: true }
      }

      case 'date': {
        const date = value instanceof Date ? value : new Date(value as string)
        if (isNaN(date.getTime())) {
          return { valid: false, error: 'Must be a valid date' }
        }
        if (colEditor.minDate && date < colEditor.minDate) {
          return {
            valid: false,
            error: `Date must be after ${colEditor.minDate.toLocaleDateString()}`,
          }
        }
        if (colEditor.maxDate && date > colEditor.maxDate) {
          return {
            valid: false,
            error: `Date must be before ${colEditor.maxDate.toLocaleDateString()}`,
          }
        }
        return { valid: true }
      }

      case 'select': {
        // Value must be one of the allowed options
        const options =
          typeof colEditor.options === 'function'
            ? [] // can't validate dynamic options without row context here
            : (colEditor.options ?? [])
        if (options.length > 0) {
          const valid = options.some((o) => o.value === value)
          if (!valid) {
            return { valid: false, error: 'Must be a valid option' }
          }
        }
        return { valid: true }
      }

      case 'text':
      default:
        return { valid: true }
    }
  }

  // ── Read Cell Value ────────────────────────
  // Delegates to CellValuePlugin when available.
  // Falls back to direct field lookup so EditPlugin
  // works in isolation (e.g. unit tests without
  // CellValuePlugin registered).

  private readCellValue(cell: CellPosition): unknown {
    // Use RowModelPlugin.getRow() to find the row by its engine ID.
    // This is correct regardless of what rowId field the developer configured —
    // the engine always stores rows keyed by their extracted _id.
    const rowModel = this.context.getPlugin<RowModelPlugin>(ROW_MODEL_PLUGIN_ID)
    const normalizedRow = rowModel?.getRow(cell.rowId)
    const row = normalizedRow?._data ?? null

    if (!row) return null

    // Prefer CellValuePlugin — supports nested paths and custom getters
    const cellValue =
      this.context.getPlugin<CellValuePlugin>(CELL_VALUE_PLUGIN_ID)
    if (cellValue) return cellValue.getRawValue(row, cell.columnId)

    // Fallback: direct field lookup for standalone use
    const { definitions } = this.context.store.read('columns')
    const col = definitions.find((d) => d.id === cell.columnId)
    if (!col) return null
    return (row as Record<string, unknown>)[col.field]
  }

  // ── Editor Type ────────────────────────────

  private getEditorType(columnId: string): EditorType {
    return this.columnEditors.get(columnId)?.type ?? 'text'
  }

  // ── Idle State ─────────────────────────────

  private writeIdle(): void {
    this.context.store.write('editing', {
      isEditing: false,
      editingCell: null,
      originalValue: null,
      currentValue: null,
      isValid: true,
      validationError: null,
    })
  }

  // ── Public API ─────────────────────────────

  // Called by adapter to register editor config per column
  registerColumnEditor(columnId: string, config: ColumnEditorConfig): void {
    this.columnEditors.set(columnId, config)
  }

  unregisterColumnEditor(columnId: string): void {
    this.columnEditors.delete(columnId)
  }

  getColumnEditor(columnId: string): ColumnEditorConfig | undefined {
    return this.columnEditors.get(columnId)
  }

  // Programmatic API
  startEdit(cell: CellPosition): void {
    this.context.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
  }

  commitEdit(): void {
    const current = this.context.store.read('editing')
    if (!current.isEditing || !current.editingCell) return
    this.context.eventBus.emit(GridEvent.EDIT_COMMIT_REQUESTED, {
      cell: current.editingCell,
    })
  }

  cancelEdit(): void {
    const current = this.context.store.read('editing')
    if (!current.isEditing || !current.editingCell) return
    this.context.eventBus.emit(GridEvent.EDIT_CANCEL_REQUESTED, {
      cell: current.editingCell,
    })
  }

  isEditing(): boolean {
    return this.context.store.read('editing').isEditing
  }

  getEditingCell(): CellPosition | null {
    return this.context.store.read('editing').editingCell
  }

  getEditState() {
    return this.context.store.read('editing')
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((fn) => fn())
    this.cleanups = []
    this.columnEditors.clear()
  }
}
