// ============================================
// @elitegrid/core — Export Plugin
// CSV export for all, filtered, selected, or current page rows
//
// Owns:
//   - EXPORT_REQUESTED listener → builds CSV → emits EXPORT_COMPLETED
//   - EXPORT_STARTED / EXPORT_COMPLETED events
//
// Does NOT:
//   - Touch the DOM (download is triggered by the adapter)
//   - Own a store namespace (export is a one-shot operation)
//   - Know about frameworks
//
// Scopes:
//   'all'      — every row in the raw dataset (unfiltered, unsorted)
//   'filtered' — rows after filter + sort (what the user sees)
//   'page'     — only the current page of filtered rows
//   'selected' — only the selected rows (in filtered+sorted order)
//
// CSV format:
//   - RFC 4180 compliant
//   - Header row uses column display headers
//   - Values from CellValuePlugin.getExportValue (respects exportFormatter)
//   - Values containing comma / quote / newline are quoted and escaped
//   - BOM prefix (\uFEFF) for correct Excel UTF-8 rendering
//
// The adapter listens to EXPORT_COMPLETED and triggers the download.
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import { CELL_VALUE_PLUGIN_ID } from '../cell-value/index'
import type { CellValuePlugin } from '../cell-value/index'
import type { ColumnId } from '../../types/index'
import { ROW_MODEL_PLUGIN_ID } from '../row-model/index'
import type { RowModelPlugin } from '../row-model/index'

// ── Plugin ID ─────────────────────────────────

export const EXPORT_PLUGIN_ID = 'export'

// ── Export scope ───────────────────────────────

export type ExportScope = 'all' | 'filtered' | 'page' | 'selected'

// ── Export config (per-call options) ──────────

export interface ExportOptions {
  // Which rows to include — default: 'filtered'
  scope?: ExportScope

  // Output filename without extension — default: 'export'
  filename?: string

  // Column ids to include — default: all visible columns in order
  columns?: ColumnId[]

  // Whether to include the header row — default: true
  includeHeader?: boolean

  // CSV delimiter — default: ','
  delimiter?: string
}

// ── Event payloads ─────────────────────────────

export interface ExportRequestedPayload {
  format: 'csv'
  scope?: ExportScope
  filename?: string
  columns?: ColumnId[]
  includeHeader?: boolean
  delimiter?: string
}

export interface ExportStartedPayload {
  format: 'csv'
  rowCount: number
}

export interface ExportCompletedPayload {
  format: 'csv'
  rowCount: number
  filename: string
  // The CSV string — adapter writes it to a Blob and triggers download
  content: string
}

// ── Implementation ─────────────────────────────

export class ExportPlugin implements Plugin {
  readonly id = EXPORT_PLUGIN_ID

  private context!: PluginContext

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    context.eventBus.on(GridEvent.EXPORT_REQUESTED, (payload: unknown) => {
      const req = payload as ExportRequestedPayload
      this.export({
        scope: req.scope,
        filename: req.filename,
        columns: req.columns,
        includeHeader: req.includeHeader,
        delimiter: req.delimiter,
      })
    })
  }

  // ── Public API ────────────────────────────
  // Callable directly by the adapter (e.g. from a toolbar button)
  // or via EXPORT_REQUESTED event.

  export(options: ExportOptions = {}): void {
    const scope = options.scope ?? 'filtered'
    const filename = options.filename ?? 'export'
    const delimiter = options.delimiter ?? ','
    const includeHeader = options.includeHeader ?? true

    // Resolve rows for the requested scope
    const rows = this.resolveRows(scope)

    // Resolve columns — visible columns in order, or caller-specified subset
    const columnIds = options.columns ?? this.resolveColumnIds()

    this.context.eventBus.emit(GridEvent.EXPORT_STARTED, {
      format: 'csv',
      rowCount: rows.length,
    } satisfies ExportStartedPayload)

    const content = this.buildCsv(rows, columnIds, delimiter, includeHeader)
    const outputFilename = `${filename}.csv`

    this.context.eventBus.emit(GridEvent.EXPORT_COMPLETED, {
      format: 'csv',
      rowCount: rows.length,
      filename: outputFilename,
      content,
    } satisfies ExportCompletedPayload)
  }

  // ── Row resolution ────────────────────────

  private resolveRows(scope: ExportScope): unknown[] {
    switch (scope) {
      case 'all':
        return this.context.store.read('raw').rows

      case 'filtered':
        return this.context.store.read('sorted').rows

      case 'page':
        return this.context.store.read('paginated').rows

      case 'selected': {
        const { selectedIds } = this.context.store.read('selection')
        const sorted = this.context.store.read('sorted').rows

        // Use RowModelPlugin to get correctly-extracted IDs for each row,
        // regardless of what rowId field the developer configured.
        // selectedIds is always keyed by the engine's extracted _id,
        // so we must match against the same source.
        const rowModel =
          this.context.getPlugin<RowModelPlugin>(ROW_MODEL_PLUGIN_ID)

        if (rowModel) {
          // RowModelPlugin rows are in the same order as sorted rows.
          // Zip by index to match each sorted row to its engine ID.
          const allIds = rowModel.getRowIds()
          return sorted.filter((_, index) =>
            selectedIds.has(allIds[index] ?? '')
          )
        }

        // Fallback: direct 'id' field (standalone use without RowModelPlugin)
        return sorted.filter((r) =>
          selectedIds.has(String((r as Record<string, unknown>)['id']))
        )
      }
    }
  }

  // ── Column resolution ─────────────────────

  private resolveColumnIds(): ColumnId[] {
    const { definitions, order } = this.context.store.read('columns')
    return order.filter((id) => {
      const col = definitions.find((d) => d.id === id)
      return col?.visible !== false
    })
  }

  // ── CSV builder ───────────────────────────

  private buildCsv(
    rows: unknown[],
    columnIds: ColumnId[],
    delimiter: string,
    includeHeader: boolean
  ): string {
    const { definitions } = this.context.store.read('columns')
    const cellValue =
      this.context.getPlugin<CellValuePlugin>(CELL_VALUE_PLUGIN_ID)

    const lines: string[] = []

    // ── Header row ────────────────────────
    if (includeHeader) {
      const headers = columnIds.map((id) => {
        const col = definitions.find((d) => d.id === id)
        return csvEscape(col?.header ?? id, delimiter)
      })
      lines.push(headers.join(delimiter))
    }

    // ── Data rows ─────────────────────────
    for (const row of rows) {
      const cells = columnIds.map((id) => {
        const value = cellValue
          ? cellValue.getExportValue(row, id)
          : rawFallback(row, id, definitions)
        return csvEscape(value, delimiter)
      })
      lines.push(cells.join(delimiter))
    }

    // BOM + CRLF line endings (RFC 4180 + Excel UTF-8 compatibility)
    return '\uFEFF' + lines.join('\r\n')
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    // Nothing plugin-specific to tear down
  }
}

// ── CSV utilities ──────────────────────────────
// Exported so adapter and tests can use them directly.

/**
 * RFC 4180 CSV cell escaping.
 * Wraps the value in double-quotes if it contains the delimiter,
 * a double-quote, or a newline. Escapes existing double-quotes by doubling.
 */
export function csvEscape(
  value: string | null | undefined,
  delimiter = ','
): string {
  // Null/undefined → empty cell, not the literal string "null" or "undefined"
  if (value === null || value === undefined) return ''
  const str = String(value)
  if (
    str.includes(delimiter) ||
    str.includes('"') ||
    str.includes('\n') ||
    str.includes('\r')
  ) {
    return `"${str.replace(/"/g, '""')}"`
  }
  return str
}

/**
 * Fallback value extractor when CellValuePlugin is not registered.
 * Used in unit tests and edge cases.
 */
function rawFallback(
  row: unknown,
  columnId: ColumnId,
  definitions: Array<{ id: ColumnId; field: string }>
): string {
  const col = definitions.find((d) => d.id === columnId)
  if (!col) return ''
  const value = (row as Record<string, unknown>)[col.field]
  if (value === null || value === undefined) return ''
  return String(value)
}
