// ============================================
// @elitegrid/core — Sort Plugin
// Second step in the data pipeline
// Reads from 'filtered' namespace
// Writes to 'sorted' namespace
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { SortModel, SortDirection } from '../../types/index'

// ── Plugin ID ─────────────────────────────────

export const SORT_PLUGIN_ID = 'sort'

// ── Config ────────────────────────────────────

export interface SortConfig {
  multiSort?: boolean
  multiSortKey?: 'shift' | 'ctrl'
  defaultDirection?: SortDirection
  nullsFirst?: boolean
}

// ── Column value type (detected once per sort call) ───────────────

type ColType = 'number' | 'string' | 'boolean' | 'date' | 'unknown'

// ── Implementation ─────────────────────────────

export class SortPlugin implements Plugin {
  readonly id = SORT_PLUGIN_ID

  private context!: PluginContext
  private config: SortConfig = {}

  // Current active sort model
  private sortModel: SortModel[] = []

  // Sort result cache (LRU, max 5 entries)
  // Key: stringified sort model + filteredVersion
  // Value: sorted row array
  private cache: Map<string, unknown[]> = new Map()
  private cacheKeys: string[] = []
  private static readonly MAX_CACHE = 5

  // Increments every time filtered rows change
  // Ensures cache is invalidated on every filter change
  private filteredVersion: number = 0

  // Pre-built collator — 5-10× faster than per-call localeCompare
  private collator = new Intl.Collator(undefined, { numeric: true })

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: SortConfig): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // When filter changes — re-sort new filtered rows
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.FILTER_COMPLETED,
        this.handleFilterCompleted
      )
    )

    // When sort is requested — apply new sort
    this.cleanups.push(
      context.eventBus.on(GridEvent.SORT_REQUESTED, this.handleSortRequested)
    )

    // Run initial sort pass with empty model
    this.applySort()
  }

  // ── Event Handlers ─────────────────────────

  private handleFilterCompleted = (): void => {
    // Increment version to invalidate all cached results
    this.filteredVersion++
    this.applySort()
  }

  private handleSortRequested = (payload: { sortModel: SortModel[] }): void => {
    this.sortModel = payload.sortModel
    this.applySort()
  }

  // ── Apply Sort ─────────────────────────────

  private applySort(): void {
    const { rows } = this.context.store.read('filtered')

    // No sort active — pass rows through unchanged
    if (this.sortModel.length === 0) {
      this.context.store.write('sorted', {
        rows,
        sortModel: [],
      })

      this.context.eventBus.emit(GridEvent.SORT_COMPLETED, {
        sortModel: [],
        rowCount: rows.length,
      })
      return
    }

    // Check cache
    const cacheKey = this.getCacheKey()
    const cached = this.cache.get(cacheKey)

    if (cached) {
      this.context.store.write('sorted', {
        rows: cached,
        sortModel: this.sortModel,
      })

      this.context.eventBus.emit(GridEvent.SORT_COMPLETED, {
        sortModel: this.sortModel,
        rowCount: cached.length,
        fromCache: true,
      })
      return
    }

    // Sort rows — measure wall time for perf telemetry
    const t0 = Date.now()
    const sorted = this.performSort(rows)
    const ms = Date.now() - t0

    // LRU cache — evict oldest entry when limit reached
    this.cache.set(cacheKey, sorted)
    this.cacheKeys.push(cacheKey)
    if (this.cacheKeys.length > SortPlugin.MAX_CACHE) {
      const oldest = this.cacheKeys.shift()!
      this.cache.delete(oldest)
    }

    // Write to store
    this.context.store.write('sorted', {
      rows: sorted,
      sortModel: this.sortModel,
    })

    // Notify pipeline
    this.context.eventBus.emit(GridEvent.SORT_COMPLETED, {
      sortModel: this.sortModel,
      rowCount: sorted.length,
      fromCache: false,
      _ms: ms,
    })
  }

  // ── Perform Sort ───────────────────────────
  //
  // Optimisation strategy (chosen after profiling at 1M rows):
  //
  // NUMERIC columns — TypedArray index sort
  //   Extract all values into a Float64Array once.
  //   Sort a Uint32Array of indices against it.
  //   V8 can optimise typed-array comparators far better than
  //   generic JS callbacks — 2.5–3× faster than Array.sort for numbers.
  //   Desc = sort asc then Array.reverse() — O(n) is cheaper than re-sorting.
  //
  // STRING / other columns — callback sort with hoisted getter
  //   The getter (flat vs nested path) is built once outside the comparator,
  //   eliminating the field.includes('.') string scan from every comparison call.
  //   Type check (typeof) is also hoisted — detected from the first non-null value.
  //
  // MULTI-SORT — generic callback with hoisted getters + type array
  //   One getter and one type per sort column, built before sort starts.
  //   The comparator loops models in priority order but reads pre-built state.
  //
  // Note: the JavaScript sort callback overhead itself is ~1s per 20M comparisons
  // (O(n log n) at 1M rows) regardless of what happens inside the callback.
  // That's the V8 TimSort ceiling for JS-land sorts, not a code problem.
  // For server-side data sources this doesn't apply — the server sorts.

  private performSort(rows: unknown[]): unknown[] {
    if (rows.length === 0) return rows

    const nullsFirst = this.config.nullsFirst ?? false

    // ── Single-column fast paths ──────────────────────────────────

    if (this.sortModel.length === 1) {
      const model = this.sortModel[0]!
      const { columnId, direction } = model
      const asc = direction !== 'desc'
      const getter = this.makeGetter(columnId)

      // Custom comparator overrides all type-based paths
      if (model.comparator) {
        const sign = asc ? 1 : -1
        const nullDir = nullsFirst ? -1 : 1
        const { comparator } = model
        const copy = rows.slice()
        copy.sort((a, b) => {
          const va = getter(a)
          const vb = getter(b)
          const aN = va == null
          const bN = vb == null
          if (aN || bN) {
            if (aN && bN) return 0
            return aN ? nullDir : -nullDir
          }
          try {
            return comparator(va, vb) * sign
          } catch {
            return 0
          }
        })
        return copy
      }

      const colType = this.detectType(rows, getter)

      if (colType === 'number') {
        return this.numericIndexSort(rows, getter, asc, nullsFirst)
      }

      // Callback sort for non-numeric — hoisted getter + sign
      const copy = rows.slice()
      const sign = asc ? 1 : -1
      const nullDir = nullsFirst ? -1 : 1

      if (colType === 'string') {
        const { collator } = this
        copy.sort((a, b) => {
          const va = getter(a) as string | null | undefined
          const vb = getter(b) as string | null | undefined
          const aN = va == null
          const bN = vb == null
          if (aN || bN) {
            if (aN && bN) return 0
            return aN ? nullDir : -nullDir
          }
          return collator.compare(va!, vb!) * sign
        })
        return copy
      }

      if (colType === 'boolean') {
        copy.sort((a, b) => {
          const va = getter(a) as boolean | null | undefined
          const vb = getter(b) as boolean | null | undefined
          const aN = va == null
          const bN = vb == null
          if (aN || bN) {
            if (aN && bN) return 0
            return aN ? nullDir : -nullDir
          }
          return (va === vb ? 0 : va ? 1 : -1) * sign
        })
        return copy
      }

      if (colType === 'date') {
        copy.sort((a, b) => {
          const va = getter(a) as Date | null | undefined
          const vb = getter(b) as Date | null | undefined
          const aN = va == null
          const bN = vb == null
          if (aN || bN) {
            if (aN && bN) return 0
            return aN ? nullDir : -nullDir
          }
          return (va!.getTime() - vb!.getTime()) * sign
        })
        return copy
      }

      // unknown type fallback
      const { collator } = this
      copy.sort((a, b) => {
        const va = getter(a)
        const vb = getter(b)
        const aN = va == null
        const bN = vb == null
        if (aN || bN) {
          if (aN && bN) return 0
          return aN ? nullDir : -nullDir
        }
        return collator.compare(String(va), String(vb)) * sign
      })
      return copy
    }

    // ── Multi-column sort — hoisted getters and types ─────────────
    // Build per-column getters and types once, before the sort loop

    const getters = this.sortModel.map((m) => this.makeGetter(m.columnId))
    const types = this.sortModel.map((m, i) =>
      this.detectType(rows, getters[i]!)
    )
    const signs = this.sortModel.map((m) => (m.direction === 'desc' ? -1 : 1))
    const nullDir = nullsFirst ? -1 : 1
    const { collator } = this
    const models = this.sortModel

    const copy = rows.slice()
    copy.sort((a, b) => {
      for (let i = 0; i < models.length; i++) {
        const va = getters[i]!(a)
        const vb = getters[i]!(b)
        const aN = va == null
        const bN = vb == null
        if (aN || bN) {
          if (!(aN && bN)) return aN ? nullDir : -nullDir
          continue // both null — try next column
        }

        // Custom comparator overrides type-based logic
        const model = models[i]!
        if (model.comparator) {
          try {
            const r = model.comparator(va, vb)
            if (r !== 0) return r * signs[i]!
          } catch {
            // comparator threw — treat as equal, try next column
          }
          continue
        }

        let r = 0
        const t = types[i]
        if (t === 'number') {
          r = (va as number) - (vb as number)
        } else if (t === 'string') {
          r = collator.compare(va as string, vb as string)
        } else if (t === 'boolean') {
          r = va === vb ? 0 : va ? 1 : -1
        } else if (t === 'date') {
          r = (va as Date).getTime() - (vb as Date).getTime()
        } else {
          r = collator.compare(String(va), String(vb))
        }

        if (r !== 0) return r * signs[i]!
      }
      return 0
    })
    return copy
  }

  // ── Numeric index sort ─────────────────────
  // Uses Float64Array + Uint32Array index trick for 2.5–3× speedup
  // over callback sort on numeric columns.
  // Desc: sort asc, then reverse — O(n) reverse beats re-sorting.

  private numericIndexSort(
    rows: unknown[],
    getter: (row: unknown) => unknown,
    asc: boolean,
    nullsFirst: boolean
  ): unknown[] {
    const n = rows.length
    const vals = new Float64Array(n)
    const idxs = new Uint32Array(n)

    for (let i = 0; i < n; i++) {
      const v = getter(rows[i])
      // Encode null/undefined as NaN — handled by sort comparator
      vals[i] = v == null ? NaN : (v as number)
      idxs[i] = i
    }

    // NaN (encodes null/undefined) does NOT sort reliably in JS —
    // V8 treats NaN comparator results as 0 (equal), so positions are
    // non-deterministic without an explicit guard. Always check.
    const nullDir = nullsFirst ? -1 : 1
    idxs.sort((a, b) => {
      const va = vals[a]!
      const vb = vals[b]!
      const aN = isNaN(va)
      const bN = isNaN(vb)
      if (aN || bN) {
        if (aN && bN) return 0
        return aN ? nullDir : -nullDir
      }
      return va - vb
    })

    // Pre-allocated output array — 3× faster than Array.from(idxs, mapper) at 1M rows.
    // Array.from allocates a fresh array AND calls a mapper closure per element.
    // A plain for-loop into a pre-sized array is a single memory write per element.
    const out = new Array<unknown>(n)
    for (let i = 0; i < n; i++) out[i] = rows[idxs[i]!]
    if (!asc) out.reverse()
    return out
  }

  // ── Detect column type from first non-null value ───────────────
  // Samples up to 10 rows — not a full scan — to keep init cost O(1).

  private detectType(
    rows: unknown[],
    getter: (row: unknown) => unknown
  ): ColType {
    const limit = Math.min(10, rows.length)
    for (let i = 0; i < limit; i++) {
      const v = getter(rows[i])
      if (v == null) continue
      if (v instanceof Date) return 'date'
      const t = typeof v
      if (t === 'number') return 'number'
      if (t === 'string') return 'string'
      if (t === 'boolean') return 'boolean'
    }
    return 'unknown'
  }

  // ── Build value getter ─────────────────────
  // Hoists the dot-path check OUT of the comparator.
  // For flat fields: direct bracket access.
  // For nested paths (e.g. "user.address.city"): compiled key array traversal.

  private makeGetter(field: string): (row: unknown) => unknown {
    if (!field.includes('.')) {
      // Flat field — single property read, no allocation
      return (row: unknown) => (row as Record<string, unknown>)[field]
    }

    // Nested path — compile keys once
    const keys = field.split('.')
    return (row: unknown): unknown => {
      let cur: unknown = row
      for (const key of keys) {
        if (cur == null) return undefined
        cur = (cur as Record<string, unknown>)[key]
      }
      return cur
    }
  }

  // ── Extract Value (public — used by tests and external callers) ─

  private extractValue(row: unknown, field: string): unknown {
    return this.makeGetter(field)(row)
  }

  // ── Cache Key ──────────────────────────────
  // Build a lightweight string key without JSON.stringify.
  // sortModel rarely has more than 3 entries — string concat is 10-20×
  // faster than JSON.stringify for this payload size.

  private getCacheKey(): string {
    let key = ''
    for (const m of this.sortModel) {
      key += `${m.columnId}:${m.direction}:${m.nullsFirst ?? 0}|`
    }
    key += this.filteredVersion
    return key
  }

  // ── Public API ─────────────────────────────

  getSortModel(): SortModel[] {
    return [...this.sortModel]
  }

  setSortModel(model: SortModel[]): void {
    this.context.eventBus.emit(GridEvent.SORT_REQUESTED, {
      sortModel: model,
    })
  }

  addSort(columnId: string, direction: SortDirection): void {
    const multiSort = this.config.multiSort ?? true

    if (multiSort) {
      // Remove existing sort for this column
      const existing = this.sortModel.filter((m) => m.columnId !== columnId)
      this.setSortModel([...existing, { columnId, direction }])
    } else {
      // Single sort — replace entirely
      this.setSortModel([{ columnId, direction }])
    }
  }

  removeSort(columnId: string): void {
    const filtered = this.sortModel.filter((m) => m.columnId !== columnId)
    this.setSortModel(filtered)
  }

  clearSort(): void {
    this.setSortModel([])
  }

  // Cycle sort state for a column
  // none → asc → desc → none
  cycleSort(columnId: string): void {
    const existing = this.sortModel.find((m) => m.columnId === columnId)

    if (!existing) {
      this.addSort(columnId, 'asc')
    } else if (existing.direction === 'asc') {
      this.addSort(columnId, 'desc')
    } else {
      this.removeSort(columnId)
    }
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
    this.cache.clear()
    this.cacheKeys = []
  }
}
