// ============================================
// @elitegrid/adapter-react — GridCell.tsx
// Renders a single cell value
//
// Responsibilities:
//   1. Call getCellValue() to get the value
//   2. Apply column formatter if defined
//   3. Apply cell class if defined
//   4. Correct ARIA attributes
//   5. Memoized — only re-renders when value changes
//
// V1 — getCellValue reads from row._data via props
// V2 — getCellValue will use store.subscribeToRow
//      internally — zero change to this component
// ============================================

import React, { memo } from 'react'
import { useGridContext } from '../context/GridContext'
import { useCellFocused, useCellEditing } from '../use-grid'
import { CellEditor } from './GridCellEditor'
import { GridEvent } from '@elitegrid/core'
import type { CellPosition, ColumnId, ColumnEditorConfig } from '@elitegrid/core'
import type { ColumnDef } from '../create-grid'

// ── Props ─────────────────────────────────────

interface GridCellProps {
  rowId: string
  columnId: ColumnId
  columnIndex: number
  rowIndex: number
  // V1 — reads from row._data
  // V2 — replaced with store subscription internally
  // This prop signature never changes
  getCellValue: () => unknown
  columnWidths: Map<string, number>
  // Lookup maps from GridBody — O(1) replacement for the previous
  // per-cell Array.find() calls.
  columnDefMap: Map<string, unknown>
  columnOptionsMap: Map<string, ColumnDef>
}

// ── GridCell ──────────────────────────────────
// Wrapped in memo with custom comparator
// Only re-renders when the actual cell value changes
// Not when sibling cells change

export const GridCell = memo(
  function GridCell({
    rowId,
    columnId,
    columnIndex,
    rowIndex,
    getCellValue,
    columnWidths,
    columnDefMap,
    columnOptionsMap,
  }: GridCellProps) {
    const grid = useGridContext()
    const { options } = grid

    // ── Edit / focus state — per-cell selectors ───────────────────
    // These hooks only re-render THIS cell when ITS focused/editing
    // status changes, not when any other cell changes.
    const isFocused = useCellFocused(grid, rowId, columnId)
    const isEditing = useCellEditing(grid, rowId, columnId)
    // editState is NOT subscribed here. CellEditor owns its own
    // subscription and only pays that cost when actually rendered.

    // ── Selection config (needed for cell click handler) ──
    const selectionMode = options.selection?.mode ?? 'none'
    const selectOnRowClick = options.selection?.selectOnRowClick ?? true
    const checkboxOnly = options.selection?.checkboxOnly ?? false

    // getCellValue() returns the full row object — needed for per-row editable
    // resolution and for CellValuePlugin formatting context.
    const rawRowObj = getCellValue() as Record<string, unknown> | null
    const value = rawRowObj?.[columnId]

    // ── Column editable flag ──────────────────
    // When edit.enabled is a function, resolve it per-row at render time (Â§2.7).
    // normalizeColumns marks function-enabled columns as editable:true at the
    // engine level so EDIT_START_REQUESTED is allowed through. The actual
    // per-row gate is here — if the function returns false for this row,
    // we prevent edit-start even though the engine would permit it.
    const colDef2 = columnDefMap.get(columnId) as
      | { editable?: boolean }
      | undefined
    // O(1) Map lookup — columnOptionsMap is built once in GridBody.
    // Previously this was options.columns.find() — O(n) per cell render.
    const colOptions = columnOptionsMap.get(columnId)
    const enabledConfig = colOptions?.edit?.enabled
    const isEditable =
      typeof enabledConfig === 'function'
        ? enabledConfig(rawRowObj as unknown) // per-row resolution
        : (colDef2?.editable ?? false)

    // ── Column definition (O(1) Map lookup) ────
    // Cell re-renders when value changes, not when column definitions
    // change — that's GridHeader's job.
    const colDef = columnDefMap.get(columnId) as
      | { id: string; width?: number }
      | undefined

    if (!colDef) return null

    const colWidth = columnWidths.get(columnId) ?? colDef.width ?? 150

    // ── Display value via CellValuePlugin ─────
    // CellValuePlugin owns all formatting logic:
    //   formatter â†’ rawToString fallback
    // rawRowObj is always a plain TData object — the pipeline never wraps
    // rows in NormalizedRow objects (RowModelPlugin keeps its own internal map
    // but never writes wrapped rows to the store). Checking ._data would break
    // any developer whose data genuinely has a field called '_data' (Â§7.4).
    const cellValuePlugin = grid.plugins.cellValue
    const rawRow = rawRowObj as Record<string, unknown>
    const displayValue = cellValuePlugin
      ? cellValuePlugin.getDisplayValue(rawRow, columnId)
      : value === null || value === undefined
        ? ''
        : String(value)

    // ── Cell class ────────────────────────
    const columnOptions = columnOptionsMap.get(columnId)
    const cellClassOption = columnOptions?.display?.cellClass
    const extraClass =
      typeof cellClassOption === 'function'
        ? cellClassOption(value, rawRow as Record<string, unknown>)
        : (cellClassOption ?? '')

    return (
      <div
        className={['yg-cell', extraClass].filter(Boolean).join(' ')}
        role="gridcell"
        // aria-colindex is 1-based per ARIA spec
        aria-colindex={columnIndex + 1}
        aria-readonly={!isEditable}
        // data attributes used by useFocusManager to find cell in DOM
        data-rowid={rowId}
        data-columnid={columnId}
        // tabIndex: focused cell is 0 (in tab order), others are -1
        tabIndex={isFocused ? 0 : -1}
        onFocus={() => {
          // Sync focus store when cell receives DOM focus (e.g. mouse click)
          if (!isFocused) {
            grid.kernel.eventBus.emit(GridEvent.FOCUS_SET_REQUESTED, {
              cell: { rowId, columnId, rowIndex, columnIndex },
            })
          }
        }}
        onDoubleClick={(e) => {
          e.stopPropagation()
          if (!isEditable) return
          // Only handle double-click if trigger is 'doubleClick' (default)
          const trigger = options.editing?.trigger ?? 'doubleClick'
          if (trigger !== 'doubleClick') return
          const cell: CellPosition = { rowId, columnId, rowIndex, columnIndex }
          grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
        }}
        onClick={(e) => {
          // Always stop propagation — cell owns its own clicks
          e.stopPropagation()

          if (e.detail > 1) return // second click of double-click — skip
          if (isEditing) return // editor is open — don't change selection

          // click-to-edit: if trigger is 'click' and cell is editable, open editor
          const trigger = options.editing?.trigger ?? 'doubleClick'
          if (
            trigger === 'click' &&
            isEditable &&
            !e.shiftKey &&
            !e.ctrlKey &&
            !e.metaKey
          ) {
            const cell: CellPosition = {
              rowId,
              columnId,
              rowIndex,
              columnIndex,
            }
            grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
            return
          }

          if (selectionMode === 'none' || !selectOnRowClick || checkboxOnly)
            return

          const editingEnabled = options.editing?.enabled ?? false
          const hasModifier = e.shiftKey || e.ctrlKey || e.metaKey

          // If editing is enabled and this is a plain click (no modifier),
          // check if the row is already selected — if so, don't clear selection.
          // User may be about to double-click to edit. Modifier clicks always work.
          if (editingEnabled && !hasModifier) {
            const { selectedIds } = grid.kernel.store.read('selection')
            const alreadySelected = selectedIds.has(rowId)
            if (alreadySelected) return // preserve selection — let dblclick handle edit
          }

          grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
            rowId,
            shiftKey: e.shiftKey,
            ctrlKey: e.ctrlKey,
            metaKey: e.metaKey,
          })
        }}
        style={{
          // ── Layout — must be inline: CSS may not load in all environments ──
          display: 'flex',
          alignItems: 'center',
          overflow: 'hidden',
          whiteSpace: 'nowrap',
          textOverflow: 'ellipsis',
          flexShrink: 0,
          boxSizing: 'border-box',
          position: 'relative',
          fontSize: 'var(--eg-cell-font-size, 0.875rem)',
          color: 'var(--eg-cell-text)',
          padding: 'var(--eg-cell-padding, 0 12px)',
          // ── Sizing — dynamic per column ───────────────────────────────────
          width: colWidth,
          minWidth: colWidth,
          maxWidth: colWidth,
          height: '100%',
          // ── Dynamic appearance ────────────────────────────────────────────
          borderRight: options.appearance?.showColumnBorders
            ? 'var(--eg-cell-border)'
            : undefined,
          // Focus ring — inset outline so it never gets clipped by overflow:hidden
          outline:
            isFocused && !isEditing
              ? '2px solid var(--eg-primary)'
              : 'none',
          outlineOffset: -2,
        }}
      >
        {isEditing ? (
          // ── Editor ────────────────────────────
          // CellEditor owns its own editState subscription internally.
          // Only this one component re-renders on every keystroke.
          <CellEditor
            cell={{ rowId, columnId, rowIndex, columnIndex }}
            editorConfig={
              (grid.plugins.edit as unknown as { getColumnEditor: (id: string) => ColumnEditorConfig | undefined })?.getColumnEditor(columnId) ?? null
            }
            colWidth={colWidth}
            rowHeight={40}
          />
        ) : (
          // ── Display value ──────────────────────
          <span
            style={{
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap',
              width: '100%',
            }}
            title={displayValue}
          >
            {displayValue}
          </span>
        )}
      </div>
    )
  },

  // ── Custom memo comparator ────────────────
  // React.memo by default does shallow comparison of all props
  // getCellValue is a new function reference on every GridRow render
  // Without this comparator — memo never works because
  // getCellValue always looks different
  //
  // We compare the actual VALUE instead of the function reference
  // Cell only re-renders when the value itself changes
  (prevProps, nextProps) => {
    // If these structural props change — re-render
    if (prevProps.rowId !== nextProps.rowId) return false
    if (prevProps.columnId !== nextProps.columnId) return false
    if (prevProps.columnIndex !== nextProps.columnIndex) return false
    if (prevProps.rowIndex !== nextProps.rowIndex) return false

    // Compare the specific cell's field value — not the full row reference.
    // getCellValue() now returns the full row object (for CellValuePlugin context),
    // so we extract the field value here for comparison.
    const prevRow = prevProps.getCellValue() as Record<string, unknown> | null
    const nextRow = nextProps.getCellValue() as Record<string, unknown> | null
    const prevValue = prevRow?.[prevProps.columnId]
    const nextValue = nextRow?.[nextProps.columnId]

    // Width change — re-render
    // (columnWidths is now a stable Map ref thanks to GridBody's useMemo,
    //  so this only fires when widths actually change)
    const prevWidth = prevProps.columnWidths.get(prevProps.columnId)
    const nextWidth = nextProps.columnWidths.get(nextProps.columnId)
    if (prevWidth !== nextWidth) return false

    // Lookup map identity — if maps were rebuilt (definitions changed),
    // re-render so we pick up new colDef / formatter / cellClass.
    if (prevProps.columnDefMap !== nextProps.columnDefMap) return false
    if (prevProps.columnOptionsMap !== nextProps.columnOptionsMap) return false

    return prevValue === nextValue
    // Note: isFocused and isEditing come from useCellFocused / useCellEditing
    // hooks inside the component. Hooks always run regardless of memo — the
    // comparator controls whether the function body re-runs for prop changes,
    // but internal useState updates always trigger a re-render of their
    // specific component. So focus and edit state are handled correctly
    // without needing to appear in the comparator.
  }
)
