// ============================================
// @elitegrid/adapter-react — GridOverlay.tsx
// Error and empty state overlays
//
// NOTE: Loading state is handled by the shimmer in GridBody.tsx.
// If appearance.loadingComponent is provided, it renders here instead.
//
// Priority order:
// 1. Custom component (full control)
// 2. Simple props (title, description, icon)
// 3. Default built-in UI
// ============================================

import React from 'react'
import { useGridContext } from '../context/GridContext'
import { useRawState } from '../use-grid'

export function GridOverlay() {
  const grid = useGridContext()
  const { loading, error, rows } = useRawState(grid)
  const { options } = grid
  const appearance = options.appearance

  const { rows: paginatedRows } = grid.kernel.store.read('paginated')

  const overlayStyle: React.CSSProperties = {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: 'var(--eg-overlay-bg, rgba(255,255,255,0.9))',
    zIndex: 5,
    gap: 12,
  }

  // ── Custom loading component ───────────────
  // Only handle loading here if the developer provided a custom component.
  // Default loading state is handled by the shimmer skeleton in GridBody.
  if (loading && appearance?.loadingComponent) {
    const LoadingComponent = appearance.loadingComponent
    return (
      <div style={overlayStyle} className="yg-overlay yg-overlay--loading">
        <LoadingComponent />
      </div>
    )
  }

  // ── Error state ───────────────────────────
  if (error) {
    if (appearance?.errorComponent) {
      const ErrorComponent = appearance.errorComponent
      return (
        <div style={overlayStyle} className="yg-overlay yg-overlay--error">
          <ErrorComponent error={error} />
        </div>
      )
    }

    return (
      <div
        className="yg-overlay yg-overlay--error"
        style={overlayStyle}
        role="alert"
        aria-live="assertive"
      >
        <div
          style={{
            width: 40,
            height: 40,
            borderRadius: '50%',
            backgroundColor: 'var(--eg-error-bg)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '1.25rem',
          }}
        >
          ⚠️
        </div>
        <div style={{ textAlign: 'center' }}>
          <p
            style={{
              margin: 0,
              fontSize: '0.875rem',
              fontWeight: 600,
              color: 'var(--eg-error)',
            }}
          >
            Failed to load data
          </p>
          <p
            style={{
              margin: '4px 0 0',
              fontSize: '0.8rem',
              color: 'var(--eg-muted-text)',
            }}
          >
            {error.message}
          </p>
        </div>
      </div>
    )
  }

  // ── Empty state ───────────────────────────
  // Don't show empty state while loading — shimmer covers it
  if (loading) return null

  const hasSourceData = rows.length > 0
  const isFilteredEmpty = hasSourceData && paginatedRows.length === 0

  if (paginatedRows.length > 0) return null

  if (appearance?.emptyStateComponent) {
    const EmptyComponent = appearance.emptyStateComponent
    return (
      <div style={overlayStyle} className="yg-overlay yg-overlay--empty">
        <EmptyComponent />
      </div>
    )
  }

  if (isFilteredEmpty) {
    const title = appearance?.filteredEmptyState?.title ?? 'No matching results'
    const description =
      appearance?.filteredEmptyState?.description ??
      'Try adjusting your filters'
    const icon = appearance?.filteredEmptyState?.icon

    return (
      <div
        className="yg-overlay yg-overlay--empty"
        style={overlayStyle}
        role="status"
        aria-label={title}
        aria-live="polite"
      >
        {icon ?? (
          <div
            style={{
              width: 56,
              height: 56,
              borderRadius: '50%',
              backgroundColor: 'var(--eg-empty-icon-bg)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '1.5rem',
            }}
          >
            🔍
          </div>
        )}
        <div style={{ textAlign: 'center' }}>
          <p
            style={{
              margin: 0,
              fontSize: '0.9375rem',
              fontWeight: 600,
              color: 'var(--eg-text)',
            }}
          >
            {title}
          </p>
          <p
            style={{
              margin: '4px 0 0',
              fontSize: '0.8125rem',
              color: 'var(--eg-muted-text)',
            }}
          >
            {description}
          </p>
        </div>
      </div>
    )
  }

  const title = appearance?.emptyState?.title ?? 'No data'
  const description =
    appearance?.emptyState?.description ?? 'No rows to display'
  const icon = appearance?.emptyState?.icon

  return (
    <div
      className="yg-overlay yg-overlay--empty"
      style={overlayStyle}
      role="status"
      aria-label={title}
      aria-live="polite"
    >
      {icon ?? (
        <div
          style={{
            width: 56,
            height: 56,
            borderRadius: '50%',
            backgroundColor: 'var(--eg-empty-icon-bg)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '1.5rem',
          }}
        >
          📭
        </div>
      )}
      <div style={{ textAlign: 'center' }}>
        <p
          style={{
            margin: 0,
            fontSize: '0.9375rem',
            fontWeight: 600,
            color: 'var(--eg-text)',
          }}
        >
          {title}
        </p>
        <p
          style={{
            margin: '4px 0 0',
            fontSize: '0.8125rem',
            color: 'var(--eg-muted-text)',
          }}
        >
          {description}
        </p>
      </div>
    </div>
  )
}
