// ============================================
// @elitegrid/adapter-react — Grid.tsx
// Root component — entry point for the developer
// ============================================

import React, { useEffect, useMemo, useState } from 'react'
import { GridContext } from '../context/GridContext'
import { GridBody } from './GridBody'
import { GridPagination } from './GridPagination'
import type { GridInstance, GridAPI, ColumnState, PaginationState } from '../create-grid'
import { useExport } from '../use-grid'
import { GridEvent } from '@elitegrid/core'
import type { SortDirection, SortModel, FilterModel, ColumnFilter } from '@elitegrid/core'

interface GridProps<TData = unknown> {
  grid: GridInstance<TData>
}

function buildGridAPI<TData>(grid: GridInstance<TData>): GridAPI<TData> {
  const { plugins, kernel, options } = grid

  // Derive row ID field once — mirrors the same derivation in createGrid
  const rowIdField =
    typeof options.rowId === 'string' ? (options.rowId as string) : 'id'

  // Helper — extract plain TData rows from a store namespace
  // All pipeline namespaces (raw, filtered, sorted, paginated) contain
  // plain TData objects — no NormalizedRow wrapper, no ._id or ._data
  const plainRows = (namespace: 'raw' | 'sorted' | 'paginated') =>
    kernel.store.read(namespace).rows as TData[]

  // Helper — get row ID from a plain data object
  const rowId = (r: TData): string => String((r as Record<string, unknown>)[rowIdField])

  return {
    // ── Data ────────────────────────────────
    setData: (rows) => plugins.dataSource.setData(rows),

    getData: () => plainRows('raw'),

    getDisplayedRows: () => plainRows('paginated'),

    refreshData: async () => {
      kernel.eventBus.emit(GridEvent.DATA_REFRESH_REQUESTED)
    },

    addRow: (row, index) => plugins.dataSource.addRow(row, index),

    updateRow: (id, changes) =>
      plugins.dataSource.updateRow(id, changes),

    deleteRow: (id) => plugins.dataSource.deleteRow(id),

    deleteRows: (ids) => {
      // Batch all deletes in one raw store write then emit DATA_CHANGED once.
      // The loop approach fires N full pipeline passes (filter â†’ sort â†’ paginate).
      // This approach fires exactly one — critical for bulk delete of 100+ rows.
      if (ids.length === 0) return
      const idSet = new Set(ids)
      const { rows } = kernel.store.read('raw')
      const remaining = (rows as TData[]).filter(
        (r: TData) => !idSet.has(rowId(r))
      )
      kernel.store.write('raw', {
        rows: remaining,
        totalCount: remaining.length,
      })
      // Notify selection plugin to remove deleted IDs
      ids.forEach((id) =>
        kernel.eventBus.emit(GridEvent.ROW_DELETED, { rowId: id })
      )
      kernel.eventBus.emit(GridEvent.DATA_CHANGED, { type: 'delete' })
    },

    // ── Columns ─────────────────────────────
    setColumnVisible: (id, visible) =>
      plugins.columnModel.setVisible(id, visible),

    setColumnWidth: (id, width) => plugins.columnModel.setWidth(id, width),

    setColumnPinned: (id, position) =>
      plugins.columnModel.setPinned(id, position),

    moveColumn: (id, toIndex) => plugins.columnModel.moveColumn(id, toIndex),

    // Returns the original ColumnDef objects the developer passed in.
    // The engine's internal ColumnDefinition is not exposed — developer
    // always works with their own typed ColumnDef.
    getAllColumns: () => options.columns,

    getVisibleColumns: () => {
      const visibleIds = new Set(
        plugins.columnModel.getVisibleColumns().map((c: { id: string }) => c.id)
      )
      return options.columns.filter((c) => visibleIds.has(c.field as string))
    },

    getColumnState: () => plugins.columnModel.getColumnState() as unknown as ColumnState[],

    applyColumnState: (state) =>
      plugins.columnModel.applyColumnState(state as unknown as Parameters<typeof plugins.columnModel.applyColumnState>[0]),

    // ── Sort ────────────────────────────────
    setSortModel: (model) => plugins.sort.setSortModel(model as unknown as SortModel[]),

    getSortModel: () => plugins.sort.getSortModel() as unknown as Array<{ columnId: string; direction: SortDirection }>,

    clearSort: () => plugins.sort.clearSort(),

    // ── Filter ──────────────────────────────
    setFilterModel: (model) => plugins.filter.setFilterModel(model as unknown as FilterModel),

    getFilterModel: () => plugins.filter.getFilterModel() as unknown as Record<string, unknown>,

    setColumnFilter: (columnId, filter) =>
      plugins.filter.setColumnFilter(columnId, filter as unknown as ColumnFilter),

    clearColumnFilter: (columnId) => plugins.filter.clearColumnFilter(columnId),

    clearFilters: () => plugins.filter.clearAll(),

    // ── Selection ───────────────────────────
    selectRow: (id) => plugins.selection.selectRow(id),

    deselectRow: (id) => plugins.selection.deselectRow(id),

    toggleRow: (id) => plugins.selection.toggleRow(id),

    selectAll: () => plugins.selection.selectAll(),

    deselectAll: () => plugins.selection.deselectAll(),

    isRowSelected: (id) => plugins.selection.isSelected(id),

    getSelectedRows: () => {
      // selectedIds contains plain row ID values (from the 'id' field or rowId config)
      // sorted rows are plain TData objects — filter directly by ID field
      const ids = new Set(plugins.selection.getSelectedIds())
      return plainRows('sorted').filter((r) => ids.has(rowId(r)))
    },

    getSelectedIds: () => new Set(plugins.selection.getSelectedIds()),

    // ── Editing ─────────────────────────────
    startEditing: (rId, columnId) => {
      // Find the row's current index in the paginated rows to build CellPosition
      const rows = plainRows('paginated')
      const rowIndex = rows.findIndex((r) => rowId(r) === rId)
      const { definitions } = kernel.store.read('columns')
      const columnIndex = (definitions as Array<{ id: string }>).findIndex(
        (c) => c.id === columnId
      )
      if (rowIndex === -1 || columnIndex === -1) return
      plugins.edit.startEdit({ rowId: rId, columnId, rowIndex, columnIndex })
    },

    stopEditing: (save = true) => {
      if (save) plugins.edit.commitEdit()
      else plugins.edit.cancelEdit()
    },

    isEditing: () => plugins.edit.isEditing(),

    getEditingCell: () => plugins.edit.getEditingCell(),

    // ── Pagination ──────────────────────────
    setPage: (page) => plugins.pagination.setPage(page),

    setPageSize: (size) => plugins.pagination.setPageSize(size),

    nextPage: () => plugins.pagination.nextPage(),

    previousPage: () => plugins.pagination.previousPage(),

    firstPage: () => plugins.pagination.firstPage(),

    lastPage: () => plugins.pagination.lastPage(),

    getPaginationState: () => plugins.pagination.getPaginationState() as unknown as PaginationState,

    // ── Scroll ──────────────────────────────
    scrollToRow: (rId) => {
      // First check if the row is on the current paginated page
      let index = plainRows('paginated').findIndex((r) => rowId(r) === rId)

      if (index === -1) {
        // Row is not on the current page — find it in the full sorted set
        // and navigate to the page it lives on before scrolling
        const allRows = plainRows('sorted')
        const globalIndex = allRows.findIndex((r) => rowId(r) === rId)
        if (globalIndex === -1) return // row not found at all

        const pageSize = kernel.store.read('paginated').pageSize ?? 0
        if (pageSize > 0) {
          const targetPage = Math.floor(globalIndex / pageSize) + 1
          plugins.pagination.setPage(targetPage)
          // After page change, recalculate index within new paginated rows
          index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
        }
      }

      if (index !== -1) plugins.viewport.scrollToRow(index)
    },

    scrollToColumn: (columnId) => plugins.viewport.scrollToColumn(columnId),

    scrollToCell: (rId, columnId) => {
      let index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
      if (index === -1) {
        const globalIndex = plainRows('sorted').findIndex(
          (r) => rowId(r) === rId
        )
        if (globalIndex !== -1) {
          const pageSize = kernel.store.read('paginated').pageSize ?? 0
          if (pageSize > 0) {
            plugins.pagination.setPage(Math.floor(globalIndex / pageSize) + 1)
            index = plainRows('paginated').findIndex((r) => rowId(r) === rId)
          }
        }
      }
      if (index !== -1) plugins.viewport.scrollToRow(index)
      plugins.viewport.scrollToColumn(columnId)
    },

    // ── Export ──────────────────────────────
    exportCSV: (exportOptions) => {
      plugins.export.export({
        filename:
          exportOptions?.filename ?? options.export?.filename ?? 'export',
        scope: exportOptions?.scope ?? options.export?.scope ?? 'filtered',
        columns: exportOptions?.columns,
        includeHeader: exportOptions?.includeHeader,
        delimiter: exportOptions?.delimiter,
      })
    },

    // ── Lifecycle ───────────────────────────
    destroy: () => kernel.destroy(),
  }
}

// ── useAriaLive ───────────────────────────────────────────────────
// Subscribes to ANNOUNCE events from AnnouncementPlugin and exposes
// the latest polite and assertive messages for the aria-live regions.
// Two separate regions are required by ARIA spec — one per live level.

function useAriaLive(grid: GridInstance<unknown>) {
  const [politeMsg, setPoliteMsg] = useState('')
  const [assertiveMsg, setAssertiveMsg] = useState('')

  useEffect(() => {
    const unsub = grid.kernel.eventBus.on(
      GridEvent.ANNOUNCE,
      (payload: { priority?: string; message: string }) => {
        if (payload.priority === 'assertive') {
          setAssertiveMsg(payload.message)
        } else {
          setPoliteMsg(payload.message)
        }
      }
    )
    return unsub
  }, [grid])

  return { politeMsg, assertiveMsg }
}

// Visually hidden but readable by screen readers
// Standard pattern — clip + size-0 + no overflow, avoids display:none
const SR_ONLY: React.CSSProperties = {
  position: 'absolute',
  width: 1,
  height: 1,
  padding: 0,
  margin: -1,
  overflow: 'hidden',
  clip: 'rect(0, 0, 0, 0)',
  whiteSpace: 'nowrap',
  border: 0,
}

// ── GridToolbar ───────────────────────────────────────────────────
// Renders above the header — export button and future toolbar items.
// Only shown when options.export is defined or showToolbar is not false.

function GridToolbar({ grid }: { grid: GridInstance<unknown> }) {
  const { triggerExport } = useExport(grid)
  const exportConfig = grid.options.export

  // Hide toolbar if export not configured and showToolbar not explicitly true
  if (!exportConfig) return null

  return (
    <div
      style={{
        display: 'flex',
        justifyContent: 'flex-end',
        alignItems: 'center',
        padding: '6px 8px',
        gap: 6,
        borderBottom: '1px solid var(--eg-border-color)',
        backgroundColor: 'var(--eg-toolbar-bg)',
        flexShrink: 0,
      }}
    >
      <button
        onClick={() => triggerExport()}
        title="Export visible rows as CSV"
        aria-label="Export CSV"
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 5,
          fontSize: '0.75rem',
          fontWeight: 600,
          padding: '4px 12px',
          borderRadius: 6,
          border: '1px solid var(--eg-border)',
          background: 'var(--eg-btn-bg)',
          cursor: 'pointer',
          color: 'var(--eg-btn-text)',
          lineHeight: 1.4,
        }}
      >
        <svg
          width="13"
          height="13"
          viewBox="0 0 13 13"
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
        >
          <path
            d="M6.5 1v7M3.5 5.5l3 3 3-3M1.5 9.5v1a1 1 0 001 1h8a1 1 0 001-1v-1"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
        Export CSV
      </button>
    </div>
  )
}

export function Grid<TData = unknown>({ grid }: GridProps<TData>) {
  const { options } = grid

  const api = useMemo(() => buildGridAPI(grid), [grid])
  const { politeMsg, assertiveMsg } = useAriaLive(grid as GridInstance<unknown>)

  // aria-rowcount — total filtered row count, updated reactively
  const [totalRows, setTotalRows] = useState(
    () => grid.kernel.store.read('filtered').matchCount
  )
  const [isLoading, setIsLoading] = useState(
    () => grid.kernel.store.read('raw').loading
  )

  useEffect(() => {
    const unsubFiltered = grid.kernel.store.subscribe('filtered', (state) => {
      setTotalRows(state.matchCount)
    })
    const unsubRaw = grid.kernel.store.subscribe('raw', (state) => {
      setIsLoading(state.loading)
    })
    return () => {
      unsubFiltered()
      unsubRaw()
    }
  }, [grid])

  // ── Export download ──────────────────────────────────────────────
  // Listen to EXPORT_COMPLETED and trigger browser file download.
  // The plugin owns CSV generation — the adapter owns the DOM download.
  useEffect(() => {
    const unsub = grid.kernel.eventBus.on(
      GridEvent.EXPORT_COMPLETED,
      (payload: { content: string; filename: string }) => {
        const blob = new Blob([payload.content], {
          type: 'text/csv;charset=utf-8;',
        })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = payload.filename
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        // Delay revoke — a.click() triggers download asynchronously.
        // Revoking synchronously races the browser's download start,
        // producing empty files on slow hardware or Safari.
        // 1000ms matches AG Grid's approach; enough for any browser.
        setTimeout(() => URL.revokeObjectURL(url), 1000)
      }
    )
    return unsub
  }, [grid])

  // Fire onReady once on mount only
  // options.events is intentionally excluded — it's mutated externally in the playground
  // and should not re-trigger this effect
  useEffect(() => {
    options.events?.onReady?.(api)
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [api])

  const theme = options.appearance?.theme ?? 'light'
  const density = options.appearance?.density ?? 'normal'
  const className = [
    'yg-grid',
    `yg-theme-${theme}`,
    `yg-density-${density}`,
    options.appearance?.className,
  ]
    .filter(Boolean)
    .join(' ')

  const style: React.CSSProperties = {
    flex: 1,
    width: '100%',
    position: 'relative',
    display: 'flex',
    flexDirection: 'column',
    overflow: 'hidden',
    ...options.appearance?.style,
  }

  return (
    <GridContext.Provider value={grid as GridInstance<unknown>}>
      <div
        className={className}
        style={style}
        role="grid"
        aria-label={options.accessibility?.gridLabel ?? 'Data grid'}
        aria-rowcount={totalRows}
        aria-busy={isLoading || undefined}
      >
        {grid.options.export != null && (
          <GridToolbar grid={grid as GridInstance<unknown>} />
        )}
        {/* GridHeader is rendered inside GridBody's scroll container (sticky)
            so horizontal scroll moves header + rows as a single native unit */}
        <GridBody />
        <GridPagination />

        {/* ── Screen reader live regions ── */}
        {/* Visually hidden — only for assistive technology */}
        {/* Two separate elements required: one per aria-live level */}
        <div
          role="status"
          aria-live="polite"
          aria-atomic="true"
          style={SR_ONLY}
        >
          {politeMsg}
        </div>
        <div
          role="alert"
          aria-live="assertive"
          aria-atomic="true"
          style={SR_ONLY}
        >
          {assertiveMsg}
        </div>
      </div>
    </GridContext.Provider>
  )
}
