// ============================================
// @elitegrid/core — Kernel
// The central coordinator of the engine
// Holds EventBus and DataStore
// Manages plugin registration and lifecycle
// ============================================

import { EventBus, type IEventBus } from '../event-bus/index'
import { GridEvent } from '../event-bus/events'
import { DataStore, type IDataStore } from '../data-store/index'

// ── Plugin Interface ───────────────────────────
// Every plugin must implement this interface

export interface Plugin {
  // Unique identifier for this plugin
  // Used to retrieve plugin from kernel
  id: string

  // Called by kernel during initialization
  // Plugin receives kernel context here
  init(context: PluginContext): void

  // Called by kernel during destruction
  // Plugin must clean up subscriptions and state
  destroy(): void
}

// ── Plugin Context ─────────────────────────────
// What every plugin receives when initialized
// This is the only way plugins access shared resources

export interface PluginContext {
  // The event bus — for emitting and subscribing to events
  eventBus: IEventBus

  // The data store — for reading and writing state
  store: IDataStore

  // Access other registered plugins by ID
  // Use sparingly — prefer event bus for communication
  getPlugin<T extends Plugin>(id: string): T | null
}

// ── Kernel Interface ───────────────────────────

export interface IKernel {
  // Register a plugin before initialization
  register(plugin: Plugin): void

  // Initialize all registered plugins
  // Must be called after all plugins are registered
  init(): void

  // Get a registered plugin by ID
  get<T extends Plugin>(id: string): T | null

  // Access the event bus directly
  readonly eventBus: IEventBus

  // Access the data store directly
  readonly store: IDataStore

  // Tear down everything — plugins, event bus, store
  destroy(): void
}

// ── Implementation ─────────────────────────────

export class Kernel implements IKernel {
  // Core shared resources
  readonly eventBus: IEventBus
  readonly store: IDataStore

  // Registered plugins — insertion order preserved
  private plugins: Map<string, Plugin> = new Map()

  // Track initialization state
  private initialized: boolean = false

  constructor() {
    // Create shared resources
    // These are created once and shared with all plugins
    this.eventBus = new EventBus()
    this.store = new DataStore()
  }

  // ── Register ───────────────────────────────

  register(plugin: Plugin): void {
    // Prevent registration after initialization
    // Plugins must be registered before init() is called
    if (this.initialized) {
      throw new Error(
        `[EliteGrid] Cannot register plugin "${plugin.id}" after kernel is initialized. ` +
          `Register all plugins before calling kernel.init()`
      )
    }

    // Prevent duplicate plugin IDs
    if (this.plugins.has(plugin.id)) {
      throw new Error(
        `[EliteGrid] Plugin "${plugin.id}" is already registered. ` +
          `Each plugin must have a unique ID.`
      )
    }

    this.plugins.set(plugin.id, plugin)
  }

  // ── Init ───────────────────────────────────

  init(): void {
    // Prevent double initialization
    if (this.initialized) {
      throw new Error(
        `[EliteGrid] Kernel is already initialized. ` +
          `Call kernel.init() only once.`
      )
    }

    // Build the plugin context
    // This is what every plugin receives
    const context: PluginContext = {
      eventBus: this.eventBus,
      store: this.store,
      // Plugins call getPlugin() during their own init() — before this.initialized
      // is set to true. Use a direct map lookup here so the pre-init guard on the
      // public get() method doesn't incorrectly block cross-plugin access.
      getPlugin: <T extends Plugin>(id: string) => {
        const p = this.plugins.get(id)
        return p ? (p as T) : null
      },
    }

    // Initialize all plugins in registration order
    // Order matters — plugins registered first init first
    // Wrap each init in try-catch: a bad plugin must not leave the kernel
    // half-initialized — log the failure with the plugin ID and rethrow
    // so the calling code knows something went wrong.
    const initializedPlugins: Plugin[] = []
    try {
      this.plugins.forEach((plugin) => {
        plugin.init(context)
        initializedPlugins.push(plugin)
      })
    } catch (err) {
      // Tear down whatever did initialize, in reverse order
      ;[...initializedPlugins].reverse().forEach((plugin) => {
        try {
          plugin.destroy()
        } catch {
          /* best-effort */
        }
      })
      this.plugins.clear()
      this.initialized = false
      throw err
    }

    this.initialized = true

    // Notify everyone the engine is ready
    this.eventBus.emit(GridEvent.GRID_READY)
  }

  // ── Get Plugin ─────────────────────────────

  get<T extends Plugin>(id: string): T | null {
    if (!this.initialized) {
      throw new Error(
        `[EliteGrid] Cannot call kernel.get("${id}") before kernel.init(). ` +
          `Call kernel.init() first, then access plugins.`
      )
    }

    const plugin = this.plugins.get(id)

    if (!plugin) {
      return null
    }

    return plugin as T
  }

  // ── Destroy ────────────────────────────────

  destroy(): void {
    // Notify everyone before teardown
    this.eventBus.emit(GridEvent.GRID_DESTROYED)

    // Destroy all plugins in reverse registration order
    // Last registered plugin destroys first
    // One failing destroy must not stop the rest — catch per plugin
    const pluginList = [...this.plugins.values()]
    pluginList.reverse().forEach((plugin) => {
      try {
        plugin.destroy()
      } catch (err) {
        // console.error(
        //   `[EliteGrid] Plugin "${plugin.id}" threw during destroy:`,
        //   err
        // )
      }
    })

    // Clear all event subscriptions
    this.eventBus.clearAll()

    // Clear plugin registry
    this.plugins.clear()

    // Reset initialization state
    this.initialized = false
  }
}
