// ============================================
// @elitegrid/core — Cell Value Plugin
// Value extraction, formatting, and parsing
// Does NOT own a store namespace — it is a
// pure service plugin queried directly by the
// adapter and other plugins (e.g. EditPlugin,
// ExportPlugin, FilterPlugin).
// ============================================
//
// Responsibilities:
//   - Extract a raw value from a row using the
//     column's field path (supports nested paths:
//     "user.address.city")
//   - Return a formatted display string using
//     the column's formatter function
//   - Parse an edited string back to the correct
//     type via the column's parser function
//   - Honour custom getter / setter per column
//   - Return an export-specific value string for
//     CSV output (falls back to display value)
//   - Handle null / undefined gracefully —
//     always returns '' for display, never throws
//
// No events emitted. No store namespace owned.
// Other plugins call this plugin's methods
// directly via kernel.get(CELL_VALUE_PLUGIN_ID).
//
// Column value config is registered per-column
// by the adapter after kernel.init(), following
// the same pattern as EditPlugin.registerColumnEditor.

import type { Plugin, PluginContext } from '../../kernel/index'
import type { ColumnId } from '../../types/index'

// ── Plugin ID ─────────────────────────────────

export const CELL_VALUE_PLUGIN_ID = 'cell-value'

// ── Per-column value config ────────────────────
// Registered by the adapter for each column that
// needs custom extraction, formatting, or parsing.
// All fields are optional — defaults apply when absent.

export interface ColumnValueConfig {
  // Custom extractor — replaces field-path lookup
  getter?: (row: unknown) => unknown

  // Custom writer — merges the new value into the row
  // Should return a new row object (immutable pattern)
  setter?: (row: unknown, value: unknown) => unknown

  // Display formatter — raw value → display string
  // Returning '' is valid (blank cell)
  formatter?: (value: unknown, row: unknown) => string

  // Export formatter — raw value → CSV string
  // Falls back to formatter, then to String(value)
  exportFormatter?: (value: unknown, row: unknown) => string

  // Parser — edited string → typed value
  // Called before the EditPlugin commits a value
  parser?: (raw: string) => unknown
}

// ── Implementation ─────────────────────────────

export class CellValuePlugin implements Plugin {
  readonly id = CELL_VALUE_PLUGIN_ID

  private context!: PluginContext

  // Per-column configs registered by the adapter
  private columnConfigs: Map<ColumnId, ColumnValueConfig> = new Map()

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context
    // No events to subscribe to — this plugin is a pure service.
  }

  // ── Column Config Registration ─────────────
  // Called by the adapter after kernel.init().

  registerColumnConfig(columnId: ColumnId, config: ColumnValueConfig): void {
    this.columnConfigs.set(columnId, config)
  }

  unregisterColumnConfig(columnId: ColumnId): void {
    this.columnConfigs.delete(columnId)
  }

  getColumnConfig(columnId: ColumnId): ColumnValueConfig | undefined {
    return this.columnConfigs.get(columnId)
  }

  // ── Raw Value Extraction ───────────────────
  // Returns the unformatted value from the row.
  // Priority: custom getter → field-path lookup.

  getRawValue(row: unknown, columnId: ColumnId): unknown {
    const config = this.columnConfigs.get(columnId)

    if (config?.getter) {
      return config.getter(row)
    }

    // Resolve field from column definitions
    const field = this.getField(columnId)
    if (!field) return undefined

    return resolveFieldPath(row, field)
  }

  // ── Display Value ──────────────────────────
  // Returns the string shown in the cell.
  // Priority: formatter → String(rawValue) → ''

  getDisplayValue(row: unknown, columnId: ColumnId): string {
    const raw = this.getRawValue(row, columnId)
    const config = this.columnConfigs.get(columnId)

    if (config?.formatter) {
      return config.formatter(raw, row)
    }

    return rawToString(raw)
  }

  // ── Export Value ───────────────────────────
  // Returns the string written into the CSV cell.
  // Priority: exportFormatter → formatter → String(rawValue)

  getExportValue(row: unknown, columnId: ColumnId): string {
    const raw = this.getRawValue(row, columnId)
    const config = this.columnConfigs.get(columnId)

    if (config?.exportFormatter) {
      return config.exportFormatter(raw, row)
    }

    if (config?.formatter) {
      return config.formatter(raw, row)
    }

    return rawToString(raw)
  }

  // ── Value Parser ───────────────────────────
  // Converts the editor's string output to the
  // typed value the data model expects.
  // Called by EditPlugin before committing.
  // Falls back to the raw string if no parser is set.

  parseValue(raw: string, columnId: ColumnId): unknown {
    const config = this.columnConfigs.get(columnId)

    if (config?.parser) {
      return config.parser(raw)
    }

    // Default parsers by column type from the store
    // (avoids hard-coding — type comes from ColumnDefinition)
    return raw
  }

  // ── Value Setter ───────────────────────────
  // Merges the new value into a row object.
  // Priority: custom setter → field-path write.
  // Returns a new row — does NOT mutate in place.

  setValue(row: unknown, columnId: ColumnId, value: unknown): unknown {
    const config = this.columnConfigs.get(columnId)

    if (config?.setter) {
      return config.setter(row, value)
    }

    const field = this.getField(columnId)
    if (!field) return row

    return setFieldPath(row, field, value)
  }

  // ── Batch Helpers ──────────────────────────
  // Convenience methods for the adapter's render loop.

  // Returns display values for every visible column in one pass.
  getDisplayRow(row: unknown, columnIds: ColumnId[]): Record<ColumnId, string> {
    const result: Record<ColumnId, string> = {}
    for (const id of columnIds) {
      result[id] = this.getDisplayValue(row, id)
    }
    return result
  }

  // Returns export values for every column in one pass.
  getExportRow(row: unknown, columnIds: ColumnId[]): Record<ColumnId, string> {
    const result: Record<ColumnId, string> = {}
    for (const id of columnIds) {
      result[id] = this.getExportValue(row, id)
    }
    return result
  }

  // ── Internal Helpers ───────────────────────

  // Looks up the field string from the columns namespace.
  private getField(columnId: ColumnId): string | undefined {
    const { definitions } = this.context.store.read('columns')
    const col = definitions.find((d) => d.id === columnId)
    return col?.field
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.columnConfigs.clear()
  }
}

// ── Pure Utility Functions ─────────────────────
// Exported so the adapter and other plugins can use
// them directly without going through the plugin.

/**
 * Resolves a dot-separated field path against an object.
 * Returns undefined for missing segments rather than throwing.
 *
 * Examples:
 *   resolveFieldPath({ a: { b: 1 } }, 'a.b') → 1
 *   resolveFieldPath({ a: null },     'a.b') → undefined
 *   resolveFieldPath({ a: 1 },        'a')   → 1
 */
export function resolveFieldPath(obj: unknown, path: string): unknown {
  if (obj === null || obj === undefined) return undefined
  if (!path) return undefined

  const parts = path.split('.')
  let current: unknown = obj

  for (const part of parts) {
    if (current === null || current === undefined) return undefined
    if (typeof current !== 'object') return undefined
    current = (current as Record<string, unknown>)[part]
  }

  return current
}

/**
 * Sets a value at a dot-separated field path, returning a
 * new object at each level (shallow-clone, immutable pattern).
 * Intermediate objects that don't exist are created.
 *
 * Examples:
 *   setFieldPath({ a: { b: 1 } }, 'a.b', 2) → { a: { b: 2 } }
 *   setFieldPath({ x: 1 },        'a.b', 2) → { x: 1, a: { b: 2 } }
 */
export function setFieldPath(
  obj: unknown,
  path: string,
  value: unknown
): unknown {
  const parts = path.split('.')

  // Recursive helper — returns a new object with the updated path
  function setDeep(current: unknown, remainingParts: string[]): unknown {
    const head = remainingParts[0] as string
    const tail = remainingParts.slice(1)

    const currentObj =
      current !== null && typeof current === 'object'
        ? (current as Record<string, unknown>)
        : {}

    if (tail.length === 0) {
      // Base case — set the value
      return { ...currentObj, [head]: value }
    }

    // Recurse into the next level
    return {
      ...currentObj,
      [head]: setDeep(currentObj[head], tail),
    }
  }

  return setDeep(obj, parts)
}

/**
 * Converts a raw cell value to a display/export string.
 * Never throws, always returns a string.
 */
export function rawToString(value: unknown): string {
  if (value === null || value === undefined) return ''
  if (typeof value === 'string') return value
  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value)
  }
  if (value instanceof Date) {
    return isNaN(value.getTime()) ? '' : value.toLocaleDateString()
  }
  // Objects / arrays — JSON for debugging, adapters override via formatter
  try {
    return JSON.stringify(value)
  } catch {
    return ''
  }
}
