// ============================================
// @elitegrid/core — Data Store
// Namespaced shared state for all plugins
// One plugin owns one namespace — no exceptions
// ============================================

import type {
  RowId,
  ColumnId,
  PinPosition,
  SortModel,
  FilterModel,
  CellPosition,
  SelectionMode,
  PaginationState,
  SelectionState,
  EditState,
} from '../types/index'
import { isDev, devWarn } from '../utils/dev'

// ── Namespace Shapes ──────────────────────────
// Each interface defines what one plugin stores

export interface RawNamespace {
  rows: unknown[]
  totalCount: number
  loading: boolean
  error: Error | null
}

export interface FilteredNamespace {
  rows: unknown[]
  matchCount: number
  filterModel: FilterModel
}

export interface SortedNamespace {
  rows: unknown[]
  sortModel: SortModel[]
}

export interface PaginatedNamespace {
  rows: unknown[]
  currentPage: number
  pageSize: number
  totalPages: number
  totalRows: number
  startRow: number
  endRow: number
  hasNextPage: boolean
  hasPreviousPage: boolean
}

export interface ColumnDefinition {
  id: ColumnId
  field: string
  header: string
  width?: number
  minWidth?: number
  maxWidth?: number
  flex?: number
  visible: boolean
  pinned: PinPosition
  resizable: boolean
  sortable: boolean
  filterable: boolean
  editable: boolean
}

export interface ColumnsNamespace {
  definitions: ColumnDefinition[]
  order: ColumnId[]
  widths: Map<ColumnId, number>
  visibility: Map<ColumnId, boolean>
  pinState: Map<ColumnId, PinPosition>
}

export interface ViewportNamespace {
  visibleRows: unknown[]
  visibleColumnIds: ColumnId[]
  startRowIndex: number
  endRowIndex: number
  startColumnIndex: number
  endColumnIndex: number
  offsetTop: number
  offsetLeft: number
  totalHeight: number
  totalWidth: number
  scrollTop: number
  scrollLeft: number
  containerWidth: number
  containerHeight: number
  rowHeight: number
}

export interface SelectionNamespace {
  selectedIds: Set<RowId>
  mode: SelectionMode
  isAllSelected: boolean
  isIndeterminate: boolean
  count: number
  anchorId: RowId | null
}

export interface EditingNamespace {
  isEditing: boolean
  editingCell: CellPosition | null
  originalValue: unknown
  currentValue: unknown
  isValid: boolean
  validationError: string | null
}

export interface FocusNamespace {
  focusedCell: CellPosition | null
  previousCell: CellPosition | null
}

// ── Complete Store Shape ───────────────────────
// All namespaces together

export interface StoreState {
  raw: RawNamespace
  filtered: FilteredNamespace
  sorted: SortedNamespace
  paginated: PaginatedNamespace
  columns: ColumnsNamespace
  viewport: ViewportNamespace
  selection: SelectionNamespace
  editing: EditingNamespace
  focus: FocusNamespace
}

// ── Namespace Keys ─────────────────────────────
// Used for type-safe read and write operations

export type NamespaceKey = keyof StoreState

// ── Subscriber Function ────────────────────────
// Called when a namespace changes

export type StoreSubscriber<K extends NamespaceKey> = (
  state: StoreState[K]
) => void

// ── Unsubscribe Function ───────────────────────

export type StoreUnsubscribe = () => void

// ── Interface ──────────────────────────────────

export interface IDataStore {
  // Read current state of a namespace
  read<K extends NamespaceKey>(namespace: K): StoreState[K]

  // Write partial update to a namespace
  // callerId: the plugin ID writing the update — used for dev-mode ownership checks
  write<K extends NamespaceKey>(
    namespace: K,
    update: Partial<StoreState[K]>,
    callerId?: string
  ): void

  // Declare this plugin owns a namespace — enforced in dev mode
  registerOwner(namespace: NamespaceKey, pluginId: string): void

  // Subscribe to changes in a namespace
  subscribe<K extends NamespaceKey>(
    namespace: K,
    subscriber: StoreSubscriber<K>
  ): StoreUnsubscribe

  // Get a snapshot of the entire store
  // Used for debugging only
  snapshot(): StoreState

  // Subscribe to a specific row's data changes
  // V1 — stub, no-op. V2 — fires when only that row changes
  subscribeToRow(
    rowId: RowId,
    handler: (data: unknown) => void
  ): StoreUnsubscribe

  // Notify a specific row's subscribers directly
  // V1 — stub, no-op. V2 — called by ViewportPlugin on ROW_UPDATED
  notifyRow(rowId: RowId, data: unknown): void
}

// ── Default State ──────────────────────────────
// Initial values for every namespace

function createDefaultState(): StoreState {
  return {
    raw: {
      rows: [],
      totalCount: 0,
      loading: false,
      error: null,
    },

    filtered: {
      rows: [],
      matchCount: 0,
      filterModel: { columns: {} },
    },

    sorted: {
      rows: [],
      sortModel: [],
    },

    paginated: {
      rows: [],
      currentPage: 1,
      pageSize: 25,
      totalPages: 0,
      totalRows: 0,
      startRow: 0,
      endRow: 0,
      hasNextPage: false,
      hasPreviousPage: false,
    },

    columns: {
      definitions: [],
      order: [],
      widths: new Map(),
      visibility: new Map(),
      pinState: new Map(),
    },

    viewport: {
      visibleRows: [],
      visibleColumnIds: [],
      startRowIndex: 0,
      endRowIndex: 0,
      startColumnIndex: 0,
      endColumnIndex: 0,
      offsetTop: 0,
      offsetLeft: 0,
      totalHeight: 0,
      totalWidth: 0,
      scrollTop: 0,
      scrollLeft: 0,
      containerWidth: 0,
      containerHeight: 0,
      rowHeight: 40,
    },

    selection: {
      selectedIds: new Set(),
      mode: 'none',
      isAllSelected: false,
      isIndeterminate: false,
      count: 0,
      anchorId: null,
    },

    editing: {
      isEditing: false,
      editingCell: null,
      originalValue: null,
      currentValue: null,
      isValid: true,
      validationError: null,
    },

    focus: {
      focusedCell: null,
      previousCell: null,
    },
  }
}

// ── Implementation ─────────────────────────────

export class DataStore implements IDataStore {
  // The actual state object
  private state: StoreState = createDefaultState()

  // Subscribers grouped by namespace
  // Key: namespace name
  // Value: Set of subscriber functions
  private subscribers: Map<NamespaceKey, Set<StoreSubscriber<NamespaceKey>>> =
    new Map()

  // Row-level subscriber map
  // Key: RowId
  // Value: Set of handlers for that row
  // V1 — declared but never populated
  // V2 — ViewportPlugin calls notifyRow() on ROW_UPDATED
  private rowSubscribers: Map<RowId, Set<(data: unknown) => void>> = new Map()

  // Namespace ownership registry — one plugin owns one namespace
  // Enforced in dev mode only; production is a no-op for zero cost.
  private namespaceOwners: Map<NamespaceKey, string> = new Map()

  // ── Register Ownership ────────────────────
  // Called by each plugin during init() to declare which namespace it owns.
  // Only the first call for a given namespace is recorded — subsequent calls
  // from other plugins trigger a dev-mode warning.

  registerOwner(namespace: NamespaceKey, pluginId: string): void {
    if (!isDev()) return
    if (this.namespaceOwners.has(namespace)) {
      const existing = this.namespaceOwners.get(namespace)
      if (existing !== pluginId) {
        devWarn(
          `[EliteGrid] Dev warning: Plugin "${pluginId}" is trying to own namespace ` +
            `"${namespace}" but it is already owned by "${existing}". ` +
            `One plugin must own one namespace — no exceptions.`
        )
      }
      return
    }
    this.namespaceOwners.set(namespace, pluginId)
  }

  // ── Read ──────────────────────────────────

  read<K extends NamespaceKey>(namespace: K): StoreState[K] {
    // Return a shallow copy to prevent direct mutation
    // Plugins must use write() to update state
    // not mutate the returned object directly
    const current = this.state[namespace]

    // Shallow copy — object spread
    // Deep clone would be too expensive for hot paths
    return { ...current } as StoreState[K]
  }

  // ── Write ─────────────────────────────────

  write<K extends NamespaceKey>(
    namespace: K,
    update: Partial<StoreState[K]>,
    callerId?: string
  ): void {
    // Dev-mode cross-namespace ownership check
    if (isDev() && callerId !== undefined) {
      const owner = this.namespaceOwners.get(namespace)
      if (owner !== undefined && owner !== callerId) {
        devWarn(
          `[EliteGrid] Dev warning: Plugin "${callerId}" is writing to namespace ` +
            `"${namespace}" which is owned by "${owner}". ` +
            `Only the owning plugin should write to its namespace.`
        )
      }
    }

    // Merge the update into current state — produces one new object reference
    // Only provided fields are updated; unmentioned fields stay unchanged
    this.state[namespace] = {
      ...this.state[namespace],
      ...update,
    }

    // Notify all subscribers of this namespace
    this.notify(namespace)
  }

  // ── Subscribe ─────────────────────────────

  subscribe<K extends NamespaceKey>(
    namespace: K,
    subscriber: StoreSubscriber<K>
  ): StoreUnsubscribe {
    // Create subscriber set for this namespace if needed
    if (!this.subscribers.has(namespace)) {
      this.subscribers.set(namespace, new Set())
    }

    const subs = this.subscribers.get(namespace)!
    subs.add(subscriber as StoreSubscriber<NamespaceKey>)

    // Return unsubscribe function
    return () => {
      subs.delete(subscriber as StoreSubscriber<NamespaceKey>)
      if (subs.size === 0) {
        this.subscribers.delete(namespace)
      }
    }
  }

  // ── Snapshot ──────────────────────────────

  snapshot(): StoreState {
    // Return full state copy for debugging
    return { ...this.state }
  }

  // ── Private: Notify ───────────────────────

  private notify(namespace: NamespaceKey): void {
    const subs = this.subscribers.get(namespace)

    if (!subs || subs.size === 0) {
      return
    }

    // write() already produced a new object reference — pass it directly.
    // A second spread here is redundant and wastes an allocation per write.
    const current = this.state[namespace]

    // Iterate the Set directly — for...of is safe during iteration:
    // deleted entries are skipped, new entries not visited.
    // One throwing subscriber must not block the rest.
    for (const subscriber of subs) {
      try {
        subscriber(current)
      } catch (err) {
        //console.error('[EliteGrid] DataStore subscriber threw:', err)
      }
    }
  }

  // ── Subscribe To Row ──────────────────────
  // V1 — returns no-op unsubscribe, map is never populated
  // V2 — GridCell calls this, notifyRow fills the map

  subscribeToRow(
    rowId: RowId,
    handler: (data: unknown) => void
  ): StoreUnsubscribe {
    if (!this.rowSubscribers.has(rowId)) {
      this.rowSubscribers.set(rowId, new Set())
    }

    const handlers = this.rowSubscribers.get(rowId)!
    handlers.add(handler)

    return () => {
      handlers.delete(handler)
      if (handlers.size === 0) {
        this.rowSubscribers.delete(rowId)
      }
    }
  }

  // ── Notify Row ────────────────────────────
  // V1 — never called, stub sitting ready
  // V2 — ViewportPlugin calls this instead of
  //      full calculateViewport() on ROW_UPDATED

  notifyRow(rowId: RowId, data: unknown): void {
    const handlers = this.rowSubscribers.get(rowId)
    if (!handlers || handlers.size === 0) return
    // for...of — no array allocation, safe during iteration
    for (const handler of handlers) {
      handler(data)
    }
  }
}
