// ============================================
// @elitegrid/adapter-react — GridFilterPopover.tsx
// Per-column filter popover
//
// Opens when user clicks filter icon in header
// Shows operator selector + value input(s)
// Applies filter to engine on Apply click
// ============================================

import React, { useState, useEffect, useRef, useCallback } from 'react'
import { useGridContext } from '../context/GridContext'
import type {
  TextFilterOperator,
  NumberFilterOperator,
  DateFilterOperator,
  BooleanFilterOperator,
  ColumnFilter,
} from '@elitegrid/core'
import { parseLocalDate } from '../utils/date'

// ── Types ─────────────────────────────────────

type FilterType = 'text' | 'number' | 'date' | 'boolean'

interface GridFilterPopoverProps {
  columnId: string
  filterType: FilterType
  anchorRef: React.RefObject<HTMLDivElement>
  onClose: () => void
  placement?: 'bottom' | 'top' | 'auto'
}

// ── Operator labels ───────────────────────────

const TEXT_OPERATORS: { value: TextFilterOperator; label: string }[] = [
  { value: 'contains', label: 'Contains' },
  { value: 'notContains', label: 'Does not contain' },
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'startsWith', label: 'Starts with' },
  { value: 'endsWith', label: 'Ends with' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const NUMBER_OPERATORS: { value: NumberFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'greaterThan', label: 'Greater than' },
  { value: 'greaterThanOrEqual', label: 'Greater than or equal' },
  { value: 'lessThan', label: 'Less than' },
  { value: 'lessThanOrEqual', label: 'Less than or equal' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const DATE_OPERATORS: { value: DateFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'before', label: 'Before' },
  { value: 'after', label: 'After' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const BOOLEAN_OPERATORS: { value: BooleanFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

// Operators that need zero inputs
const NO_INPUT_OPERATORS = ['isEmpty', 'isNotEmpty']

// Operators that need two inputs
const TWO_INPUT_OPERATORS = ['between']

// ── Position calculation helper ───────────────
// Extracted so it can be called both in the useState lazy initializer
// (gives the correct coords on the very first render, preventing the
// top-left flash) and inside the resize/scroll effect.
//
// Uses position:fixed coordinates (viewport-relative).
// Returns { top: -9999, left: -9999 } when the anchor is not yet in the
// DOM so the popover stays off-screen instead of flashing at (0, 0).

function calcPopoverPosition(
  anchor: HTMLDivElement | null,
  placement: 'bottom' | 'top' | 'auto'
): { top: number; left: number } {
  if (!anchor) return { top: -9999, left: -9999 }
  const rect = anchor.getBoundingClientRect()
  const POPOVER_HEIGHT = 280
  const POPOVER_WIDTH = 260
  const spaceBelow = window.innerHeight - rect.bottom
  const spaceAbove = rect.top
  const left = Math.min(rect.left, window.innerWidth - POPOVER_WIDTH - 8)
  const openAbove =
    placement === 'top' ||
    (placement === 'auto' &&
      spaceBelow < POPOVER_HEIGHT &&
      spaceAbove > spaceBelow)
  return {
    top: openAbove ? rect.top - POPOVER_HEIGHT - 4 : rect.bottom + 4,
    left,
  }
}

// ── GridFilterPopover ─────────────────────────

export function GridFilterPopover({
  columnId,
  filterType,
  anchorRef,
  onClose,
  placement = 'auto',
}: GridFilterPopoverProps) {
  const grid = useGridContext()
  const popoverRef = useRef<HTMLDivElement>(null)

  // Get current filter state for this column
  const currentFilter = grid.kernel.store.read('filtered').filterModel.columns[
    columnId
  ] as Record<string, unknown> | undefined

  // ── Local state ───────────────────────────
  const getDefaultOperator = () => {
    switch (filterType) {
      case 'text':
        return 'contains'
      case 'number':
        return 'equals'
      case 'date':
        return 'equals'
      case 'boolean':
        return 'equals'
    }
  }

  const [operator, setOperator] = useState<string>(
    (currentFilter?.operator as string | undefined) ?? getDefaultOperator()
  )
  const [value, setValue] = useState<string>(
    currentFilter?.value != null ? String(currentFilter.value) : ''
  )
  const [valueTo, setValueTo] = useState<string>(
    currentFilter?.valueTo != null ? String(currentFilter.valueTo) : ''
  )
  const [betweenError, setBetweenError] = useState<string | null>(null)
  const [boolValue, setBoolValue] = useState<string>(
    currentFilter?.value != null ? String(currentFilter.value) : 'true'
  )

  // ── Popover position ──────────────────────
  // Uses position:fixed so top/left are VIEWPORT-relative — do NOT add scrollY/scrollX.
  // Previously: top = rect.bottom + window.scrollY â†’ popover detached from anchor on scroll (Â§8.1).
  // Now: top = rect.bottom (viewport coords) + recalculates on resize and scroll.
  //
  // Lazy initializer: calcPopoverPosition runs synchronously on mount so
  // the very first render already has the correct coordinates.  Without
  // this, the component briefly paints at (0, 0) — the top-left flash the
  // user sees when switching between column filter icons.  The flash
  // happens because mousedown on a new icon fires onClose() (unmounts the
  // old popover) before the click event fires setActiveFilterColumnId
  // (mounts a fresh popover), so every column-switch is a full
  // unmount + remount, not an in-place update.
  const [position, setPosition] = useState<{ top: number; left: number }>(
    () => calcPopoverPosition(anchorRef.current, placement)
  )

  useEffect(() => {
    const calculate = () => {
      setPosition(calcPopoverPosition(anchorRef.current, placement))
    }

    calculate()
    window.addEventListener('resize', calculate)
    window.addEventListener('scroll', calculate, true)
    return () => {
      window.removeEventListener('resize', calculate)
      window.removeEventListener('scroll', calculate, true)
    }
  }, [anchorRef, placement])

  // ── Close on outside click or Escape ──────
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (
        popoverRef.current &&
        !popoverRef.current.contains(e.target as Node) &&
        !anchorRef.current?.contains(e.target as Node)
      ) {
        onClose()
      }
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose()
    }

    document.addEventListener('mousedown', handleClickOutside)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('mousedown', handleClickOutside)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [onClose, anchorRef])

  // ── Operators for current filter type ────
  const operators = (() => {
    switch (filterType) {
      case 'text':
        return TEXT_OPERATORS
      case 'number':
        return NUMBER_OPERATORS
      case 'date':
        return DATE_OPERATORS
      case 'boolean':
        return BOOLEAN_OPERATORS
    }
  })()

  const needsNoInput = NO_INPUT_OPERATORS.includes(operator)
  const needsTwoInputs = TWO_INPUT_OPERATORS.includes(operator)

  // ── Apply filter ──────────────────────────
  const handleApply = useCallback(() => {
    setBetweenError(null)
    const currentModel = grid.kernel.store.read('filtered').filterModel

    // Validate between range (Â§8.4) — from must be <= to
    if (needsTwoInputs && filterType === 'number') {
      const from = Number(value)
      const to = Number(valueTo)
      if (!isNaN(from) && !isNaN(to) && from > to) {
        setBetweenError('"From" must be less than or equal to "To"')
        return
      }
    }
    if (needsTwoInputs && filterType === 'date' && value && valueTo) {
      const from = parseLocalDate(value)
      const to = parseLocalDate(valueTo)
      if (from && to && from > to) {
        setBetweenError('"From" date must be before or equal to "To" date')
        return
      }
    }

    if (needsNoInput) {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: { type: filterType, operator } as ColumnFilter,
        },
      })
    } else if (filterType === 'boolean') {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'boolean',
            operator,
            value: boolValue === 'true',
          } as ColumnFilter,
        },
      })
    } else if (filterType === 'number') {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'number',
            operator,
            value: Number(value),
            ...(needsTwoInputs ? { valueTo: Number(valueTo) } : {}),
          } as ColumnFilter,
        },
      })
    } else if (filterType === 'date') {
      // parseLocalDate â†’ local midnight (Â§8.3 / Â§6.5 timezone fix)
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: {
            type: 'date',
            operator,
            value: parseLocalDate(value),
            ...(needsTwoInputs ? { valueTo: parseLocalDate(valueTo) } : {}),
          } as ColumnFilter,
        },
      })
    } else {
      grid.plugins.filter.setFilterModel({
        columns: {
          ...currentModel.columns,
          [columnId]: { type: 'text', operator, value } as ColumnFilter,
        },
      })
    }

    onClose()
  }, [
    grid,
    columnId,
    filterType,
    operator,
    value,
    valueTo,
    boolValue,
    needsNoInput,
    needsTwoInputs,
    onClose,
  ])

  // ── Clear filter ──────────────────────────
  const handleClear = useCallback(() => {
    const currentModel = grid.kernel.store.read('filtered').filterModel
    const newColumns = { ...currentModel.columns }
    delete newColumns[columnId]
    grid.plugins.filter.setFilterModel({ columns: newColumns })
    onClose()
  }, [grid, columnId, onClose])

  // ── Apply on Enter ────────────────────────
  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleApply()
  }

  // ── Shared input style ────────────────────
  const inputStyle: React.CSSProperties = {
    width: '100%',
    height: 32,
    padding: '0 8px',
    border: '1px solid var(--eg-border)',
    borderRadius: 6,
    fontSize: '0.875rem',
    color: 'var(--eg-text)',
    backgroundColor: 'var(--eg-surface)',
    boxSizing: 'border-box',
    outline: 'none',
    fontFamily: 'inherit',
  }

  const labelStyle: React.CSSProperties = {
    fontSize: '0.75rem',
    fontWeight: 600,
    color: 'var(--eg-muted-text)',
    marginBottom: 4,
    display: 'block',
    textTransform: 'uppercase',
    letterSpacing: '0.05em',
  }

  return (
    <div
      ref={popoverRef}
      style={{
        position: 'fixed',
        top: position.top,
        left: position.left,
        width: 260,
        backgroundColor: 'var(--eg-surface)',
        border: '1px solid var(--eg-border)',
        borderRadius: 8,
        boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
        zIndex: 1000,
        padding: 12,
        display: 'flex',
        flexDirection: 'column',
        gap: 10,
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          paddingBottom: 8,
          borderBottom: '1px solid var(--eg-border)',
        }}
      >
        <span
          style={{
            fontSize: '0.875rem',
            fontWeight: 600,
            color: 'var(--eg-text)',
          }}
        >
          Filter
        </span>
        <button
          onClick={onClose}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            fontSize: '1rem',
            color: 'var(--eg-muted-text)',
            padding: 0,
            lineHeight: 1,
          }}
        >
          ✕
        </button>
      </div>

      {/* Operator selector */}
      <div>
        <label style={labelStyle}>Condition</label>
        <select
          value={operator}
          onChange={(e) => setOperator(e.target.value)}
          style={{ ...inputStyle, height: 34 }}
        >
          {operators.map((op) => (
            <option key={op.value} value={op.value}>
              {op.label}
            </option>
          ))}
        </select>
      </div>

      {/* Value input(s) */}
      {!needsNoInput && (
        <>
          {filterType === 'boolean' ? (
            <div>
              <label style={labelStyle}>Value</label>
              <select
                value={boolValue}
                onChange={(e) => setBoolValue(e.target.value)}
                style={{ ...inputStyle, height: 34 }}
              >
                <option value="true">True</option>
                <option value="false">False</option>
              </select>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              <div>
                <label style={labelStyle}>
                  {needsTwoInputs ? 'From' : 'Value'}
                </label>
                <input
                  type={
                    filterType === 'number'
                      ? 'number'
                      : filterType === 'date'
                        ? 'date'
                        : 'text'
                  }
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  onKeyDown={handleKeyPress}
                  placeholder={needsTwoInputs ? 'From...' : 'Filter value...'}
                  style={inputStyle}
                  autoFocus
                />
              </div>

              {needsTwoInputs && (
                <div>
                  <label style={labelStyle}>To</label>
                  <input
                    type={
                      filterType === 'number'
                        ? 'number'
                        : filterType === 'date'
                          ? 'date'
                          : 'text'
                    }
                    value={valueTo}
                    onChange={(e) => setValueTo(e.target.value)}
                    onKeyDown={handleKeyPress}
                    placeholder="To..."
                    style={inputStyle}
                  />
                </div>
              )}
            </div>
          )}
        </>
      )}

      {/* Actions */}
      <div style={{ display: 'flex', gap: 6, paddingTop: 4 }}>
        <button
          onClick={handleClear}
          style={{
            flex: 1,
            height: 32,
            border: '1px solid var(--eg-border)',
            borderRadius: 6,
            backgroundColor: 'var(--eg-surface)',
            color: 'var(--eg-muted-text)',
            fontSize: '0.875rem',
            cursor: 'pointer',
            fontFamily: 'inherit',
          }}
        >
          Clear
        </button>
        <button
          onClick={handleApply}
          style={{
            flex: 1,
            height: 32,
            border: 'none',
            borderRadius: 6,
            backgroundColor: 'var(--eg-primary)',
            color: 'var(--eg-primary-text)',
            fontSize: '0.875rem',
            fontWeight: 600,
            cursor: 'pointer',
            fontFamily: 'inherit',
          }}
        >
          Apply
        </button>
      </div>
      {betweenError && (
        <div
          role="alert"
          style={{
            marginTop: 6,
            fontSize: '0.75rem',
            color: 'var(--eg-error)',
            padding: '4px 0',
          }}
        >
          {betweenError}
        </div>
      )}
    </div>
  )
}
