// ============================================
// @elitegrid/adapter-react — createGrid
// Factory function — builds and configures
// the engine kernel with all plugins
//
// Call this ONCE outside your component:
//
// ✅ const grid = createGrid({ columns, data })
//    function App() { return <Grid grid={grid} /> }
//
// ❌ function App() {
//      const grid = createGrid({ columns, data }) // wrong — recreates engine every render
//      return <Grid grid={grid} />
//    }
// ============================================

import {
  Kernel,
  DataSourcePlugin,
  RowModelPlugin,
  ColumnModelPlugin,
  FilterPlugin,
  SortPlugin,
  PaginationPlugin,
  ViewportPlugin,
  SelectionPlugin,
  EditPlugin,
  CellValuePlugin,
  FocusPlugin,
  AnnouncementPlugin,
  ExportPlugin,
  GridEvent,
} from '@elitegrid/core'

import type { IDataSource, SortDirection } from '@elitegrid/core'
import type React from 'react'
import { useRef, useEffect } from 'react'

// ─────────────────────────────────────────────
// SECTION 1 — Column Definition
// ─────────────────────────────────────────────
// Grouped config — each concern has its own namespace
// Developer types "sort" and only sees sort-related props
// Adding new props inside a group = never a breaking change

export interface ColumnDef<TData = unknown> {
  // Identity — always top level, always required
  field: Extract<keyof TData, string> | string
  header: string

  // Size group — all width related props together
  size?: {
    width?: number // fixed width in pixels — default: 150
    minWidth?: number // minimum resize width   — default: 50
    maxWidth?: number // maximum resize width
    flex?: number // flexible width weight
    resizable?: boolean // can user resize this column — default: true
  }

  // Display group — how the column looks
  display?: {
    pinned?: 'left' | 'right' | null // default: null
    visible?: boolean // default: true
    cellClass?: string | ((value: unknown, row: TData) => string)
    headerClass?: string
    // Format value for display — e.g. (value) => `$${value}`
    formatter?: (value: unknown, row: TData) => string
    // V2 — separate format for CSV export
    exportFormatter?: (value: unknown, row: TData) => string
  }

  // Sort group — all sort behaviour for this column
  sort?: {
    enabled?: boolean // default: true
    defaultDirection?: SortDirection
    comparator?: (a: unknown, b: unknown) => number // custom sort logic
    nullsFirst?: boolean // default: false
  }

  // Filter group — all filter behaviour for this column
  filter?: {
    enabled?: boolean // default: true
    type?: 'text' | 'number' | 'date' | 'boolean' // default: 'text'
    customFilter?: (value: unknown, row: TData) => boolean
  }

  // Edit group — all editing behaviour for this column
  edit?: {
    enabled?: boolean | ((row: TData) => boolean) // default: false
    type?: 'text' | 'number' | 'dropdown' | 'date' | 'boolean' // default: 'text'
    minDate?: Date
    maxDate?: Date
    options?: string[] // for dropdown type
    min?: number // for number type
    max?: number // for number type
    parser?: (value: string) => unknown
    validator?: (
      value: unknown,
      row: TData
    ) => string | null | Promise<string | null>
  }

  // Value group — custom data access
  // V2 — cell level rendering hooks into this group
  // subscribeToRow will be added here — zero breaking change
  value?: {
    getter?: (row: TData) => unknown
    setter?: (row: TData, value: unknown) => TData
  }
}

// ─────────────────────────────────────────────
// SECTION 2 — Grid Options
// ─────────────────────────────────────────────
// What the developer passes to createGrid()
// Every feature has its own group
// Adding new props inside any group = never a breaking change
// Adding a new group = never a breaking change

export interface GridOptions<TData = unknown> {
  // ── Data — top level, always present ─────────
  columns: ColumnDef<TData>[]
  data?: TData[]
  dataSource?: IDataSource<TData>

  // Which field to use as row ID — default: 'id'
  rowId?: keyof TData | ((row: TData) => string)

  // ── Feature groups ────────────────────────────

  sorting?: {
    enabled?: boolean // default: true
    multiSort?: boolean // default: true
    multiSortKey?: 'shift' | 'ctrl' // default: 'shift'
    defaultDirection?: SortDirection // default: 'asc'
    nullsFirst?: boolean // default: false
  }

  filtering?: {
    enabled?: boolean // default: true
    caseSensitive?: boolean // default: false
    debounceMs?: number // default: 300

    // ── Filter icon ───────────────────────
    iconPosition?: 'left' | 'right' // default: 'right'
    showIconOnHover?: boolean // default: false — always visible
    filterIcon?: React.ReactNode // custom icon — replaces default funnel
    activeFilterIcon?: React.ReactNode // custom icon when filter is active

    // ── Popover ───────────────────────────
    popoverPlacement?: 'bottom' | 'top' | 'auto' // default: 'auto'
  }

  pagination?: {
    enabled?: boolean // default: false
    pageSize?: number // default: 25
    pageSizeOptions?: number[] // default: [10, 25, 50, 100]
    showPageSizeSelector?: boolean // default: true
    showRowCount?: boolean // default: true
    showPageNumbers?: boolean // default: true
  }

  selection?: {
    mode?: 'none' | 'single' | 'multiple' // default: 'none'
    selectAllScope?: 'page' | 'all' // default: 'page'
    showCheckboxes?: boolean // default: true when mode !== 'none'
    selectOnRowClick?: boolean // default: true
    checkboxOnly?: boolean // default: false
  }

  editing?: {
    enabled?: boolean // default: false
    trigger?: 'click' | 'doubleClick' // default: 'doubleClick'
    confirmOnEnter?: boolean // default: true
    cancelOnEscape?: boolean // default: true
    moveOnTab?: boolean // default: true
  }

  appearance?: {
    theme?: 'light' | 'dark' | 'auto' // default: 'light'
    density?: 'compact' | 'normal' | 'comfortable' // default: 'normal'
    rowHeight?: number // default: 40
    headerHeight?: number // default: 44
    rowStriping?: boolean // default: true
    showColumnBorders?: boolean // default: false
    showHoverHighlight?: boolean // default: true
    className?: string
    style?: React.CSSProperties

    // ── Empty state ───────────────────────
    // Simple props — for most developers
    emptyState?: {
      title?: string // default: 'No data'
      description?: string // default: 'No rows to display'
      icon?: React.ReactNode // custom icon or image
    }
    // Shown when filter returns no results
    filteredEmptyState?: {
      title?: string // default: 'No matching results'
      description?: string // default: 'Try adjusting your filters'
      icon?: React.ReactNode
    }
    // Full custom component — overrides simple props above
    emptyStateComponent?: React.ComponentType

    // ── Loading state ─────────────────────
    // Simple props — for most developers
    loadingState?: {
      message?: string // default: 'Loading...'
    }
    // Full custom component — overrides simple props above
    loadingComponent?: React.ComponentType

    // ── Error state ───────────────────────
    // Full custom component
    errorComponent?: React.ComponentType<{ error: Error }>
  }

  scroll?: {
    bufferSize?: number // extra rows outside visible area — default: 10
  }

  // ── Export ────────────────────────────────
  export?: {
    // Default filename without extension — default: 'export'
    filename?: string
    // Default scope — default: 'filtered'
    scope?: 'all' | 'filtered' | 'page' | 'selected'
  }

  accessibility?: {
    gridLabel?: string // aria-label on grid container
    announceFocus?: boolean // default: true
    announceSort?: boolean // default: true
    announceFilter?: boolean // default: true
    announceSelection?: boolean // default: true
    announceEdit?: boolean // default: true
    announcePage?: boolean // default: true
  }

  // ── Events — all callbacks in one place ───────
  // Grouped so they never pollute top-level autocomplete
  // Developer types "events={{" and sees only callbacks
  // Adding new events = never a breaking change
  events?: {
    // Lifecycle
    onReady?: (api: GridAPI<TData>) => void

    // Row interactions
    onRowClick?: (row: TData, event: MouseEvent) => void
    onRowDoubleClick?: (row: TData, event: MouseEvent) => void

    // Edit lifecycle
    onEditStart?: (rowId: string, field: string) => void
    onEditCommit?: (rowId: string, field: string, value: unknown) => void
    onEditCancel?: (rowId: string, field: string) => void

    // Feature state changes
    onSortChange?: (
      model: Array<{ columnId: string; direction: SortDirection }>
    ) => void
    onFilterChange?: (model: Record<string, unknown>) => void
    onSelectionChange?: (rows: TData[]) => void
    onPageChange?: (page: number, pageSize: number) => void

    // Column state changes
    onColumnResize?: (columnId: string, width: number) => void
    onColumnReorder?: (columnIds: string[]) => void
    onColumnVisibilityChange?: (columnId: string, visible: boolean) => void

    // Data mutations
    onRowAdd?: (row: TData) => void
    onRowUpdate?: (id: string, changes: Partial<TData>) => void
    onRowDelete?: (id: string) => void

    // Scroll
    onScrollChange?: (scrollTop: number, scrollLeft: number) => void
  }
}

// ─────────────────────────────────────────────
// SECTION 3 — Supporting Types
// ─────────────────────────────────────────────

// Column state — for save and restore via getColumnState / applyColumnState
export interface ColumnState {
  columnId: string
  width: number
  visible: boolean
  pinned: 'left' | 'right' | null
  index: number
}

// Pagination state — returned by getPaginationState()
export interface PaginationState {
  currentPage: number
  pageSize: number
  totalRows: number
  totalPages: number
  startRow: number
  endRow: number
  hasNextPage: boolean
  hasPreviousPage: boolean
}

// ─────────────────────────────────────────────
// SECTION 4 — Grid API
// ─────────────────────────────────────────────
// What the developer gets from onReady and useGridAPI()
// This is the ONLY surface developers interact with
// They never touch plugins or kernel directly
// Adding new methods = never a breaking change

export interface GridAPI<TData = unknown> {
  // ── Data ──────────────────────────────────
  setData(rows: TData[]): void
  getData(): TData[]
  // Returns rows in current display order (after filter + sort + pagination)
  getDisplayedRows(): TData[]
  refreshData(): Promise<void>
  addRow(row: TData, index?: number): void
  updateRow(id: string, changes: Partial<TData>): void
  deleteRow(id: string): void
  deleteRows(ids: string[]): void

  // ── Columns ───────────────────────────────
  setColumnVisible(id: string, visible: boolean): void
  setColumnWidth(id: string, width: number): void
  setColumnPinned(id: string, position: 'left' | 'right' | null): void
  moveColumn(id: string, toIndex: number): void
  getAllColumns(): ColumnDef<TData>[]
  getVisibleColumns(): ColumnDef<TData>[]
  getColumnState(): ColumnState[]
  applyColumnState(state: ColumnState[]): void

  // ── Sort ──────────────────────────────────
  setSortModel(
    model: Array<{ columnId: string; direction: SortDirection }>
  ): void
  getSortModel(): Array<{ columnId: string; direction: SortDirection }>
  clearSort(): void

  // ── Filter ────────────────────────────────
  setFilterModel(model: Record<string, unknown>): void
  getFilterModel(): Record<string, unknown>
  setColumnFilter(columnId: string, filter: unknown): void
  clearColumnFilter(columnId: string): void
  clearFilters(): void

  // ── Selection ─────────────────────────────
  selectRow(id: string): void
  deselectRow(id: string): void
  toggleRow(id: string): void
  selectAll(): void
  deselectAll(): void
  isRowSelected(id: string): boolean
  getSelectedRows(): TData[]
  getSelectedIds(): Set<string>

  // ── Editing ───────────────────────────────
  startEditing(rowId: string, columnId: string): void
  stopEditing(save?: boolean): void
  isEditing(): boolean
  getEditingCell(): {
    rowId: string
    columnId: string
    rowIndex: number
    columnIndex: number
  } | null

  // ── Pagination ────────────────────────────
  setPage(page: number): void
  setPageSize(size: number): void
  nextPage(): void
  previousPage(): void
  firstPage(): void
  lastPage(): void
  getPaginationState(): PaginationState

  // ── Scroll ────────────────────────────────
  scrollToRow(rowId: string): void
  scrollToColumn(columnId: string): void
  scrollToCell(rowId: string, columnId: string): void

  // ── Export ────────────────────────────────
  exportCSV(options?: {
    filename?: string
    scope?: 'all' | 'filtered' | 'page' | 'selected'
    columns?: string[]
    includeHeader?: boolean
    delimiter?: string
  }): void

  // ── Lifecycle ─────────────────────────────
  destroy(): void
}

// ─────────────────────────────────────────────
// SECTION 4 — Grid Instance
// ─────────────────────────────────────────────
// Returned by createGrid()
// Passed into <Grid grid={grid} />
// kernel and plugins are internal — developer never touches them
// Developer only interacts through GridAPI

export interface GridInstance<TData = unknown> {
  readonly kernel: Kernel
  readonly options: GridOptions<TData>
  readonly plugins: {
    dataSource: DataSourcePlugin<TData>
    rowModel: RowModelPlugin
    columnModel: ColumnModelPlugin
    filter: FilterPlugin
    sort: SortPlugin
    pagination: PaginationPlugin
    viewport: ViewportPlugin
    selection: SelectionPlugin
    edit: EditPlugin
    cellValue: CellValuePlugin
    focus: FocusPlugin
    announcement: AnnouncementPlugin
    export: ExportPlugin
  }
  // Update event callbacks without recreating the grid.
  // Use this in React components when event handlers capture state —
  // otherwise handlers registered at createGrid() time are stale closures.
  updateEvents(events: GridOptions<TData>['events']): void
}

// ─────────────────────────────────────────────
// SECTION 5 — normalizeColumns (internal)
// ─────────────────────────────────────────────
// Converts grouped ColumnDef → flat ColumnInput the engine expects
// Engine stays clean — it never knows about ColumnDef groups
// V2 additions to ColumnDef groups get unpacked here

function normalizeColumns<TData>(
  columns: ColumnDef<TData>[],
  options: GridOptions<TData>
) {
  return columns.map((col) => ({
    id: col.field as string,
    field: col.field as string,
    header: col.header,

    // Size group → flat props
    width: col.size?.width,
    minWidth: col.size?.minWidth,
    maxWidth: col.size?.maxWidth,
    flex: col.size?.flex,
    resizable: col.size?.resizable ?? true,

    // Display group → flat props
    pinned: col.display?.pinned ?? null,
    visible: col.display?.visible ?? true,

    // Feature flags
    // Column-level setting takes priority over grid-level setting
    sortable: col.sort?.enabled ?? options.sorting?.enabled ?? true,
    filterable: col.filter?.enabled ?? options.filtering?.enabled ?? true,

    // Pass comparator so SortPlugin can call it during sort
    comparator: col.sort?.comparator,

    // editable: if enabled is a function, mark true so the engine allows
    // EDIT_START_REQUESTED through. The actual per-row check happens in
    // GridCell at render time using the function and current row data (§2.7).
    editable: col.edit?.enabled
      ? typeof col.edit.enabled === 'function'
        ? true // always allow at engine level; GridCell gates per row
        : col.edit.enabled
      : false,
  }))
}

// ─────────────────────────────────────────────
// SECTION 6 — createGrid
// ─────────────────────────────────────────────

export function createGrid<TData = unknown>(
  options: GridOptions<TData>
): GridInstance<TData> {
  // Step 1 — Create kernel
  const kernel = new Kernel()

  // Step 2 — Create plugins
  const dataSourcePlugin = new DataSourcePlugin<TData>()
  const rowModelPlugin = new RowModelPlugin()
  const columnModelPlugin = new ColumnModelPlugin()
  const filterPlugin = new FilterPlugin()
  const sortPlugin = new SortPlugin()
  const paginationPlugin = new PaginationPlugin()
  const viewportPlugin = new ViewportPlugin()
  const selectionPlugin = new SelectionPlugin()
  const editPlugin = new EditPlugin()
  const cellValuePlugin = new CellValuePlugin()
  const focusPlugin = new FocusPlugin()
  const exportPlugin = new ExportPlugin()
  const announcementPlugin = new AnnouncementPlugin({
    announce: {
      focus: options.accessibility?.announceFocus ?? true,
      sort: options.accessibility?.announceSort ?? true,
      filter: options.accessibility?.announceFilter ?? true,
      page: options.accessibility?.announcePage ?? true,
      selection: options.accessibility?.announceSelection ?? true,
      edit: options.accessibility?.announceEdit ?? true,
    },
  })

  // Step 3 — Configure plugins
  // Grouped options are unpacked here
  // Each plugin gets only what it needs
  // Engine stays completely clean of grouped config

  dataSourcePlugin.configure({
    data: options.data,
    dataSource: options.dataSource,
    pageSize: options.pagination?.pageSize,
    rowId: options.rowId as string | ((row: unknown) => string) | undefined,
  })

  rowModelPlugin.configure({
    rowId: options.rowId as string | ((row: unknown) => string) | undefined,
  })

  columnModelPlugin.configure({
    columns: normalizeColumns(options.columns, options),
    defaultWidth: 150,
    defaultMinWidth: 50,
    defaultResizable: true,
    defaultSortable: options.sorting?.enabled ?? true,
    defaultFilterable: options.filtering?.enabled ?? true,
  })

  filterPlugin.configure({
    caseSensitive: options.filtering?.caseSensitive ?? false,
    debounceMs: options.filtering?.debounceMs ?? 300,
  })

  sortPlugin.configure({
    multiSort: options.sorting?.multiSort ?? true,
    multiSortKey: options.sorting?.multiSortKey ?? 'shift',
    defaultDirection: options.sorting?.defaultDirection ?? 'asc',
    nullsFirst: options.sorting?.nullsFirst ?? false,
  })

  paginationPlugin.configure({
    enabled: options.pagination?.enabled ?? false,
    pageSize: options.pagination?.pageSize ?? 25,
    pageSizeOptions: options.pagination?.pageSizeOptions ?? [10, 25, 50, 100],
  })

  // Viewport reads from both appearance and scroll groups
  // bufferSize default is 10 — extra rows rendered above and below
  // the visible viewport. Higher values reduce blank-flash risk on
  // fast scroll at the cost of slightly more DOM. 10 is a reasonable
  // default; users with very heavy cells can lower it.
  editPlugin.configure({
    // Global validator — per-column validators override this
    validator: undefined,
  })

  selectionPlugin.configure({
    mode: options.selection?.mode ?? 'none',
    selectAllScope: options.selection?.selectAllScope ?? 'page',
    deselectOnClick: true,
  })

  viewportPlugin.configure({
    rowHeight: options.appearance?.rowHeight ?? 40,
    headerHeight: options.appearance?.headerHeight ?? 44,
    bufferSize: options.scroll?.bufferSize ?? 10,
  })

  // Step 4 — Register in pipeline order
  // Kernel calls init() in registration order
  // DataSource → RowModel → ColumnModel → Filter → Sort → Pagination → Viewport
  kernel.register(dataSourcePlugin)
  kernel.register(rowModelPlugin)
  kernel.register(columnModelPlugin)
  kernel.register(filterPlugin)
  kernel.register(sortPlugin)
  kernel.register(paginationPlugin)
  kernel.register(viewportPlugin)
  kernel.register(selectionPlugin)
  kernel.register(focusPlugin)
  kernel.register(announcementPlugin)
  kernel.register(cellValuePlugin)
  kernel.register(exportPlugin)
  kernel.register(editPlugin)

  // Step 5 — Boot the engine
  // After this — data flows through the full pipeline
  kernel.init()

  // Derive the row ID field once — used in all event wiring below.
  // options.rowId can be a string key or a function.
  // When it's a function we can't use it as a field name for plain lookup —
  // in that case we fall back to 'id' for store reads (same as engine default).
  const rowIdField =
    typeof options.rowId === 'string' ? (options.rowId as string) : 'id'

  // Wire FOCUS_CHANGED → open editor on new cell when Tab was used mid-edit.
  // EditPlugin commits on Tab, then GridCellEditor emits FOCUS_MOVE_REQUESTED.
  // FocusPlugin handles the move and emits FOCUS_CHANGED with the new cell.
  //
  // Fix for §2.2 race condition:
  // The original boolean flag `pendingEditOnFocus` could be set by a first Tab,
  // then a second Tab arrives before FOCUS_CHANGED fires — the flag stays true
  // but the focus has moved to a different cell than intended. We now store the
  // source cell identity so we can verify the commit came from the cell we expect.
  // Using a counter instead of a boolean also handles rapid Tab correctly —
  // each Tab increments the counter, each FOCUS_CHANGED decrements it.
  // If the counter is still positive when FOCUS_CHANGED fires, open the editor.
  let pendingEditCount = 0

  kernel.eventBus.on(GridEvent.FOCUS_MOVE_REQUESTED, (payload: unknown) => {
    if ((payload as { editableOnly?: boolean }).editableOnly) {
      pendingEditCount++
    }
  })

  kernel.eventBus.on(GridEvent.FOCUS_CHANGED, (payload: unknown) => {
    if (pendingEditCount <= 0) return
    pendingEditCount--

    const { cell } = payload as { cell?: unknown }
    if (!cell) return

    // No setTimeout — emit synchronously so isEditing becomes true before
    // any next keydown event can fire. The setTimeout(0) in the original
    // code was the root cause of the race — it allowed a second Enter/Tab
    // to arrive while pendingEditCount was still > 0 (§3.2 related).
    kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
  })

  // Register per-column value config from ColumnDef into CellValuePlugin
  // This runs after kernel.init() so the store has column definitions ready
  options.columns.forEach((col) => {
    const hasConfig =
      col.value?.getter ||
      col.value?.setter ||
      col.display?.formatter ||
      col.display?.exportFormatter ||
      col.edit?.parser

    if (!hasConfig) return

    cellValuePlugin.registerColumnConfig(col.field as string, {
      getter: col.value?.getter
        ? (row) => col.value!.getter!(row as TData)
        : undefined,
      setter: col.value?.setter
        ? (row, value) => col.value!.setter!(row as TData, value)
        : undefined,
      formatter: col.display?.formatter
        ? (value, row) => col.display!.formatter!(value, row as TData)
        : undefined,
      exportFormatter: col.display?.exportFormatter
        ? (value, row) => col.display!.exportFormatter!(value, row as TData)
        : undefined,
      parser: col.edit?.parser ? (raw) => col.edit!.parser!(raw) : undefined,
    })
  })

  // Register column editors for editable columns
  options.columns.forEach((col) => {
    if (!col.edit?.enabled) return
    const colDef = kernel.store
      .read('columns')
      .definitions.find((d) => d.field === col.field)
    if (!colDef) return

    // Map adapter type to plugin EditorType
    const typeMap: Record<string, string> = {
      text: 'text',
      number: 'number',
      dropdown: 'select',
      date: 'date',
      boolean: 'boolean',
    }
    const editorType = typeMap[col.edit.type ?? 'text'] ?? 'text'

    editPlugin.registerColumnEditor(colDef.id, {
      type: editorType as 'text' | 'number' | 'select' | 'date' | 'boolean',
      options: col.edit.options?.map((o) => ({ label: String(o), value: o })),
      min: col.edit.min,
      max: col.edit.max,
      minDate: col.edit.minDate,
      maxDate: col.edit.maxDate,
      validator: async (value, cell) => {
        // Get the actual row from the store for cross-field validation
        const { rows } = kernel.store.read('sorted')
        const row =
          (rows as unknown[]).find(
            (r) => String((r as Record<string, unknown>)[rowIdField]) === (cell as { rowId: string }).rowId
          ) ??
          {}

        // ── Built-in number validation ────────────────────────────────
        // Must run here because registering a custom validator bypasses
        // EditPlugin's runBuiltInValidation entirely.
        if (
          col.edit?.type === 'number' &&
          value !== null &&
          value !== undefined &&
          value !== ''
        ) {
          if (typeof value === 'number' && !Number.isFinite(value)) {
            return { valid: false, error: 'Must be a valid number' }
          }
          const num = Number(value)
          if (isNaN(num)) {
            return { valid: false, error: 'Must be a valid number' }
          }
          if (col.edit.min !== undefined && num < col.edit.min) {
            return { valid: false, error: `Must be at least ${col.edit.min}` }
          }
          if (col.edit.max !== undefined && num > col.edit.max) {
            return { valid: false, error: `Must be at most ${col.edit.max}` }
          }
        }

        // ── Built-in date range validation ────────────────────────────
        if (col.edit?.type === 'date' && value) {
          const date = value instanceof Date ? value : new Date(value as string)
          if (isNaN(date.getTime()))
            return { valid: false, error: 'Invalid date' }
          if (col.edit.minDate && date < col.edit.minDate) {
            return {
              valid: false,
              error: `Date must be after ${col.edit.minDate.toLocaleDateString()}`,
            }
          }
          if (col.edit.maxDate && date > col.edit.maxDate) {
            return {
              valid: false,
              error: `Date must be before ${col.edit.maxDate.toLocaleDateString()}`,
            }
          }
        }

        // ── Developer-provided validator ──────────────────────────────
        // Runs after built-ins so built-in errors always show first
        if (col.edit?.validator) {
          const err = await col.edit.validator(value, row as TData)
          if (err) return { valid: false, error: err }
        }

        return { valid: true }
      },
    })
  })

  // Wire onEditCommit / onEditCancel / onEditStart callbacks
  kernel.eventBus.on(GridEvent.SORT_COMPLETED, (payload: unknown) => {
    const p = payload as { sortModel?: Array<{ columnId: string; direction: SortDirection }> }
    options.events?.onSortChange?.(p.sortModel ?? [])
  })

  kernel.eventBus.on(GridEvent.FILTER_COMPLETED, (payload: unknown) => {
    const p = payload as { filterModel?: Record<string, unknown> }
    options.events?.onFilterChange?.(p.filterModel ?? {})
  })

  kernel.eventBus.on(GridEvent.EDIT_STARTED, (payload: unknown) => {
    const p = payload as { cell: { rowId: string; columnId: string } }
    options.events?.onEditStart?.(p.cell.rowId, p.cell.columnId)
  })
  kernel.eventBus.on(GridEvent.EDIT_COMMITTED, (payload: unknown) => {
    const p = payload as { cell: { rowId: string; columnId: string }; newValue: unknown }
    options.events?.onEditCommit?.(
      p.cell.rowId,
      p.cell.columnId,
      p.newValue
    )
  })
  kernel.eventBus.on(GridEvent.EDIT_CANCELLED, (payload: unknown) => {
    const p = payload as { cell: { rowId: string; columnId: string } }
    options.events?.onEditCancel?.(p.cell.rowId, p.cell.columnId)
  })

  // Wire ROW_UPDATED — update in-memory row data so grid re-renders
  kernel.eventBus.on(GridEvent.ROW_UPDATED, (payload: unknown) => {
    const { rowId, columnId, newValue } = payload as { rowId: string; columnId: string; newValue: unknown; changes?: unknown }
    const { definitions } = kernel.store.read('columns')
    const col = definitions.find((d: { id: string; field: string }) => d.id === columnId)
    if (!col) return

    // Update the raw rows in store so pipeline re-runs
    const { rows } = kernel.store.read('raw')
    const updated = (rows as unknown[]).map((r: unknown) => {
      const row = r as Record<string, unknown>
      if (String(row[rowIdField]) !== rowId) return r
      return { ...row, [col.field]: newValue }
    })
    kernel.store.write('raw', { rows: updated })
    // Emit DATA_CHANGED to re-run the full pipeline (filter → sort → paginate)
    // Preserves existing filter model and selection — unlike DATA_SET
    kernel.eventBus.emit(GridEvent.DATA_CHANGED, {})
  })

  // Wire onSelectionChange developer callback
  // GridEvent.SELECTION_CHANGED is the correct event — not a magic string
  if (options.events?.onSelectionChange) {
    kernel.eventBus.on(GridEvent.SELECTION_CHANGED, () => {
      const ids = new Set(selectionPlugin.getSelectedIds())
      // sorted rows are plain TData objects — no ._id or ._data unwrapping
      const { rows } = kernel.store.read('sorted')
      const selected = (rows as TData[]).filter((r: TData) =>
        ids.has(String((r as Record<string, unknown>)[rowIdField]))
      )
      options.events!.onSelectionChange!(selected)
    })
  }

  // ── Missing event wirings ──────────────────────────────────────────
  // These events are documented in GridOptions.events but were not
  // previously subscribed to. The grid functioned correctly internally
  // but developer callbacks never fired.

  // onPageChange — fires on page navigation AND page size change
  kernel.eventBus.on(GridEvent.PAGE_CHANGED, (payload: unknown) => {
    const p = payload as { page: number; pageSize: number }
    options.events?.onPageChange?.(p.page, p.pageSize)
  })
  kernel.eventBus.on(GridEvent.PAGE_SIZE_CHANGED, (payload: unknown) => {
    const p = payload as { pageSize: number }
    const { currentPage } = kernel.store.read('paginated')
    options.events?.onPageChange?.(currentPage, p.pageSize)
  })

  // onColumnResize — fires when user drags a column edge
  kernel.eventBus.on(GridEvent.COLUMN_RESIZED, (payload: unknown) => {
    const p = payload as { columnId: string; width: number }
    options.events?.onColumnResize?.(p.columnId, p.width)
  })

  // onColumnReorder — fires when user drags a column to a new position
  kernel.eventBus.on(GridEvent.COLUMN_REORDERED, (payload: unknown) => {
    const p = payload as { columnIds: string[] }
    options.events?.onColumnReorder?.(p.columnIds)
  })

  // onColumnVisibilityChange — fires when a column is shown or hidden
  kernel.eventBus.on(GridEvent.COLUMN_VISIBILITY_CHANGED, (payload: unknown) => {
    const p = payload as { columnId: string; visible: boolean }
    options.events?.onColumnVisibilityChange?.(
      p.columnId,
      p.visible
    )
  })

  // onScrollChange — fires on every scroll position change
  // Note: this fires frequently — developers should debounce if needed
  kernel.eventBus.on(GridEvent.SCROLL_CHANGED, (payload: unknown) => {
    const p = payload as { scrollTop: number; scrollLeft: number }
    options.events?.onScrollChange?.(p.scrollTop, p.scrollLeft)
  })

  // onRowAdd — fires when a row is added via addRow()
  kernel.eventBus.on(GridEvent.ROW_ADDED, (payload: unknown) => {
    const p = payload as { row: TData }
    options.events?.onRowAdd?.(p.row)
  })

  // onRowDelete — fires when a row is deleted via deleteRow() or deleteRows()
  kernel.eventBus.on(GridEvent.ROW_DELETED, (payload: unknown) => {
    const p = payload as { rowId: string }
    options.events?.onRowDelete?.(p.rowId)
  })

  // onRowUpdate — fires when a row is updated via updateRow() or edit commit
  // ROW_UPDATED fires for both programmatic updates and cell edit commits.
  // We re-use the existing ROW_UPDATED subscriber above for the store write;
  // call the developer callback separately here so both always fire.
  kernel.eventBus.on(GridEvent.ROW_UPDATED, (payload: unknown) => {
    // Only call onRowUpdate for programmatic updateRow() calls, not for
    // internal edit commits (which have columnId + newValue, not changes).
    // Both share the same event — distinguish by presence of `changes` field.
    const p = payload as { rowId: string; changes?: Partial<TData> }
    if (p.changes !== undefined) {
      options.events?.onRowUpdate?.(p.rowId, p.changes)
    }
  })

  // Step 6 — Return instance
  return {
    kernel,
    options,
    plugins: {
      dataSource: dataSourcePlugin,
      rowModel: rowModelPlugin,
      columnModel: columnModelPlugin,
      filter: filterPlugin,
      sort: sortPlugin,
      pagination: paginationPlugin,
      viewport: viewportPlugin,
      selection: selectionPlugin,
      edit: editPlugin,
      cellValue: cellValuePlugin,
      focus: focusPlugin,
      announcement: announcementPlugin,
      export: exportPlugin,
    },
    // Mutates the options.events object in place so all existing event
    // subscribers (which close over `options`) immediately see the new handlers.
    // This avoids stale closure bugs when event handlers are defined inline
    // in a React component and capture state (§2.6).
    updateEvents(events: GridOptions<TData>['events']) {
      options.events = { ...options.events, ...events }
    },
  }
}

// ─────────────────────────────────────────────
// SECTION 7 — useCreateGrid
// ─────────────────────────────────────────────
// Safe hook wrapper for createGrid inside React components.
//
// ✅ const grid = useCreateGrid({ columns, data })
//    function App() { return <Grid grid={grid} /> }
//
// The engine is created once on first render and reused for
// the lifetime of the component — identical to calling
// createGrid outside the component, but safe inside one.
//
// Options are intentionally NOT reactive — changing columns
// or data after mount requires calling grid.api.setData() or
// grid.api.setColumnVisible() imperatively. This matches the
// engine's design: the adapter never re-creates the engine.
//
// If you need the grid to live beyond the component (shared
// between routes, initialized before mount) use createGrid
// directly outside the component instead.

export function useCreateGrid<TData = unknown>(
  options: GridOptions<TData>
): GridInstance<TData> {
  const ref = useRef<GridInstance<TData> | null>(null)
  const destroyedRef = useRef(false)

  // Create on first render, or re-create after StrictMode destroys it
  if (ref.current === null || destroyedRef.current) {
    ref.current = createGrid(options)
    destroyedRef.current = false
  }

  // Destroy the kernel when the component unmounts.
  // This is the fix for §1.1 — without this, every route change
  // leaks the entire kernel, all plugins, and all event subscribers.
  //
  // StrictMode mounts → destroys → mounts again. The second mount
  // sees destroyedRef.current === true and re-creates the kernel above.
  //
  // If you call createGrid() outside a component (the documented
  // advanced pattern), YOU own the lifetime — call grid.kernel.destroy()
  // yourself. useCreateGrid handles it automatically.
  useEffect(() => {
    destroyedRef.current = false
    return () => {
      ref.current?.kernel.destroy()
      destroyedRef.current = true
      ref.current = null
    }
  }, [])

  return ref.current!
}
