// ============================================
// @elitegrid/adapter-react — CellEditor.tsx
// Renders the appropriate editor inside an editing cell
// Handles: text, number, select, date, boolean
//
// Fixes applied:
//   Â§6.1 — boolean editor hook no longer conditional
//   Â§6.2 — committedRef prevents double-commit on blur after Tab/Enter
//   Â§6.5 — date parsing uses local midnight, not UTC
//   Â§6.6 — validation tooltip uses portal to escape overflow:hidden
// ============================================

import React, { useEffect, useRef, useState } from 'react'
import ReactDOM from 'react-dom'
import { GridEvent } from '@elitegrid/core'
import type { CellPosition } from '@elitegrid/core'
import type { ColumnEditorConfig } from '@elitegrid/core'
import type { EditingNamespace } from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import { parseLocalDate, formatDateInput } from '../utils/date'

interface CellEditorProps {
  cell: CellPosition
  editorConfig: ColumnEditorConfig | null
  colWidth: number
  rowHeight: number
}

export function CellEditor({
  cell,
  editorConfig,
  colWidth: _colWidth,
  rowHeight,
}: CellEditorProps) {
  const grid = useGridContext()
  const inputRef = useRef<HTMLInputElement | HTMLSelectElement>(null)

  const [editState, setEditState] = useState<EditingNamespace>(
    () => grid.kernel.store.read('editing') as EditingNamespace
  )

  useEffect(() => {
    setEditState(grid.kernel.store.read('editing') as EditingNamespace)
    const unsubscribe = grid.kernel.store.subscribe('editing', () => {
      setEditState(grid.kernel.store.read('editing') as EditingNamespace)
    })
    return unsubscribe
  }, [grid])

  const currentValue = editState.currentValue
  const isValid = editState.isValid
  const validationError = editState.validationError
  const editorType = editorConfig?.type ?? 'text'

  // ── Double-commit guard (Â§6.2) ─────────────────────────────────────
  // Tab/Enter call emitCommit(), then blur fires and calls emitCommit()
  // again. committedRef ensures only the first call emits the event.
  const committedRef = useRef(false)

  const emitChange = (value: unknown) => {
    grid.kernel.eventBus.emit(GridEvent.EDIT_VALUE_CHANGED, { cell, value })
  }

  const emitCommit = () => {
    if (committedRef.current) return
    committedRef.current = true
    grid.kernel.eventBus.emit(GridEvent.EDIT_COMMIT_REQUESTED, { cell })
  }

  const emitCancel = () => {
    if (committedRef.current) return
    committedRef.current = true
    grid.kernel.eventBus.emit(GridEvent.EDIT_CANCEL_REQUESTED, { cell })
  }

  // ── Boolean toggle effect (Â§6.1 hook fix) ─────────────────────────
  // Previously useEffect was inside if(editorType === 'boolean') block
  // — a Rules of Hooks violation. Now unconditional, gated internally.
  const boolTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  useEffect(() => {
    if (editorType !== 'boolean') return
    emitChange(!currentValue)
    boolTimerRef.current = setTimeout(() => emitCommit(), 0)
    return () => {
      if (boolTimerRef.current) clearTimeout(boolTimerRef.current)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []) // run once on mount — boolean toggles immediately

  // Auto-focus on mount
  useEffect(() => {
    if (editorType === 'boolean') return
    const el = inputRef.current
    if (!el) return
    el.focus()
    if (el instanceof HTMLInputElement) el.select()
  }, [editorType])

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault()
      emitCommit()
    } else if (e.key === 'Escape') {
      e.preventDefault()
      emitCancel()
    } else if (e.key === 'Tab') {
      e.preventDefault()
      emitCommit()
      grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
        direction: e.shiftKey ? 'prev' : 'next',
        editableOnly: true,
      })
    }
  }

  const baseStyle: React.CSSProperties = {
    width: '100%',
    height: rowHeight - 4,
    boxSizing: 'border-box',
    border: isValid
      ? '2px solid var(--eg-primary)'
      : '2px solid var(--eg-error)',
    borderRadius: 4,
    padding: '0 8px',
    fontSize: '0.875rem',
    color: 'var(--eg-cell-text)',
    backgroundColor: 'var(--eg-row-bg)',
    outline: 'none',
  }

  if (editorType === 'boolean') return null

  if (editorType === 'select') {
    const selectOptions = Array.isArray(editorConfig?.options)
      ? editorConfig.options
      : []
    return (
      <div style={{ position: 'relative', width: '100%' }}>
        <select
          ref={inputRef as React.RefObject<HTMLSelectElement>}
          value={String(currentValue ?? '')}
          onChange={(e) => emitChange(e.target.value)}
          onKeyDown={handleKeyDown}
          onBlur={emitCommit}
          style={{ ...baseStyle, cursor: 'pointer' }}
        >
          {selectOptions.map((opt) => (
            <option key={String(opt.value)} value={String(opt.value)}>
              {opt.label}
            </option>
          ))}
        </select>
        {!isValid && validationError && (
          <ValidationTooltip message={validationError} inputRef={inputRef} />
        )}
      </div>
    )
  }

  if (editorType === 'date') {
    const minVal = editorConfig?.minDate
      ? formatDateInput(editorConfig.minDate)
      : undefined
    const maxVal = editorConfig?.maxDate
      ? formatDateInput(editorConfig.maxDate)
      : undefined
    return (
      <div style={{ position: 'relative', width: '100%' }}>
        <input
          ref={inputRef as React.RefObject<HTMLInputElement>}
          type="date"
          value={formatDateInput(currentValue)}
          min={minVal}
          max={maxVal}
          onChange={(e) =>
            emitChange(e.target.value ? parseLocalDate(e.target.value) : null)
          }
          onKeyDown={handleKeyDown}
          onBlur={emitCommit}
          style={baseStyle}
        />
        {!isValid && validationError && (
          <ValidationTooltip message={validationError} inputRef={inputRef} />
        )}
      </div>
    )
  }

  if (editorType === 'number') {
    return (
      <div style={{ position: 'relative', width: '100%' }}>
        <input
          ref={inputRef as React.RefObject<HTMLInputElement>}
          type="number"
          value={
            currentValue === null || currentValue === undefined
              ? ''
              : String(currentValue)
          }
          min={editorConfig?.min}
          max={editorConfig?.max}
          step={editorConfig?.step ?? 1}
          onChange={(e) =>
            emitChange(e.target.value === '' ? null : Number(e.target.value))
          }
          onKeyDown={handleKeyDown}
          onBlur={emitCommit}
          style={baseStyle}
        />
        {!isValid && validationError && (
          <ValidationTooltip message={validationError} inputRef={inputRef} />
        )}
      </div>
    )
  }

  return (
    <div style={{ position: 'relative', width: '100%' }}>
      <input
        ref={inputRef as React.RefObject<HTMLInputElement>}
        type="text"
        value={
          currentValue === null || currentValue === undefined
            ? ''
            : String(currentValue)
        }
        onChange={(e) => emitChange(e.target.value)}
        onKeyDown={handleKeyDown}
        onBlur={emitCommit}
        style={baseStyle}
      />
      {!isValid && validationError && (
        <ValidationTooltip message={validationError} inputRef={inputRef} />
      )}
    </div>
  )
}

// ── Validation tooltip portal (Â§6.6) ──────────────────────────────────
// Previously: position:absolute top:100% — clipped by overflow:hidden on GridCell.
// Now: portal into document.body with fixed positioning from getBoundingClientRect.
// Recalculates on resize and scroll so it stays attached to the input.

interface ValidationTooltipProps {
  message: string
  inputRef: React.RefObject<HTMLInputElement | HTMLSelectElement>
}

function ValidationTooltip({ message, inputRef }: ValidationTooltipProps) {
  const [pos, setPos] = useState<{ top: number; left: number } | null>(null)

  useEffect(() => {
    const el = inputRef.current
    if (!el) return
    const update = () => {
      const rect = el.getBoundingClientRect()
      setPos({ top: rect.bottom + 2, left: rect.left })
    }
    update()
    window.addEventListener('resize', update)
    window.addEventListener('scroll', update, true)
    return () => {
      window.removeEventListener('resize', update)
      window.removeEventListener('scroll', update, true)
    }
  }, [inputRef])

  if (!pos) return null

  return ReactDOM.createPortal(
    <div
      role="alert"
      style={{
        position: 'fixed',
        top: pos.top,
        left: pos.left,
        zIndex: 9999,
        backgroundColor: 'var(--eg-error)',
        color: 'var(--eg-error-text)',
        fontSize: '0.75rem',
        padding: '3px 8px',
        borderRadius: 4,
        whiteSpace: 'nowrap',
        boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
        pointerEvents: 'none',
      }}
    >
      {message}
    </div>,
    document.body
  )
}
