// ============================================
// @elitegrid/adapter-react — GridBody.tsx
// The scroll container — virtualizes rows
// ============================================

import React, { useEffect, useRef, useState } from 'react'
import { GridEvent } from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import {
  useGrid,
  useViewportState,
  useColumnsState,
  useFocusManager,
} from '../use-grid'
import { GridRow } from './GridRow'
import { GridOverlay } from './GridOverlay'
import { GridHeader } from './GridHeader'
import { calculateColumnWidths } from '../utils/columnWidths'

export function GridBody() {
  const grid = useGridContext()
  const { containerRef } = useGrid(grid)

  // ── Focus management — moves DOM focus on FOCUS_CHANGED ──────────
  useFocusManager(grid, containerRef)
  const viewport = useViewportState(grid)

  const { definitions } = useColumnsState(grid)

  const {
    visibleRows,
    visibleColumnIds,
    offsetTop,
    totalHeight,
    rowHeight,
    containerWidth,
    totalWidth,
  } = viewport

  // The engine's totalWidth covers only data columns. The checkbox column
  // (48px) is rendered outside the engine model. The spacer's minWidth must
  // include the checkbox so body.scrollWidth == header.scrollWidth — without
  // this, the header's last column icons are clipped when scrolled to the
  // far right because the header can scroll 48px further than the body.
  const showCheckboxes =
    grid.options.selection?.mode !== 'none' &&
    (grid.options.selection?.showCheckboxes ?? true)
  const scrollableWidth = totalWidth + (showCheckboxes ? 48 : 0)

  const columnWidths = React.useMemo(
    () =>
      calculateColumnWidths(definitions, grid.options.columns, containerWidth),
    [definitions, grid.options.columns, containerWidth]
  )

  const columnDefMap = React.useMemo(
    () => new Map(definitions.map((d) => [d.id, d])),
    [definitions]
  )

  const columnOptionsMap = React.useMemo(
    () => new Map(grid.options.columns.map((c) => [c.field as string, c])),
    [grid.options.columns]
  )

  // ── Loading state — shimmer ───────────────
  // hasAttemptedLoad tracks whether any data load has started.
  // Without this, static data shows "No data" for one render before
  // the viewport plugin computes visibleRows — a flash of wrong state (Â§10.1)
  const hasAttemptedLoadRef = useRef(
    grid.kernel.store.read('raw').rows.length > 0
  )
  const [isLoading, setIsLoading] = useState(
    () =>
      grid.kernel.store.read('viewport').visibleRows.length === 0 &&
      !hasAttemptedLoadRef.current
  )

  useEffect(() => {
    const unsubViewport = grid.kernel.eventBus.on(
      GridEvent.VIEWPORT_CHANGED,
      () => {
        const { visibleRows } = grid.kernel.store.read('viewport')
        if (visibleRows.length > 0) {
          setIsLoading(false)
        }
      }
    )

    const unsubDataSource = grid.kernel.eventBus.on(
      GridEvent.DATA_LOADING,
      () => {
        hasAttemptedLoadRef.current = true
        setIsLoading(true)
      }
    )

    return () => {
      unsubViewport()
      unsubDataSource()
    }
  }, [grid])



  // ── Reset scroll on sort/filter/page change ───
  useEffect(() => {
    const unsubscribeSort = grid.kernel.eventBus.on(
      GridEvent.SORT_COMPLETED,
      () => {
        if (containerRef.current) {
          containerRef.current.scrollTop = 0
        }
      }
    )

    const unsubscribePage = grid.kernel.eventBus.on(
      GridEvent.PAGE_CHANGED,
      () => {
        if (containerRef.current) {
          containerRef.current.scrollTop = 0
        }
      }
    )

    const unsubscribeFilter = grid.kernel.eventBus.on(
      GridEvent.FILTER_COMPLETED,
      () => {
        if (containerRef.current) {
          containerRef.current.scrollTop = 0
        }
      }
    )

    return () => {
      unsubscribeSort()
      unsubscribePage()
      unsubscribeFilter()
    }
  }, [grid, containerRef])

  // ── Shimmer skeleton ──────────────────────
  const skeletonRowCount = Math.ceil(
    (containerRef.current?.clientHeight ?? 400) / rowHeight
  )

  return (
    <div
      ref={containerRef}
      className="yg-body"
      role="presentation"
      aria-label={undefined}
      tabIndex={0}
      onKeyDown={(e) => {
        // Only handle keys when no editor is open
        const { isEditing } = grid.kernel.store.read('editing')
        if (isEditing) return

        const keyMap: Record<
          string,
          { direction: string; editableOnly?: boolean; ctrl?: boolean }
        > = {
          ArrowUp: { direction: 'up' },
          ArrowDown: { direction: 'down' },
          ArrowLeft: { direction: 'left' },
          ArrowRight: { direction: 'right' },
          Tab: { direction: e.shiftKey ? 'prev' : 'next' },
          Home: { direction: e.ctrlKey ? 'first' : 'rowStart' },
          End: { direction: e.ctrlKey ? 'last' : 'rowEnd' },
          Enter: { direction: 'none' }, // opens editor on focused cell
        }

        const mapping = keyMap[e.key]
        if (!mapping) return

        e.preventDefault()

        if (e.key === 'Enter') {
          // Open editor on currently focused cell
          const { focusedCell } = grid.kernel.store.read('focus')
          if (focusedCell) {
            grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, {
              cell: focusedCell,
            })
          }
          return
        }

        grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
          direction: mapping.direction,
          editableOnly: false,
        })
      }}
      style={{
        flex: 1,
        overflowY: 'scroll', // always reserve scrollbar space — clientWidth stable
        overflowX: 'auto',
        position: 'relative',
        WebkitOverflowScrolling: 'touch',
        outline: 'none',
      }}
    >
      {/* Sticky header — inside the unified scroll container so horizontal
          scroll moves header and rows as a single native unit. Zero JS sync. */}
      <GridHeader />

      {/* Shimmer — shown only while waiting for rows to arrive.
          zIndex 1 keeps it below the sticky header (zIndex 2) so column
          names remain visible during loading. */}
      {isLoading && (
        <div
          aria-hidden="true"
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'var(--eg-row-bg)',
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            zIndex: 1,
          }}
        >
          {Array.from({ length: skeletonRowCount }).map((_, i) => (
            <div
              key={i}
              style={{
                height: rowHeight,
                minHeight: rowHeight,
                display: 'flex',
                alignItems: 'center',
                borderBottom: '1px solid var(--eg-row-border)',
                backgroundColor:
                  i % 2 === 0
                    ? 'var(--eg-row-striped-bg)'
                    : 'var(--eg-row-bg)',
                boxSizing: 'border-box',
                flexShrink: 0,
              }}
            >
              {visibleColumnIds.map((colId) => {
                const colWidth = columnWidths.get(colId) ?? 150
                return (
                  <div
                    key={colId}
                    style={{
                      width: colWidth,
                      minWidth: colWidth,
                      maxWidth: colWidth,
                      height: '100%',
                      display: 'flex',
                      alignItems: 'center',
                      padding: '0 12px',
                      boxSizing: 'border-box',
                      flexShrink: 0,
                    }}
                  >
                    <div
                      style={{
                        width: '100%',
                        height: 12,
                        borderRadius: 6,
                        background:
                          'linear-gradient(90deg, var(--eg-skeleton-base) 25%, var(--eg-skeleton-highlight) 50%, var(--eg-skeleton-base) 75%)',
                        backgroundSize: '200% 100%',
                        animation: 'yg-shimmer 1.2s infinite',
                      }}
                    />
                  </div>
                )
              })}
            </div>
          ))}
        </div>
      )}

      {/* Spacer — creates full scrollable area */}
      <div
        style={{
          height: totalHeight,
          minWidth: scrollableWidth,
          position: 'relative',
          pointerEvents: 'none',
          // contain:strict tells the browser this subtree is self-contained —
          // enables paint and layout isolation for virtualised content
          contain: 'strict',
        }}
      >
        {/* Rows wrapper — translateY positions visible rows */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            minWidth: scrollableWidth,
            transform: `translateY(${offsetTop}px)`,
            pointerEvents: 'auto',
            // Promotes to its own GPU compositor layer so translateY changes
            // never trigger a repaint of the scroll container background
            willChange: 'transform',
          }}
        >
          {visibleRows.map((row, index) => {
            const rawRow = row as Record<string, unknown>

            // Use the configured rowId field — never hardcode 'id'.
            // options.rowId can be a string key or a function.
            const rowIdField =
              typeof grid.options.rowId === 'string' ? grid.options.rowId : 'id'
            const rowId = String(
              rawRow[rowIdField] ?? `__row_${viewport.startRowIndex + index}`
            )

            return (
              <GridRow
                key={rowId}
                rowId={rowId}
                row={rawRow}
                rowIndex={viewport.startRowIndex + index}
                rowHeight={rowHeight}
                visibleColumnIds={visibleColumnIds}
                columnWidths={columnWidths}
                columnDefMap={columnDefMap}
                columnOptionsMap={columnOptionsMap}
              />
            )
          })}
        </div>
      </div>

      {/* Empty / Loading / Error overlay */}
      <GridOverlay />

      {/* Keyframes */}
      <style>{`
        @keyframes yg-shimmer {
          0% { background-position: 200% 0; }
          100% { background-position: -200% 0; }
        }
      `}</style>
    </div>
  )
}
