// ============================================
// @elitegrid/adapter-react — GridRow.tsx
// Renders a single row of cells
// ============================================

import React, { memo, useCallback } from 'react'
import { useGridContext } from '../context/GridContext'
import { GridCell } from './GridCell'
import { useCellSelected } from '../use-grid'
import { GridEvent } from '@elitegrid/core'
import type { ColumnId } from '@elitegrid/core'
import type { ColumnDef } from '../create-grid'

interface GridRowProps {
  rowId: string
  row: Record<string, unknown>
  rowIndex: number
  rowHeight: number
  visibleColumnIds: ColumnId[]
  columnWidths: Map<string, number>
  // Lookup maps built once in GridBody and passed down so individual
  // cells don't run Array.find() per render. See GridBody for details.
  columnDefMap: Map<string, unknown>
  columnOptionsMap: Map<string, ColumnDef>
}

export const GridRow = memo(function GridRow({
  rowId,
  row,
  rowIndex,
  rowHeight,
  visibleColumnIds,
  columnWidths,
  columnDefMap,
  columnOptionsMap,
}: GridRowProps) {
  const grid = useGridContext()
  const { options } = grid

  // Per-row selector — only THIS row re-renders when its selection changes.
  // Previously useSelectionState() caused every mounted row to re-render
  // whenever any row was selected/deselected.
  const isSelected = useCellSelected(grid, rowId)
  const selectionMode = options.selection?.mode ?? 'none'
  const selectOnRowClick = options.selection?.selectOnRowClick ?? true
  const checkboxOnly = options.selection?.checkboxOnly ?? false

  // Stable function reference — row object identity is stable per virtualised
  // render cycle, and useCallback keyed on `row` means this only changes
  // when the row data itself changes, not on every GridRow re-render.
  const getCellValue = useCallback(() => row, [row])

  const handleRowClick = useCallback(
    (e: React.MouseEvent) => {
      // Cells stop propagation and re-emit selection themselves
      // This handler only fires for clicks on non-cell row areas (padding etc)
      if (selectionMode !== 'none' && selectOnRowClick && !checkboxOnly) {
        grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
          rowId,
          shiftKey: e.shiftKey,
          ctrlKey: e.ctrlKey,
          metaKey: e.metaKey,
        })
      }
      options.events?.onRowClick?.(row as unknown, e.nativeEvent)
    },
    [
      rowId,
      row,
      selectionMode,
      selectOnRowClick,
      checkboxOnly,
      grid,
      options.events,
    ]
  )

  const handleRowDoubleClick = useCallback(
    (e: React.MouseEvent) => {
      options.events?.onRowDoubleClick?.(row as unknown, e.nativeEvent)
    },
    [row, options.events]
  )

  const isEven = rowIndex % 2 === 0
  const showStriping = options.appearance?.rowStriping ?? true

  return (
    <div
      className="yg-row"
      role="row"
      aria-rowindex={rowIndex + 1}
      aria-selected={selectionMode !== 'none' ? isSelected : undefined}
      onClick={handleRowClick}
      onDoubleClick={handleRowDoubleClick}
      style={{
        // ── Layout — must be inline: CSS may not load in all environments ──
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
        boxSizing: 'border-box',
        userSelect: 'none',
        // ── Sizing ────────────────────────────────────────────────────────
        height: rowHeight,
        minHeight: rowHeight,
        maxHeight: rowHeight,
        // ── Dynamic appearance ────────────────────────────────────────────
        backgroundColor: isSelected
          ? 'var(--eg-row-selected-bg)'
          : showStriping && isEven
            ? 'var(--eg-row-striped-bg)'
            : 'var(--eg-row-bg)',
        borderBottom: isSelected
          ? 'var(--eg-row-selected-border)'
          : 'var(--eg-row-border)',
        cursor:
          selectionMode !== 'none' || options.events?.onRowClick
            ? 'pointer'
            : 'default',
        outline: isSelected
          ? '1px solid var(--eg-row-selected-outline, transparent)'
          : undefined,
      }}
    >
      {/* ── Row checkbox ─────────────────────────────── */}
      {selectionMode !== 'none' &&
        (options.selection?.showCheckboxes ?? true) && (
          <div
            className="yg-cell yg-cell--checkbox"
            role="gridcell"
            style={{
              // Layout must be inline — same reason as row above
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flexShrink: 0,
              boxSizing: 'border-box',
              width: 48,
              minWidth: 48,
              maxWidth: 48,
              height: '100%',
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <input
              type="checkbox"
              aria-label={`Select row ${rowIndex + 1}`}
              checked={isSelected}
              onChange={(e) => {
                grid.kernel.eventBus.emit(GridEvent.CHECKBOX_ROW_CHANGED, {
                  rowId,
                  checked: e.target.checked,
                })
              }}
              style={{
                cursor: 'pointer',
                width: 16,
                height: 16,
                accentColor: 'var(--eg-primary)',
              }}
            />
          </div>
        )}

      {visibleColumnIds.map((columnId, columnIndex) => {
        // getCellValue is defined once above with useCallback — stable reference
        // so GridCell's memo comparator sees the same function between renders.
        return (
          <GridCell
            key={columnId}
            rowId={rowId}
            columnId={columnId}
            columnIndex={columnIndex}
            rowIndex={rowIndex}
            getCellValue={getCellValue}
            columnWidths={columnWidths}
            columnDefMap={columnDefMap}
            columnOptionsMap={columnOptionsMap}
          />
        )
      })}
    </div>
  )
})
