// ============================================
// @elitegrid/adapter-react — GridContext
// React context that passes GridInstance
// down the component tree
//
// Used internally by all Grid sub-components
// Developer never imports this directly
// ============================================

import { createContext, useContext } from 'react'
import type { GridInstance } from '../create-grid'

// ── Context ───────────────────────────────────
// Default is null — only has a value inside <Grid>

export const GridContext = createContext<GridInstance<unknown> | null>(null)

// ── useGridContext ────────────────────────────
// Internal hook used by GridHeader, GridBody,
// GridRow, GridCell — any component that needs
// access to the grid instance
//
// Throws a clear error if used outside <Grid>
// so developers know immediately what went wrong

export function useGridContext<TData = unknown>(): GridInstance<TData> {
  const context = useContext(GridContext)

  if (!context) {
    throw new Error(
      '[EliteGrid] Grid components must be rendered inside <Grid>. ' +
        'Make sure you are not using grid hooks outside of the Grid component tree.'
    )
  }

  return context as GridInstance<TData>
}
