// ============================================
// @elitegrid/adapter-react — GridHeader.tsx
// Renders the column header row
//
// Responsibilities:
//   1. Read column definitions from store
//   2. Render one header cell per visible column
//   3. Show sort indicator on sorted columns
//   4. Handle click to sort
//   5. Show filter icon per filterable column
//   6. Open filter popover on filter icon click
//   7. Support custom filter icon, position, hover behavior
//   8. Column resize via drag handle
// ============================================

import React, { useCallback, useEffect, useRef, useState } from 'react'
import { useGridContext } from '../context/GridContext'
import {
  useColumnsState,
  useSortedState,
  useFilteredState,
  useViewportState,
  useSelectionState,
} from '../use-grid'
import { calculateColumnWidths } from '../utils/columnWidths'
import { GridFilterPopover } from './Gridfilterpopover'
import { GridEvent } from '@elitegrid/core'
import type { ColumnDefinition } from '@elitegrid/core'

// ── Default filter icon ───────────────────────

function DefaultFilterIcon() {
  return (
    <svg width="12" height="12" viewBox="0 0 12 12" fill="currentColor">
      <path d="M1 2h10L7 6.5V10.5L5 9.5V6.5L1 2z" />
    </svg>
  )
}

// ── GridHeader ────────────────────────────────

export function GridHeader() {
  const grid = useGridContext()
  const { definitions, order } = useColumnsState(grid)
  const { sortModel } = useSortedState(grid)
  const { containerWidth, totalWidth } = useViewportState(grid)
  const { options } = grid
  const {
    isAllSelected,
    isIndeterminate,
    mode: selectionMode,
  } = useSelectionState(grid)
  const showCheckboxes =
    selectionMode !== 'none' && (options.selection?.showCheckboxes ?? true)

  // Must match the body spacer minWidth so header and rows always align.
  const scrollableWidth = totalWidth + (showCheckboxes ? 48 : 0)

  const filteringOptions = options.filtering

  // Calculate pixel widths — memoized to keep Map reference stable.
  // A new Map every render would invalidate GridCell's memo comparator
  // on every unrelated re-render.
  const columnWidths = React.useMemo(
    () => calculateColumnWidths(definitions, options.columns, containerWidth),
    [definitions, options.columns, containerWidth]
  )

  // ── Filter popover state ──────────────────
  const [activeFilterColumnId, setActiveFilterColumnId] = useState<
    string | null
  >(null)
  const [hoveredColumnId, setHoveredColumnId] = useState<string | null>(null)
  const filterIconRefs = useRef<Map<string, React.RefObject<HTMLDivElement>>>(
    new Map()
  )

  const getFilterIconRef = (columnId: string) => {
    if (!filterIconRefs.current.has(columnId)) {
      filterIconRefs.current.set(columnId, React.createRef<HTMLDivElement>())
    }
    return filterIconRefs.current.get(columnId)!
  }

  // Clean up stale refs when columns are removed (Â§4.2)
  // Prevents stale DOM refs from causing wrong popover positions
  useEffect(() => {
    const validIds = new Set(definitions.map((d: { id: string }) => d.id))
    for (const key of filterIconRefs.current.keys()) {
      if (!validIds.has(key)) filterIconRefs.current.delete(key)
    }
  }, [definitions])

  // Abort controller for document-level drag listeners (Â§4.3)
  // Ensures mousemove/mouseup listeners are removed if grid unmounts mid-drag
  const dragAbortRef = useRef<AbortController | null>(null)

  useEffect(() => {
    return () => {
      // Abort any in-progress column resize drag on unmount
      dragAbortRef.current?.abort()
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }
  }, [])

  // ── Active filter check ───────────────────
  // Subscribe to filtered namespace so filter icon updates immediately
  // when a filter is applied or cleared — previously this was a stale
  // store.read() that only updated on unrelated re-renders (Â§4.4)
  const { filterModel } = useFilteredState(grid)
  const isColumnFiltered = (columnId: string) => columnId in filterModel.columns

  // ── Handle Sort Click ─────────────────────
  const handleSortClick = useCallback(
    (columnId: string, sortable: boolean) => {
      if (!sortable) return
      if (options.sorting?.enabled === false) return
      // Block sort if a resize drag just happened
      if (didResizeRef.current) return
      grid.plugins.sort.cycleSort(columnId)
    },
    [grid, options.sorting?.enabled]
  )

  // ── Get Sort Direction ────────────────────
  const getSortDirection = (columnId: string) => {
    const model = sortModel.find((s) => s.columnId === columnId)
    return model?.direction ?? null
  }

  // ── Get Sort Index ────────────────────────
  const getSortIndex = (columnId: string) => {
    if (sortModel.length <= 1) return null
    const index = sortModel.findIndex((s) => s.columnId === columnId)
    return index === -1 ? null : index + 1
  }

  // ── Column Resize ─────────────────────────
  // Track active resize state in a ref — not state
  // Avoids re-renders during drag which would be very expensive
  const resizeStateRef = useRef<{
    columnId: string
    startX: number
    startWidth: number
    minWidth: number
    maxWidth: number | undefined
  } | null>(null)

  const [resizingColumnId, setResizingColumnId] = useState<string | null>(null)
  // Track if a resize drag happened — blocks sort click after resize
  const didResizeRef = useRef(false)

  const handleResizeMouseDown = useCallback(
    (e: React.MouseEvent, col: ColumnDefinition) => {
      e.preventDefault()
      e.stopPropagation() // don't trigger sort

      // Read the current width directly from the engine store at the moment
      // the drag starts — not from the columnWidths closure. The closure
      // reflects the width at last render; if the engine updated between
      // renders the closure would be stale and startWidth would be wrong.
      const storeWidths = grid.kernel.store.read('columns').widths
      const currentWidth = storeWidths.get(col.id) ?? col.width ?? 150
      const minWidth = col.minWidth ?? 50
      const maxWidth = col.maxWidth

      resizeStateRef.current = {
        columnId: col.id,
        startX: e.clientX,
        startWidth: currentWidth,
        minWidth,
        maxWidth,
      }

      setResizingColumnId(col.id)

      // Set cursor on body during drag
      document.body.style.cursor = 'col-resize'
      document.body.style.userSelect = 'none'

      // AbortController — if the grid unmounts mid-drag, the useEffect
      // cleanup calls dragAbortRef.current.abort(), which removes these
      // listeners automatically via the signal option (Â§4.3)
      const controller = new AbortController()
      dragAbortRef.current = controller
      const { signal } = controller

      // ── Mouse move — calculate new width ──
      const handleMouseMove = (moveEvent: MouseEvent) => {
        const state = resizeStateRef.current
        if (!state) return

        didResizeRef.current = true

        const delta = moveEvent.clientX - state.startX
        let newWidth = state.startWidth + delta
        newWidth = Math.max(state.minWidth, newWidth)
        if (state.maxWidth !== undefined) {
          newWidth = Math.min(state.maxWidth, newWidth)
        }

        const currentContainerWidth =
          grid.kernel.store.read('viewport').containerWidth
        grid.plugins.columnModel.setWidth(
          state.columnId,
          Math.floor(newWidth),
          currentContainerWidth
        )
      }

      // ── Mouse up — commit resize ──────────
      const handleMouseUp = (upEvent: MouseEvent) => {
        const state = resizeStateRef.current
        if (!state) return

        const delta = upEvent.clientX - state.startX
        let finalWidth = state.startWidth + delta
        finalWidth = Math.max(state.minWidth, finalWidth)
        if (state.maxWidth !== undefined) {
          finalWidth = Math.min(state.maxWidth, finalWidth)
        }

        const currentContainerWidth =
          grid.kernel.store.read('viewport').containerWidth
        grid.plugins.columnModel.setWidth(
          state.columnId,
          Math.floor(finalWidth),
          currentContainerWidth
        )

        options.events?.onColumnResize?.(state.columnId, Math.floor(finalWidth))

        resizeStateRef.current = null
        setResizingColumnId(null)
        document.body.style.cursor = ''
        document.body.style.userSelect = ''
        controller.abort()
        dragAbortRef.current = null

        // Block the click event that fires after mouseup — prevents
        // sort triggering after a resize drag (Â§4.1 partial fix)
        if (didResizeRef.current) {
          const blockClick = (clickEvent: MouseEvent) => {
            clickEvent.stopPropagation()
            clickEvent.preventDefault()
            document.removeEventListener('click', blockClick, true)
          }
          document.addEventListener('click', blockClick, true)
          setTimeout(() => {
            didResizeRef.current = false
            document.removeEventListener('click', blockClick, true)
          }, 100)
        }
      }

      // signal option auto-removes these listeners when abort() is called
      document.addEventListener('mousemove', handleMouseMove, { signal })
      document.addEventListener('mouseup', handleMouseUp, { signal })
    },
    [grid, options.events]
  )

  // ── Visible columns in display order ──────
  const visibleColumns = order
    .map((id) => definitions.find((d) => d.id === id))
    .filter((col): col is ColumnDefinition => col != null && col.visible)

  const headerHeight = options.appearance?.headerHeight ?? 44

  // ── Filter icon customization ─────────────
  const iconPosition = filteringOptions?.iconPosition ?? 'right'
  const showIconOnHover = filteringOptions?.showIconOnHover ?? false
  const popoverPlacement = filteringOptions?.popoverPlacement ?? 'auto'

  return (
    <>
      <div
        className="yg-header"
        role="rowgroup"
        style={{
          // Sticky inside the unified scroll container — stays at the top during
          // vertical scroll; moves horizontally with the content (same container),
          // so header and rows are always in perfect alignment with zero JS sync.
          position: 'sticky',
          top: 0,
          zIndex: 2,
          height: headerHeight,
          minHeight: headerHeight,
          // Must be at least as wide as the scrollable content so column headers
          // extend to the right edge as the user scrolls.
          minWidth: scrollableWidth,
          display: 'flex',
          flexDirection: 'row',
          borderBottom: 'var(--eg-header-border)',
          backgroundColor: 'var(--eg-header-bg)',
          flexShrink: 0,
          cursor: resizingColumnId ? 'col-resize' : undefined,
        }}
      >
        {/* ── Select All checkbox ──────────────────────────────── */}
        {showCheckboxes && (
          <div
            className="yg-header-cell yg-header-cell--checkbox"
            role="columnheader"
            aria-label="Select all rows"
            style={{
              width: 48,
              minWidth: 48,
              maxWidth: 48,
              height: '100%',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flexShrink: 0,
              boxSizing: 'border-box',
              borderRight: options.appearance?.showColumnBorders
                ? 'var(--eg-cell-border)'
                : undefined,
            }}
          >
            <input
              type="checkbox"
              aria-label="Select all rows"
              checked={isAllSelected}
              ref={(el) => {
                if (el) el.indeterminate = isIndeterminate
              }}
              onChange={(e) => {
                grid.kernel.eventBus.emit(GridEvent.SELECT_ALL_TOGGLED, {
                  checked: e.target.checked,
                })
              }}
              style={{
                cursor: 'pointer',
                width: 16,
                height: 16,
                accentColor: 'var(--eg-primary)',
              }}
            />
          </div>
        )}

        {visibleColumns.map((col) => {
          const direction = getSortDirection(col.id)
          const sortIndex = getSortIndex(col.id)
          const isSorted = direction !== null
          const isSortable = col.sortable && options.sorting?.enabled !== false
          const isFilterable =
            col.filterable && options.filtering?.enabled !== false
          const isFiltered = isColumnFiltered(col.id)
          const isHovered = hoveredColumnId === col.id
          const isResizing = resizingColumnId === col.id
          const colWidth = columnWidths.get(col.id) ?? 150
          const filterIconRef = getFilterIconRef(col.id)
          const isResizable = col.resizable !== false

          // Show filter icon based on hover setting
          const showFilterIcon =
            isFilterable &&
            (!showIconOnHover ||
              isHovered ||
              isFiltered ||
              activeFilterColumnId === col.id)

          // Custom or default filter icon
          const filterIconElement = isFiltered
            ? (filteringOptions?.activeFilterIcon ??
              filteringOptions?.filterIcon ?? <DefaultFilterIcon />)
            : (filteringOptions?.filterIcon ?? <DefaultFilterIcon />)

          // ── Filter icon button ───────────────
          const filterIconButton = showFilterIcon ? (
            <div
              ref={filterIconRef}
              onClick={(e) => {
                e.stopPropagation()
                setActiveFilterColumnId(
                  activeFilterColumnId === col.id ? null : col.id
                )
              }}
              aria-label={`Filter ${col.header}`}
              title={`Filter ${col.header}`}
              style={{
                flexShrink: 0,
                width: 20,
                height: 20,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                borderRadius: 4,
                cursor: 'pointer',
                fontSize: '0.75rem',
                color: isFiltered
                  ? 'var(--eg-primary)'
                  : 'var(--eg-muted-text)',
                backgroundColor: isFiltered
                  ? 'var(--eg-primary-light)'
                  : activeFilterColumnId === col.id
                    ? 'var(--eg-hover-bg)'
                    : 'transparent',
                transition:
                  'background-color 0.15s, color 0.15s, opacity 0.15s',
                opacity: showIconOnHover && !isFiltered && !isHovered ? 0 : 1,
              }}
            >
              {filterIconElement}
            </div>
          ) : showIconOnHover ? (
            <div style={{ width: 20, flexShrink: 0 }} />
          ) : null

          return (
            <div
              key={col.id}
              className={[
                'yg-header-cell',
                isSorted ? 'yg-header-cell--sorted' : '',
                isSortable ? 'yg-header-cell--sortable' : '',
                isFiltered ? 'yg-header-cell--filtered' : '',
                isResizing ? 'yg-header-cell--resizing' : '',
              ]
                .filter(Boolean)
                .join(' ')}
              role="columnheader"
              aria-sort={
                direction === 'asc'
                  ? 'ascending'
                  : direction === 'desc'
                    ? 'descending'
                    : 'none'
              }
              onMouseEnter={() => setHoveredColumnId(col.id)}
              onMouseLeave={() => setHoveredColumnId(null)}
              style={{
                width: colWidth,
                minWidth: colWidth,
                maxWidth: colWidth,
                height: '100%',
                display: 'flex',
                alignItems: 'center',
                padding: '0 12px',
                cursor: isSortable ? 'pointer' : 'default',
                userSelect: 'none',
                fontWeight: 600,
                fontSize: '0.875rem',
                color: 'var(--eg-header-text)',
                borderRight: options.appearance?.showColumnBorders
                  ? 'var(--eg-cell-border)'
                  : undefined,
                boxSizing: 'border-box',
                flexShrink: 0,
                gap: 4,
                position: 'relative', // needed for resize handle positioning
                backgroundColor: isResizing
                  ? 'var(--eg-header-active-bg)'
                  : undefined,
              }}
              onClick={() => handleSortClick(col.id, col.sortable)}
            >
              {/* Filter icon — left position */}
              {iconPosition === 'left' && filterIconButton}

              {/* Column label */}
              <span
                style={{
                  flex: 1,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                }}
              >
                {col.header}
              </span>

              {/* Sort indicator */}
              {isSortable && (
                <span
                  className="yg-sort-indicator"
                  aria-hidden="true"
                  style={{
                    opacity: isSorted ? 1 : 0.3,
                    fontSize: '0.75rem',
                    color: isSorted
                      ? 'var(--eg-sort-active-color)'
                      : 'var(--eg-sort-icon-color)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: 2,
                    flexShrink: 0,
                  }}
                >
                  {direction === 'asc' ? '↑' : direction === 'desc' ? '↓' : '↕'}
                  {sortIndex !== null && (
                    <span style={{ fontSize: '0.65rem' }}>{sortIndex}</span>
                  )}
                </span>
              )}

              {/* Filter icon — right position (default) */}
              {iconPosition === 'right' && filterIconButton}

              {/* ── Resize handle ──────────────────
                  Positioned at the right edge of the header cell
                  Only shown for resizable columns
                  6px wide — wide enough to grab easily */}
              {isResizable && (
                <div
                  className="yg-resize-handle"
                  onMouseDown={(e) => handleResizeMouseDown(e, col)}
                  onClick={(e) => e.stopPropagation()}
                  aria-hidden="true"
                  style={{
                    position: 'absolute',
                    right: -4,
                    top: 0,
                    bottom: 0,
                    width: 12,
                    cursor: 'col-resize',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    zIndex: 2,
                  }}
                >
                  {/* Visual indicator line */}
                  <div
                    style={{
                      width: 2,
                      height: isHovered || isResizing ? '60%' : '30%',
                      borderRadius: 1,
                      backgroundColor: isResizing
                        ? 'var(--eg-primary)'
                        : isHovered
                          ? 'var(--eg-border-hover)'
                          : 'var(--eg-border)',
                      transition: 'height 0.15s, background-color 0.15s',
                    }}
                  />
                </div>
              )}
            </div>
          )
        })}
      </div>

      {/* Filter popover */}
      {/* key=columnId forces a fresh mount (and lazy-initializer re-run)
          whenever the active column changes, even if React 18 batches the
          nullâ†’newColumnId state transition and skips the unmount phase. */}
      {activeFilterColumnId && (
        <GridFilterPopover
          key={activeFilterColumnId}
          columnId={activeFilterColumnId}
          filterType={
            (options.columns.find(
              (c) => (c.field as string) === activeFilterColumnId
            )?.filter?.type ?? 'text') as 'text' | 'number' | 'date' | 'boolean'
          }
          anchorRef={getFilterIconRef(activeFilterColumnId)}
          onClose={() => setActiveFilterColumnId(null)}
          placement={popoverPlacement}
        />
      )}
    </>
  )
}
