// ============================================
// @elitegrid/adapter-react — GridPagination.tsx
// Pagination controls bar — renders below grid
//
// Responsibilities:
//   1. Show current page info — "Showing 1-25 of 100,000"
//   2. Page size selector dropdown
//   3. First / Prev / Next / Last buttons
//   4. Page number buttons with ellipsis
//   5. Fires pagination plugin methods on interaction
// ============================================

import React, { useCallback } from 'react'
import { useGridContext } from '../context/GridContext'
import { usePaginationState } from '../use-grid'

// ── GridPagination ────────────────────────────

export function GridPagination() {
  const grid = useGridContext()
  const { options } = grid
  const pagination = usePaginationState(grid)

  const {
    currentPage,
    pageSize,
    totalPages,
    totalRows,
    startRow,
    endRow,
    hasNextPage,
    hasPreviousPage,
  } = pagination

  // ── Handlers ──────────────────────────────
  // Hooks must be called before any early return (Rules of Hooks)

  const handlePageChange = useCallback(
    (page: number) => {
      grid.plugins.pagination.setPage(page)
      options.events?.onPageChange?.(page, pageSize)
    },
    [grid, pageSize, options.events]
  )

  const handlePageSizeChange = useCallback(
    (e: React.ChangeEvent<HTMLSelectElement>) => {
      const newSize = Number(e.target.value)
      grid.plugins.pagination.setPageSize(newSize)
      options.events?.onPageChange?.(1, newSize)
    },
    [grid, options.events]
  )

  // Don't render if pagination is disabled
  if (!options.pagination?.enabled) return null

  // ── Page size options ─────────────────────
  const pageSizeOptions = options.pagination?.pageSizeOptions ?? [
    10, 25, 50, 100,
  ]
  const showPageSizeSelector = options.pagination?.showPageSizeSelector ?? true
  const showRowCount = options.pagination?.showRowCount ?? true
  const showPageNumbers = options.pagination?.showPageNumbers ?? true

  // ── Page numbers with ellipsis ────────────
  // Shows: 1 ... 4 5 6 ... 20
  // Always shows first, last, current, and 1 sibling each side

  const getPageNumbers = (): Array<number | '...'> => {
    if (totalPages <= 7) {
      // Show all pages if 7 or fewer
      return Array.from({ length: totalPages }, (_, i) => i + 1)
    }

    const pages: Array<number | '...'> = []
    const showLeftEllipsis = currentPage > 3
    const showRightEllipsis = currentPage < totalPages - 2

    // Always show page 1
    pages.push(1)

    if (showLeftEllipsis) {
      pages.push('...')
    }

    // Show pages around current
    const start = Math.max(2, currentPage - 1)
    const end = Math.min(totalPages - 1, currentPage + 1)

    for (let i = start; i <= end; i++) {
      pages.push(i)
    }

    if (showRightEllipsis) {
      pages.push('...')
    }

    // Always show last page
    pages.push(totalPages)

    return pages
  }

  // ── Styles ────────────────────────────────

  const buttonBase: React.CSSProperties = {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    height: 32,
    minWidth: 32,
    padding: '0 8px',
    border: '1px solid var(--eg-border)',
    borderRadius: 6,
    backgroundColor: 'var(--eg-btn-bg)',
    color: 'var(--eg-btn-text)',
    fontSize: '0.875rem',
    cursor: 'pointer',
    userSelect: 'none',
    transition: 'background-color 0.15s, border-color 0.15s',
    fontFamily: 'inherit',
  }

  const activeButtonStyle: React.CSSProperties = {
    ...buttonBase,
    backgroundColor: 'var(--eg-primary)',
    borderColor: 'var(--eg-primary)',
    color: 'var(--eg-primary-text)',
    fontWeight: 600,
  }

  const disabledButtonStyle: React.CSSProperties = {
    ...buttonBase,
    opacity: 0.4,
    cursor: 'not-allowed',
  }

  return (
    <div
      className="yg-pagination"
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '8px 12px',
        borderTop: 'var(--eg-header-border)',
        backgroundColor: 'var(--eg-header-bg)',
        flexShrink: 0,
        gap: 8,
        flexWrap: 'wrap',
      }}
    >
      {/* ── Left — row count + page size ────── */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        {/* Row count */}
        {showRowCount && totalRows > 0 && (
          <span
            style={{
              fontSize: '0.875rem',
              color: 'var(--eg-muted-text)',
              whiteSpace: 'nowrap',
            }}
          >
            Showing{' '}
            <strong style={{ color: 'var(--eg-text)' }}>
              {startRow}–{endRow}
            </strong>{' '}
            of{' '}
            <strong style={{ color: 'var(--eg-text)' }}>
              {totalRows.toLocaleString()}
            </strong>
          </span>
        )}

        {/* Page size selector */}
        {showPageSizeSelector && (
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <span
              style={{
                fontSize: '0.875rem',
                color: 'var(--eg-muted-text)',
                whiteSpace: 'nowrap',
              }}
            >
              Rows per page
            </span>
            <select
              value={pageSize}
              onChange={handlePageSizeChange}
              style={{
                height: 32,
                padding: '0 8px',
                border: '1px solid var(--eg-border)',
                borderRadius: 6,
                backgroundColor: 'var(--eg-btn-bg)',
                color: 'var(--eg-btn-text)',
                fontSize: '0.875rem',
                cursor: 'pointer',
                fontFamily: 'inherit',
              }}
            >
              {pageSizeOptions.map((size) => (
                <option key={size} value={size}>
                  {size}
                </option>
              ))}
            </select>
          </div>
        )}
      </div>

      {/* ── Right — page navigation ──────────── */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
        {/* First page */}
        <button
          onClick={() => handlePageChange(1)}
          disabled={!hasPreviousPage}
          style={!hasPreviousPage ? disabledButtonStyle : buttonBase}
          title="First page"
          aria-label="First page"
        >
          «
        </button>

        {/* Previous page */}
        <button
          onClick={() => handlePageChange(currentPage - 1)}
          disabled={!hasPreviousPage}
          style={!hasPreviousPage ? disabledButtonStyle : buttonBase}
          title="Previous page"
          aria-label="Previous page"
        >
          ‹
        </button>

        {/* Page numbers */}
        {showPageNumbers &&
          getPageNumbers().map((page, index) =>
            page === '...' ? (
              <span
                key={`ellipsis-${index}`}
                style={{
                  padding: '0 4px',
                  color: 'var(--eg-muted-text)',
                  fontSize: '0.875rem',
                  userSelect: 'none',
                }}
              >
                ...
              </span>
            ) : (
              <button
                key={page}
                onClick={() => handlePageChange(page)}
                style={page === currentPage ? activeButtonStyle : buttonBase}
                aria-label={`Page ${page}`}
                aria-current={page === currentPage ? 'page' : undefined}
              >
                {page}
              </button>
            )
          )}

        {/* Next page */}
        <button
          onClick={() => handlePageChange(currentPage + 1)}
          disabled={!hasNextPage}
          style={!hasNextPage ? disabledButtonStyle : buttonBase}
          title="Next page"
          aria-label="Next page"
        >
          ›
        </button>

        {/* Last page */}
        <button
          onClick={() => handlePageChange(totalPages)}
          disabled={!hasNextPage}
          style={!hasNextPage ? disabledButtonStyle : buttonBase}
          title="Last page"
          aria-label="Last page"
        >
          »
        </button>
      </div>
    </div>
  )
}
