// ============================================
// @elitegrid/core — Viewport Plugin
// Final step in the data pipeline
// Reads from 'paginated' namespace
// Writes to 'viewport' namespace
// Zero DOM — pure math only
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { ColumnId } from '../../types/index'
import { devError } from '../../utils/dev'

export const VIEWPORT_PLUGIN_ID = 'viewport'

export interface ViewportConfig {
  rowHeight?: number
  headerHeight?: number
  bufferSize?: number
}

export interface ContainerDimensions {
  width: number
  height: number
}

export interface ScrollPosition {
  scrollTop: number
  scrollLeft: number
}

export class ViewportPlugin implements Plugin {
  readonly id = VIEWPORT_PLUGIN_ID

  private context!: PluginContext
  private config: ViewportConfig = {}

  private containerWidth: number = 0
  private containerHeight: number = 0
  private scrollTop: number = 0
  private scrollLeft: number = 0

  private rowHeight: number = 40
  private headerHeight: number = 44
  private bufferSize: number = 3

  private cleanups: Array<() => void> = []

  configure(config: ViewportConfig): void {
    this.config = config

    const rawHeight = config.rowHeight ?? 40
    if (rawHeight <= 0) {
      const msg =
        `[EliteGrid] rowHeight must be greater than 0 (received ${rawHeight}). ` +
        `A zero or negative rowHeight causes infinite virtualization loops. ` +
        `Falling back to 40px.`
      devError(msg)
      // devError throws in dev — only reached in production
      this.rowHeight = 40
    } else {
      this.rowHeight = rawHeight
    }

    this.headerHeight = config.headerHeight ?? 44
    this.bufferSize = config.bufferSize ?? 3
  }

  init(context: PluginContext): void {
    this.context = context

    this.cleanups.push(
      context.eventBus.on(
        GridEvent.CONTAINER_RESIZED,
        this.handleContainerResized
      )
    )

    this.cleanups.push(
      context.eventBus.on(GridEvent.SCROLL_CHANGED, this.handleScrollChanged)
    )

    this.cleanups.push(
      context.eventBus.on(
        GridEvent.PAGINATED_DATA_CHANGED,
        this.handlePaginationChanged
      )
    )

    this.cleanups.push(
      context.eventBus.on(
        GridEvent.COLUMN_VISIBILITY_CHANGED,
        this.handleColumnChanged
      )
    )

    this.cleanups.push(
      context.eventBus.on(GridEvent.COLUMN_REORDERED, this.handleColumnChanged)
    )

    // ── KEY FIX ───────────────────────────────────────────────────────
    // Listen to COLUMN_RESIZED so totalWidth is recalculated whenever
    // a column is resized. Without this, totalWidth stays at the initial
    // value (sum of minWidths for flex columns) and the scroll container
    // is undersized — causing the black void when scrolling right.
    this.cleanups.push(
      context.eventBus.on(GridEvent.COLUMN_RESIZED, this.handleColumnChanged)
    )
    // ─────────────────────────────────────────────────────────────────

    this.calculateViewport()
  }

  private handleContainerResized = (payload: ContainerDimensions): void => {
    this.containerWidth = payload.width
    this.containerHeight = payload.height
    this.calculateViewport()
  }

  private handleScrollChanged = (payload: ScrollPosition): void => {
    // Clamp negative scroll (Safari rubber-band sends negative values)
    this.scrollTop = Math.max(0, payload.scrollTop)
    this.scrollLeft = Math.max(0, payload.scrollLeft)
    this.calculateViewport()
  }

  private handlePaginationChanged = (): void => {
    // Reset scroll offset to top when page changes
    this.scrollTop = 0
    this.calculateViewport()
  }

  private handleColumnChanged = (): void => {
    this.calculateViewport()
  }

  // ── Calculate total width ──────────────────────────────────────────
  // Must mirror calculateColumnWidths() in the adapter exactly so the
  // scrollable area (totalWidth) always matches the actual rendered width.
  //
  // Fixed columns  → use col.width directly
  // Flex columns   → share containerWidth proportionally (same math as adapter)
  // If containerWidth is 0 (before first ResizeObserver tick) → use minWidth
  private calculateTotalWidth(
    definitions: Array<{
      id: string
      width?: number
      minWidth?: number
      flex?: number
      visible?: boolean
    }>
  ): number {
    const visibleCols = definitions.filter((c) => c.visible !== false)
    const fixedCols = visibleCols.filter((c) => c.width != null)
    const flexCols = visibleCols.filter((c) => c.width == null)

    const fixedTotal = fixedCols.reduce((sum, c) => sum + (c.width ?? 0), 0)

    let flexTotal = 0
    if (flexCols.length > 0) {
      const remaining = this.containerWidth - fixedTotal
      if (remaining > 0) {
        const totalFlex = flexCols.reduce((sum, c) => sum + (c.flex ?? 1), 0)
        flexTotal = flexCols.reduce((sum, c) => {
          const calculated = ((c.flex ?? 1) / totalFlex) * remaining
          return sum + Math.max(c.minWidth ?? 50, Math.floor(calculated))
        }, 0)
      } else {
        flexTotal = flexCols.reduce((sum, c) => sum + (c.minWidth ?? 50), 0)
      }
    }

    return fixedTotal + flexTotal
  }

  private calculateViewport(): void {
    const { rows } = this.context.store.read('paginated')
    const { definitions, order } = this.context.store.read('columns')

    const totalRows = rows.length
    const totalColumns = definitions.length

    const totalHeight = totalRows * this.rowHeight

    // ── Use accurate totalWidth ────────────────────────────────────────
    // Old: definitions.reduce((sum, col) => sum + (col.width ?? 150), 0)
    // That used 150 for flex columns — wrong, caused undersized scroll area.
    const totalWidth = this.calculateTotalWidth(definitions)

    const availableHeight = Math.max(
      0,
      this.containerHeight - this.headerHeight
    )

    const visibleRowCount =
      availableHeight > 0 ? Math.ceil(availableHeight / this.rowHeight) : 0

    const firstVisibleRow =
      this.rowHeight > 0 ? Math.floor(this.scrollTop / this.rowHeight) : 0

    const startRowIndex = Math.max(0, firstVisibleRow - this.bufferSize)
    const endRowIndex = Math.min(
      totalRows - 1,
      firstVisibleRow + visibleRowCount + this.bufferSize
    )

    const offsetTop = startRowIndex * this.rowHeight

    // Build a Map for O(1) column definition lookup — replaces the
    // Array.find() that previously ran for every column in the order array
    const defMap = new Map(definitions.map((d) => [d.id, d]))

    const visibleColumnIds = order.filter((id) => {
      const col = defMap.get(id)
      return col?.visible ?? true
    })

    const visibleRows = rows.slice(startRowIndex, endRowIndex + 1)

    this.context.store.write('viewport', {
      visibleRows,
      visibleColumnIds,
      startRowIndex,
      endRowIndex,
      startColumnIndex: 0,
      endColumnIndex: totalColumns - 1,
      offsetTop,
      offsetLeft: 0,
      totalHeight,
      totalWidth,
      scrollTop: this.scrollTop,
      scrollLeft: this.scrollLeft,
      containerWidth: this.containerWidth,
      containerHeight: this.containerHeight,
      rowHeight: this.rowHeight,
    })

    this.context.eventBus.emit(GridEvent.VIEWPORT_CHANGED, {
      startRowIndex,
      endRowIndex,
    })
  }

  scrollToRow(rowIndex: number): void {
    const { rows } = this.context.store.read('paginated')
    const clampedIndex = Math.min(Math.max(0, rowIndex), rows.length - 1)
    const scrollTop = clampedIndex * this.rowHeight
    this.scrollTop = scrollTop
    this.context.eventBus.emit(GridEvent.SCROLL_CHANGED, {
      scrollTop,
      scrollLeft: this.scrollLeft,
    })
    this.calculateViewport()
  }

  scrollToColumn(columnId: ColumnId): void {
    const { definitions } = this.context.store.read('columns')
    let offsetLeft = 0
    for (const col of definitions) {
      if (col.id === columnId) break
      if (col.visible) {
        // Use actual width for fixed cols, minWidth for flex cols
        offsetLeft += col.width ?? col.minWidth ?? 50
      }
    }
    this.scrollLeft = offsetLeft
    this.calculateViewport()
  }

  getViewportState() {
    return this.context.store.read('viewport')
  }

  getRowHeight(): number {
    return this.rowHeight
  }

  getTotalHeight(): number {
    const { rows } = this.context.store.read('paginated')
    return rows.length * this.rowHeight
  }

  getRowAtScrollPosition(scrollTop: number): number {
    return Math.floor(scrollTop / this.rowHeight)
  }

  getScrollPositionForRow(rowIndex: number): number {
    return rowIndex * this.rowHeight
  }

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
  }
}
